    // ── fd90.233: pandas-parity bare-name aliases for the *_agg ──
    // ── reductions. Each delegates to the corresponding _agg method. ──
    // ── Without these, `df.min()` etc. fail to resolve (df.min was   ──
    // ── reaching some Iterator-trait fallback with unsatisfied        ──
    // ── bounds). Inherent methods shadow the trait fallback.          ──

    /// Per-column min — pandas-parity alias for [`min_agg`](Self::min_agg).
    pub fn min(&self) -> Result<Series, FrameError> {
        self.min_agg()
    }

    /// Per-column max — pandas-parity alias for [`max_agg`](Self::max_agg).
    pub fn max(&self) -> Result<Series, FrameError> {
        self.max_agg()
    }

    /// Per-column std — pandas-parity alias for [`std_agg`](Self::std_agg).
    pub fn std(&self) -> Result<Series, FrameError> {
        self.std_agg()
    }

    /// Per-column var — pandas-parity alias for [`var_agg`](Self::var_agg).
    pub fn var(&self) -> Result<Series, FrameError> {
        self.var_agg()
    }

    /// Per-column median — pandas-parity alias for [`median_agg`](Self::median_agg).
    pub fn median(&self) -> Result<Series, FrameError> {
        self.median_agg()
    }

    /// Per-column product — pandas-parity alias for [`prod_agg`](Self::prod_agg).
    pub fn prod(&self) -> Result<Series, FrameError> {
        self.prod_agg()
    }

    /// Per-column skewness — pandas-parity alias for [`skew_agg`](Self::skew_agg).
    pub fn skew(&self) -> Result<Series, FrameError> {
        self.skew_agg()
    }

    /// Per-column excess kurtosis — pandas-parity alias for
    /// [`kurtosis_agg`](Self::kurtosis_agg). Pandas uses both `kurt` and
    /// `kurtosis` as aliases.
    pub fn kurtosis(&self) -> Result<Series, FrameError> {
        self.kurtosis_agg()
    }

    /// Per-column excess kurtosis (pandas alias for `kurtosis`).
    pub fn kurt(&self) -> Result<Series, FrameError> {
        self.kurtosis_agg()
    }

    /// Per-column standard error of the mean — pandas-parity alias for
    /// [`sem_agg`](Self::sem_agg).
    pub fn sem(&self) -> Result<Series, FrameError> {
        self.sem_agg()
    }

    // ── Row-axis (axis=1) aggregations ──

    /// Internal: reduce each row across numeric columns using a closure.
    fn reduce_rows<F>(&self, func: F, name: &str) -> Result<Series, FrameError>
    where
        F: Fn(&[f64]) -> f64,
    {
        // Per br-frankenpandas-d3tdy: pandas treats Bool columns as 0/1
        // numerics in row-axis reductions. Excluding Bool silently dropped
        // valid contributions; Bool.to_f64() already returns Ok(0.0/1.0),
        // so allowing the dtype through the filter is sufficient.
        let numeric_cols: Vec<&str> = self
            .column_order
            .iter()
            .filter(|c| {
                let dt = self.columns[c.as_str()].dtype();
                dt == DType::Int64 || dt == DType::Float64 || dt == DType::Bool
            })
            .map(|s| s.as_str())
            .collect();

        let mut values = Vec::with_capacity(self.len());
        for row_idx in 0..self.len() {
            let row_vals: Vec<f64> = numeric_cols
                .iter()
                .filter_map(|&col_name| self.columns[col_name].values()[row_idx].to_f64().ok())
                .collect();
            if row_vals.is_empty() {
                values.push(Scalar::Null(NullKind::NaN));
            } else {
                values.push(Scalar::Float64(func(&row_vals)));
            }
        }
        // Per br-frankenpandas-8no14: pandas df.<reducer>(axis=1) preserves
        // df.index.name on the per-row result. Covers sum_axis1, mean_axis1,
        // min_axis1, max_axis1, std_axis1, var_axis1, etc.
        let index = Index::new(self.index.labels().to_vec()).rename_index(self.index.name());
        let column = Column::from_values(values)?;
        Series::new(name.to_owned(), index, column)
    }

    fn row_sample_var(vals: &[f64]) -> f64 {
        let n = vals.len() as f64;
        if n < 2.0 {
            return f64::NAN;
        }
        let mean = vals.iter().sum::<f64>() / n;
        vals.iter().map(|v| (v - mean).powi(2)).sum::<f64>() / (n - 1.0)
    }

    fn row_sem(vals: &[f64]) -> f64 {
        let n = vals.len() as f64;
        if n < 2.0 {
            return f64::NAN;
        }
        Self::row_sample_var(vals).sqrt() / n.sqrt()
    }

    fn row_skew(vals: &[f64]) -> f64 {
        let count = vals.len();
        if count < 3 {
            return f64::NAN;
        }
        let n = count as f64;
        let mean = vals.iter().sum::<f64>() / n;
        let m2 = vals.iter().map(|v| (v - mean).powi(2)).sum::<f64>();
        let m3 = vals.iter().map(|v| (v - mean).powi(3)).sum::<f64>();
        let s2 = m2 / (n - 1.0);
        if s2 == 0.0 {
            return 0.0;
        }
        let s3 = s2.powf(1.5);
        (n / ((n - 1.0) * (n - 2.0))) * (m3 / s3)
    }

    fn row_kurtosis(vals: &[f64]) -> f64 {
        let count = vals.len();
        if count < 4 {
            return f64::NAN;
        }
        let n = count as f64;
        let mean = vals.iter().sum::<f64>() / n;
        let m2 = vals.iter().map(|v| (v - mean).powi(2)).sum::<f64>();
        let m4 = vals.iter().map(|v| (v - mean).powi(4)).sum::<f64>();
        let s2 = m2 / (n - 1.0);
        if s2 == 0.0 {
            return 0.0;
        }
        let adj = (n * (n + 1.0)) / ((n - 1.0) * (n - 2.0) * (n - 3.0));
        let sub = (3.0 * (n - 1.0).powi(2)) / ((n - 2.0) * (n - 3.0));
        adj * (m4 / (s2 * s2)) - sub
    }

    /// Sum across columns per row.
    ///
    /// Matches `pd.DataFrame.sum(axis=1)`.
    pub fn sum_axis1(&self) -> Result<Series, FrameError> {
        // Per br-frankenpandas-c0g3x: reduce_rows filters out Timedelta64
        // columns. For uniformly-Timedelta DataFrames, route to a
        // Timedelta-typed row reducer.
        if self.all_columns_timedelta() {
            return self.reduce_rows_timedelta(
                |ns_vals| {
                    let mut acc: i64 = 0;
                    for v in ns_vals {
                        acc = Timedelta::add(acc, *v);
                    }
                    if ns_vals.is_empty() {
                        Timedelta::NAT
                    } else {
                        acc
                    }
                },
                "sum",
            );
        }
        self.reduce_rows(|vals| vals.iter().sum(), "sum")
    }

    /// Mean across columns per row.
    ///
    /// Matches `pd.DataFrame.mean(axis=1)`.
    pub fn mean_axis1(&self) -> Result<Series, FrameError> {
        // Per br-frankenpandas-c0g3x: sister to sum_axis1 above.
        if self.all_columns_timedelta() {
            return self.reduce_rows_timedelta(
                |ns_vals| {
                    if ns_vals.is_empty() {
                        return Timedelta::NAT;
                    }
                    let sum: f64 = ns_vals.iter().map(|v| *v as f64).sum();
                    let mean = sum / ns_vals.len() as f64;
                    if !mean.is_finite() {
                        Timedelta::NAT
                    } else {
                        mean.clamp(i64::MIN as f64, i64::MAX as f64) as i64
                    }
                },
                "mean",
            );
        }
        self.reduce_rows(|vals| vals.iter().sum::<f64>() / vals.len() as f64, "mean")
    }

    /// Minimum across columns per row.
    ///
    /// Matches `pd.DataFrame.min(axis=1)`.
    pub fn min_axis1(&self) -> Result<Series, FrameError> {
        // Per br-frankenpandas-c0g3x: sister to sum_axis1 above.
        if self.all_columns_timedelta() {
            return self.reduce_rows_timedelta(
                |ns_vals| ns_vals.iter().copied().min().unwrap_or(Timedelta::NAT),
                "min",
            );
        }
        self.reduce_rows(
            |vals| vals.iter().copied().fold(f64::INFINITY, f64::min),
            "min",
        )
    }

    /// Apply a custom function to each row of the DataFrame.
    ///
    /// Matches `pd.DataFrame.apply(func, axis=1)`. The function receives
    /// a slice of `Scalar` values representing the row (in `column_order`)
    /// and should return a single `Scalar` result.
    pub fn apply_rows<F>(&self, func: F, name: &str) -> Result<Series, FrameError>
    where
        F: Fn(&[Scalar]) -> Scalar,
    {
        let mut values = Vec::with_capacity(self.len());
        for row_idx in 0..self.len() {
            let row: Vec<Scalar> = self
                .column_order
                .iter()
                .map(|col_name| self.columns[col_name].values()[row_idx].clone())
                .collect();
            values.push(func(&row));
        }
        // Per br-frankenpandas-4oeba: pandas df.apply(func, axis=1) preserves
        // df.index.name on the row-wise result.
        let index = Index::new(self.index.labels().to_vec()).rename_index(self.index.name());
        let column = Column::from_values(values)?;
        Series::new(name, index, column)
    }

    /// Maximum across columns per row.
    ///
    /// Matches `pd.DataFrame.max(axis=1)`.
    pub fn max_axis1(&self) -> Result<Series, FrameError> {
        // Per br-frankenpandas-c0g3x: sister to sum_axis1 above.
        if self.all_columns_timedelta() {
            return self.reduce_rows_timedelta(
                |ns_vals| ns_vals.iter().copied().max().unwrap_or(Timedelta::NAT),
                "max",
            );
        }
        self.reduce_rows(
            |vals| vals.iter().copied().fold(f64::NEG_INFINITY, f64::max),
            "max",
        )
    }

    /// Per br-frankenpandas-c0g3x: Timedelta-typed row reducer for axis=1
    /// sum/mean/min/max. Collects ns from Timedelta64 columns per row
    /// (skipping NaT), applies the op, emits Scalar::Timedelta64.
    fn reduce_rows_timedelta<F>(&self, op: F, name: &str) -> Result<Series, FrameError>
    where
        F: Fn(&[i64]) -> i64,
    {
        let mut values = Vec::with_capacity(self.len());
        for row_idx in 0..self.len() {
            let mut ns_vals: Vec<i64> = Vec::with_capacity(self.column_order.len());
            for col_name in &self.column_order {
                if let Scalar::Timedelta64(ns) = &self.columns[col_name].values()[row_idx]
                    && *ns != Timedelta::NAT
                {
                    ns_vals.push(*ns);
                }
            }
            values.push(Scalar::Timedelta64(op(&ns_vals)));
        }
        let index = Index::new(self.index.labels().to_vec()).rename_index(self.index.name());
        let column = Column::new(DType::Timedelta64, values)?;
        Series::new(name.to_owned(), index, column)
    }

    /// Standard deviation across columns per row.
    ///
    /// Matches `pd.DataFrame.std(axis=1)`.
    pub fn std_axis1(&self) -> Result<Series, FrameError> {
        self.reduce_rows(|vals| Self::row_sample_var(vals).sqrt(), "std")
    }

    /// Variance across columns per row.
    ///
    /// Matches `pd.DataFrame.var(axis=1)`.
    pub fn var_axis1(&self) -> Result<Series, FrameError> {
        self.reduce_rows(Self::row_sample_var, "var")
    }

    /// Standard error of the mean across columns per row.
    ///
    /// Matches `pd.DataFrame.sem(axis=1)`.
    pub fn sem_axis1(&self) -> Result<Series, FrameError> {
        self.reduce_rows(Self::row_sem, "sem")
    }

    /// Skewness across columns per row.
    ///
    /// Matches `pd.DataFrame.skew(axis=1)`.
    pub fn skew_axis1(&self) -> Result<Series, FrameError> {
        self.reduce_rows(Self::row_skew, "skew")
    }

    /// Excess kurtosis across columns per row.
    ///
    /// Matches `pd.DataFrame.kurtosis(axis=1)`.
    pub fn kurtosis_axis1(&self) -> Result<Series, FrameError> {
        self.reduce_rows(Self::row_kurtosis, "kurtosis")
    }

    /// Alias for `kurtosis_axis1()` — pandas exposes
    /// `df.kurt(axis=1)` and `df.kurtosis(axis=1)` as equivalents.
    pub fn kurt_axis1(&self) -> Result<Series, FrameError> {
        self.kurtosis_axis1()
    }

    /// Count of non-null values across columns per row.
    ///
    /// Matches `pd.DataFrame.count(axis=1)`.
    pub fn count_axis1(&self) -> Result<Series, FrameError> {
        let mut values = Vec::with_capacity(self.len());
        for row_idx in 0..self.len() {
            let cnt = self
                .column_order
                .iter()
                .filter(|col_name| !self.columns[col_name.as_str()].values()[row_idx].is_missing())
                .count();
            values.push(Scalar::Int64(cnt as i64));
        }
        // Per br-frankenpandas-wgkw9: pandas df.count(axis=1) preserves row index name.
        let index = Index::new(self.index.labels().to_vec()).rename_index(self.index.name());
        let column = Column::from_values(values)?;
        Series::new("count".to_owned(), index, column)
    }

    /// Whether all non-null values are truthy across columns per row.
    ///
    /// Matches `pd.DataFrame.all(axis=1)`.
    pub fn all_axis1(&self) -> Result<Series, FrameError> {
        let mut values = Vec::with_capacity(self.len());
        for row_idx in 0..self.len() {
            let result = self.column_order.iter().all(|col_name| {
                let val = &self.columns[col_name.as_str()].values()[row_idx];
                match val {
                    Scalar::Null(_) => true, // NaN is ignored in all()
                    Scalar::Bool(b) => *b,
                    Scalar::Int64(v) => *v != 0,
                    Scalar::Float64(v) => *v != 0.0 && !v.is_nan(),
                    Scalar::Utf8(s) => !s.is_empty(),
                    Scalar::Timedelta64(v) => *v != 0 && *v != Timedelta::NAT,
                    Scalar::Datetime64(v) => *v != 0 && *v != Timedelta::NAT,
                    Scalar::Period(v) => *v != 0 && *v != i64::MIN,
                    Scalar::Interval(_) => true,
                }
            });
            values.push(Scalar::Bool(result));
        }
        // Per br-frankenpandas-tpwlx: pandas df.all(axis=1) preserves row index name.
        let index = Index::new(self.index.labels().to_vec()).rename_index(self.index.name());
        let column = Column::from_values(values)?;
        Series::new("all".to_owned(), index, column)
    }

    /// Whether any non-null value is truthy across columns per row.
    ///
    /// Matches `pd.DataFrame.any(axis=1)`.
    pub fn any_axis1(&self) -> Result<Series, FrameError> {
        let mut values = Vec::with_capacity(self.len());
        for row_idx in 0..self.len() {
            let result = self.column_order.iter().any(|col_name| {
                let val = &self.columns[col_name.as_str()].values()[row_idx];
                match val {
                    Scalar::Null(_) => false,
                    Scalar::Bool(b) => *b,
                    Scalar::Int64(v) => *v != 0,
                    Scalar::Float64(v) => *v != 0.0 && !v.is_nan(),
                    Scalar::Utf8(s) => !s.is_empty(),
                    Scalar::Timedelta64(v) => *v != 0 && *v != Timedelta::NAT,
                    Scalar::Datetime64(v) => *v != 0 && *v != Timedelta::NAT,
                    Scalar::Period(v) => *v != 0 && *v != i64::MIN,
                    Scalar::Interval(_) => true,
                }
            });
            values.push(Scalar::Bool(result));
        }
        // Per br-frankenpandas-29wua: pandas df.any(axis=1) preserves row index name.
        let index = Index::new(self.index.labels().to_vec()).rename_index(self.index.name());
        let column = Column::from_values(values)?;
        Series::new("any".to_owned(), index, column)
    }

    /// Median across columns per row.
    ///
    /// Matches `pd.DataFrame.median(axis=1)`.
    /// Per-row quantile across numeric columns (axis=1).
    ///
    /// Matches `pd.DataFrame.quantile(q, axis=1)`. For each row the
    /// numeric column values are collected (skipping non-numeric and
    /// missing entries) and their linear-interpolation quantile is
    /// returned. `q` must lie in `[0.0, 1.0]`. Rows with no numeric
    /// entries emit `Null(NaN)`.
    pub fn quantile_axis1(&self, q: f64) -> Result<Series, FrameError> {
        if !(0.0..=1.0).contains(&q) {
            return Err(FrameError::CompatibilityRejected(format!(
                "quantile must be between 0 and 1, got {q}"
            )));
        }
        let len = self.index.labels().len();
        // pandas df.quantile(q, axis=1) on a uniformly-Timedelta DataFrame
        // returns Timedelta per row. The numeric-only Int64/Float64 filter
        // silently drops Timedelta columns, leaving each row's nums empty
        // and emitting Null(NaN). Sister to the cum*_axis1 (br-bktp1) and
        // sum/mean/min/max_axis1 (br-c0g3x) Timedelta surgeries.
        let all_td = self.all_columns_timedelta();
        let mut out = Vec::with_capacity(len);
        for row_idx in 0..len {
            if all_td {
                let mut td_vals: Vec<f64> = Vec::new();
                for name in &self.column_order {
                    if let Scalar::Timedelta64(ns) = &self.columns[name].values()[row_idx]
                        && *ns != Timedelta::NAT
                    {
                        td_vals.push(*ns as f64);
                    }
                }
                if td_vals.is_empty() {
                    out.push(Scalar::Timedelta64(Timedelta::NAT));
                    continue;
                }
                td_vals.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
                let n = td_vals.len();
                let qns = if n == 1 {
                    td_vals[0]
                } else {
                    let pos = q * (n - 1) as f64;
                    let lo = pos.floor() as usize;
                    let hi = pos.ceil() as usize;
                    if lo == hi {
                        td_vals[lo]
                    } else {
                        let weight = pos - lo as f64;
                        td_vals[lo] + (td_vals[hi] - td_vals[lo]) * weight
                    }
                };
                let clamped = qns.clamp(i64::MIN as f64, i64::MAX as f64);
                out.push(Scalar::Timedelta64(clamped as i64));
                continue;
            }
            let mut nums: Vec<f64> = Vec::new();
            for name in &self.column_order {
                let col = &self.columns[name];
                if col.dtype() != DType::Int64 && col.dtype() != DType::Float64 {
                    continue;
                }
                let v = &col.values()[row_idx];
                if v.is_missing() {
                    continue;
                }
                if let Ok(f) = v.to_f64()
                    && !f.is_nan()
                {
                    nums.push(f);
                }
            }
            if nums.is_empty() {
                out.push(Scalar::Null(NullKind::NaN));
                continue;
            }
            nums.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
            let n = nums.len();
            if n == 1 {
                out.push(Scalar::Float64(nums[0]));
                continue;
            }
            let pos = q * (n - 1) as f64;
            let lo = pos.floor() as usize;
            let hi = pos.ceil() as usize;
            let value = if lo == hi {
                nums[lo]
            } else {
                let weight = pos - lo as f64;
                nums[lo] + (nums[hi] - nums[lo]) * weight
            };
            out.push(Scalar::Float64(value));
        }
        // Per br-frankenpandas-jhhml: pandas df.quantile(q, axis=1) preserves row index name.
        let index = Index::new(self.index.labels().to_vec()).rename_index(self.index.name());
        let column = Column::from_values(out)?;
        Series::new("quantile", index, column)
    }

    /// Per-row index label of the first smallest numeric value.
    ///
    /// Matches `pd.DataFrame.idxmin(axis=1)` combined with positional
    /// column lookup. Returns the column-name Series entry for each
    /// row's argmin; rows with no numeric entries emit Null(NaN).
    pub fn argmin_axis1(&self) -> Result<Series, FrameError> {
        self.arg_extrema_axis1(false)
    }

    /// Per-row index label of the first largest numeric value.
    ///
    /// Matches `pd.DataFrame.idxmax(axis=1)`.
    pub fn argmax_axis1(&self) -> Result<Series, FrameError> {
        self.arg_extrema_axis1(true)
    }

    fn arg_extrema_axis1(&self, largest: bool) -> Result<Series, FrameError> {
        let len = self.index.labels().len();
        let mut out = Vec::with_capacity(len);
        for row_idx in 0..len {
            let mut best: Option<(&str, f64)> = None;
            for name in &self.column_order {
                let col = &self.columns[name];
                if col.dtype() != DType::Int64 && col.dtype() != DType::Float64 {
                    continue;
                }
                let v = &col.values()[row_idx];
                if v.is_missing() {
                    continue;
                }
                if let Ok(f) = v.to_f64()
                    && !f.is_nan()
                {
                    let take = match best {
                        None => true,
                        Some((_, cur)) if largest => f > cur,
                        Some((_, cur)) => f < cur,
                    };
                    if take {
                        best = Some((name.as_str(), f));
                    }
                }
            }
            match best {
                Some((name, _)) => out.push(Scalar::Utf8(name.to_owned())),
                None => out.push(Scalar::Null(NullKind::NaN)),
            }
        }
        let label = if largest { "idxmax" } else { "idxmin" };
        // Per br-frankenpandas-nbpsb: pandas df.idxmin(axis=1)/idxmax(axis=1)
        // preserve row-axis name.
        let index = Index::new(self.index.labels().to_vec()).rename_index(self.index.name());
        let column = Column::from_values(out)?;
        Series::new(label, index, column)
    }

    pub fn median_axis1(&self) -> Result<Series, FrameError> {
        self.reduce_rows(
            |vals| {
                let mut sorted = vals.to_vec();
                sorted.sort_by(|a, b| a.partial_cmp(b).unwrap_or(std::cmp::Ordering::Equal));
                let n = sorted.len();
                if n % 2 == 0 {
                    (sorted[n / 2 - 1] + sorted[n / 2]) / 2.0
                } else {
                    sorted[n / 2]
                }
            },
            "median",
        )
    }

    /// Product across columns per row.
    ///
    /// Matches `pd.DataFrame.prod(axis=1)`.
    pub fn prod_axis1(&self) -> Result<Series, FrameError> {
        self.reduce_rows(|vals| vals.iter().product(), "prod")
    }

    /// Internal: extract a named column as a Series.
    fn column_as_series(&self, name: &str) -> Result<Series, FrameError> {
        let col = self.columns.get(name).ok_or_else(|| {
            FrameError::CompatibilityRejected(format!("column not found: {name}"))
        })?;
        Series::new(name.to_string(), self.index.clone(), col.clone())
    }

    // ── DataFrame element-wise operations ──

    /// Cumulative sum per column.
    ///
    /// Matches `pd.DataFrame.cumsum()`.
    pub fn cumsum(&self) -> Result<Self, FrameError> {
        self.apply_per_column(|s| s.cumsum())
    }

    /// Cumulative product per column.
    ///
    /// Matches `pd.DataFrame.cumprod()`.
    pub fn cumprod(&self) -> Result<Self, FrameError> {
        self.apply_per_column(|s| s.cumprod())
    }

    /// Cumulative maximum per column.
    ///
    /// Matches `pd.DataFrame.cummax()`.
    pub fn cummax(&self) -> Result<Self, FrameError> {
        self.apply_per_column(|s| s.cummax())
    }

    /// Cumulative minimum per column.
    ///
    /// Matches `pd.DataFrame.cummin()`.
    pub fn cummin(&self) -> Result<Self, FrameError> {
        self.apply_per_column(|s| s.cummin())
    }

    fn cumulative_axis1<F>(&self, init: f64, op: F) -> Result<Self, FrameError>
    where
        F: Fn(f64, f64) -> f64 + Copy,
    {
        let mut per_column: Vec<Vec<Scalar>> = self
            .column_order
            .iter()
            .map(|_| Vec::with_capacity(self.len()))
            .collect();

        for row_idx in 0..self.len() {
            let mut acc = init;
            for (col_idx, col_name) in self.column_order.iter().enumerate() {
                let value = &self.columns[col_name].values()[row_idx];
                if value.is_missing() {
                    per_column[col_idx].push(Scalar::Null(NullKind::NaN));
                } else {
                    let x = value.to_f64().map_err(ColumnError::from)?;
                    acc = op(acc, x);
                    per_column[col_idx].push(Scalar::Float64(acc));
                }
            }
        }

        let mut columns = BTreeMap::new();
        for (name, values) in self.column_order.iter().cloned().zip(per_column) {
            columns.insert(name, Column::new(DType::Float64, values)?);
        }

        Ok(Self {
            columns,
            column_order: self.column_order.clone(),
            index: self.index.clone(),
            column_multiindex: self.column_multiindex.clone(),
            row_multiindex: self.row_multiindex.clone(),
            allows_duplicate_labels: self.allows_duplicate_labels,
        })
    }

    /// Per br-frankenpandas-bktp1: detect uniformly-Timedelta64 DataFrame.
    /// The f64 cumulative_axis1 helper errors via to_f64() on Timedelta64
    /// columns.
    fn all_columns_timedelta(&self) -> bool {
        !self.column_order.is_empty()
            && self
                .column_order
                .iter()
                .all(|name| matches!(self.columns[name].dtype(), DType::Timedelta64))
    }

    /// Per br-frankenpandas-bktp1: typed-i64 cumulative axis=1 reducer for
    /// uniformly-Timedelta DataFrames. Op operates on i64 ns; missing
    /// positions don't advance the accumulator. Emits Scalar::Timedelta64.
    fn cumulative_axis1_timedelta<Op>(&self, init: i64, op: Op) -> Result<Self, FrameError>
    where
        Op: Fn(i64, i64) -> i64,
    {
        let mut per_column: Vec<Vec<Scalar>> = self
            .column_order
            .iter()
            .map(|_| Vec::with_capacity(self.len()))
            .collect();
        for row_idx in 0..self.len() {
            let mut acc = init;
            let mut started = false;
            for (col_idx, col_name) in self.column_order.iter().enumerate() {
                let value = &self.columns[col_name].values()[row_idx];
                match value {
                    Scalar::Timedelta64(ns) if *ns != Timedelta::NAT => {
                        acc = if started { op(acc, *ns) } else { *ns };
                        started = true;
                        per_column[col_idx].push(Scalar::Timedelta64(acc));
                    }
                    _ => per_column[col_idx].push(Scalar::Timedelta64(Timedelta::NAT)),
                }
            }
        }
        let mut columns = BTreeMap::new();
        for (name, values) in self.column_order.iter().cloned().zip(per_column) {
            columns.insert(name, Column::new(DType::Timedelta64, values)?);
        }
        Ok(Self {
            columns,
            column_order: self.column_order.clone(),
            index: self.index.clone(),
            column_multiindex: self.column_multiindex.clone(),
            row_multiindex: self.row_multiindex.clone(),
            allows_duplicate_labels: self.allows_duplicate_labels,
        })
    }

    /// Cumulative sum across columns, computed row-wise.
    ///
    /// Matches `pd.DataFrame.cumsum(axis=1, skipna=True)`.
    pub fn cumsum_axis1(&self) -> Result<Self, FrameError> {
        if self.all_columns_timedelta() {
            return self.cumulative_axis1_timedelta(0, Timedelta::add);
        }
        self.cumulative_axis1(0.0, |acc, x| acc + x)
    }

    /// Cumulative product across columns, computed row-wise.
    ///
    /// Matches `pd.DataFrame.cumprod(axis=1, skipna=True)`.
    pub fn cumprod_axis1(&self) -> Result<Self, FrameError> {
        // Per br-frankenpandas-bktp1: pandas raises TypeError on
        // td_df.cumprod(axis=1); mirror Series::cumprod br-v36qy by emitting
        // all-NaT for uniformly-Timedelta DataFrames.
        if self.all_columns_timedelta() {
            let mut columns = BTreeMap::new();
            for name in &self.column_order {
                let len = self.len();
                let vals: Vec<Scalar> = (0..len)
                    .map(|_| Scalar::Timedelta64(Timedelta::NAT))
                    .collect();
                columns.insert(name.clone(), Column::new(DType::Timedelta64, vals)?);
            }
            return Ok(Self {
                columns,
                column_order: self.column_order.clone(),
                index: self.index.clone(),
                column_multiindex: self.column_multiindex.clone(),
                row_multiindex: self.row_multiindex.clone(),
                allows_duplicate_labels: self.allows_duplicate_labels,
            });
        }
        self.cumulative_axis1(1.0, |acc, x| acc * x)
    }

    /// Cumulative minimum across columns, computed row-wise.
    ///
    /// Matches `pd.DataFrame.cummin(axis=1, skipna=True)`.
    pub fn cummin_axis1(&self) -> Result<Self, FrameError> {
        // Per br-frankenpandas-bktp1: sister to cumsum_axis1 above.
        if self.all_columns_timedelta() {
            return self.cumulative_axis1_timedelta(i64::MAX, |a, b| a.min(b));
        }
        self.cumulative_axis1(f64::INFINITY, f64::min)
    }

    /// Cumulative maximum across columns, computed row-wise.
    ///
    /// Matches `pd.DataFrame.cummax(axis=1, skipna=True)`.
    pub fn cummax_axis1(&self) -> Result<Self, FrameError> {
        // Per br-frankenpandas-bktp1: sister to cumsum_axis1 above.
        if self.all_columns_timedelta() {
            return self.cumulative_axis1_timedelta(i64::MIN, |a, b| a.max(b));
        }
        self.cumulative_axis1(f64::NEG_INFINITY, f64::max)
    }

    /// First-order difference per column.
    ///
    /// Matches `pd.DataFrame.diff(periods)`.
    pub fn diff(&self, periods: i64) -> Result<Self, FrameError> {
        self.apply_per_column(|s| s.diff(periods))
    }

    /// First-order difference across columns per row.
    ///
    /// Matches `pd.DataFrame.diff(periods, axis=1)`.
    pub fn diff_axis1(&self, periods: i64) -> Result<Self, FrameError> {
        let n_cols = self.column_order.len();
        let n_rows = self.len();
        let mut out_cols = BTreeMap::new();

        // Per br-frankenpandas-r82bc: detect uniformly-Timedelta64 column and
        // preserve dtype. Sister surgery to pct_change_axis1's
        // br-frankenpandas-dj6rv Timedelta64 branch — but for diff the result
        // is Timedelta64 (delta of deltas), not f64 (dimensionless ratio).
        let all_timedelta = self.column_order.iter().all(|name| {
            let col = &self.columns[name];
            matches!(col.dtype(), DType::Timedelta64)
                || col.values().iter().all(|v| {
                    matches!(v, Scalar::Timedelta64(_))
                        || matches!(v, Scalar::Null(NullKind::NaT))
                        || v.is_missing()
                })
        }) && self.column_order.iter().any(|name| {
            self.columns[name]
                .values()
                .iter()
                .any(|v| matches!(v, Scalar::Timedelta64(ns) if *ns != Timedelta::NAT))
        });

        for (j, name) in self.column_order.iter().enumerate() {
            let mut vals = Vec::with_capacity(n_rows);
            let prev_idx = if periods >= 0 {
                j.checked_sub(periods as usize)
            } else {
                let p = periods.unsigned_abs() as usize;
                match j.checked_add(p) {
                    Some(p_idx) if p_idx < n_cols => Some(p_idx),
                    _ => None,
                }
            };

            if let Some(p_idx) = prev_idx {
                let prev_name = &self.column_order[p_idx];
                let current_col = &self.columns[name];
                let prev_col = &self.columns[prev_name];

                for i in 0..n_rows {
                    let curr_val = &current_col.values()[i];
                    let prev_val = &prev_col.values()[i];
                    if curr_val.is_missing() || prev_val.is_missing() {
                        if all_timedelta {
                            vals.push(Scalar::Timedelta64(Timedelta::NAT));
                        } else {
                            vals.push(Scalar::Null(NullKind::NaN));
                        }
                        continue;
                    }
                    if let (Scalar::Timedelta64(c_ns), Scalar::Timedelta64(p_ns)) =
                        (curr_val, prev_val)
                    {
                        vals.push(Scalar::Timedelta64(Timedelta::sub(*c_ns, *p_ns)));
                        continue;
                    }
                    match (curr_val.to_f64(), prev_val.to_f64()) {
                        (Ok(c), Ok(p)) => vals.push(Scalar::Float64(c - p)),
                        _ => vals.push(Scalar::Null(NullKind::NaN)),
                    }
                }
            } else if all_timedelta {
                vals.resize(n_rows, Scalar::Timedelta64(Timedelta::NAT));
            } else {
                vals.resize(n_rows, Scalar::Null(NullKind::NaN));
            }
            let out_dtype = if all_timedelta {
                DType::Timedelta64
            } else {
                DType::Float64
            };
            out_cols.insert(name.clone(), Column::new(out_dtype, vals)?);
        }
        Self::new_with_column_order(self.index.clone(), out_cols, self.column_order.clone())
    }

    /// Percentage change across columns per row.
    ///
    /// Matches `pd.DataFrame.pct_change(periods, axis=1)`.
    pub fn pct_change_axis1(&self, periods: i64) -> Result<Self, FrameError> {
        let n_cols = self.column_order.len();
        let n_rows = self.len();
        let mut out_cols = BTreeMap::new();

        for (j, name) in self.column_order.iter().enumerate() {
            let mut vals = Vec::with_capacity(n_rows);
            let prev_idx = if periods >= 0 {
                j.checked_sub(periods as usize)
            } else {
                let p = periods.unsigned_abs() as usize;
                match j.checked_add(p) {
                    Some(p_idx) if p_idx < n_cols => Some(p_idx),
                    _ => None,
                }
            };

            if let Some(p_idx) = prev_idx {
                let prev_name = &self.column_order[p_idx];
                let current_col = &self.columns[name];
                let prev_col = &self.columns[prev_name];

                for i in 0..n_rows {
                    let curr_val = &current_col.values()[i];
                    let prev_val = &prev_col.values()[i];
                    if curr_val.is_missing() || prev_val.is_missing() {
                        vals.push(Scalar::Null(NullKind::NaN));
                        continue;
                    }
                    // Per br-frankenpandas-dj6rv: Timedelta64 pct_change
                    // ratio is dimensionless f64.
                    if let (Scalar::Timedelta64(c_ns), Scalar::Timedelta64(p_ns)) =
                        (curr_val, prev_val)
                    {
                        if *c_ns == Timedelta::NAT || *p_ns == Timedelta::NAT {
                            vals.push(Scalar::Null(NullKind::NaN));
                        } else {
                            vals.push(Scalar::Float64(
                                (*c_ns as f64 - *p_ns as f64) / (*p_ns as f64),
                            ));
                        }
                        continue;
                    }
                    match (curr_val.to_f64(), prev_val.to_f64()) {
                        (Ok(c), Ok(p)) => vals.push(Scalar::Float64((c - p) / p)),
                        _ => vals.push(Scalar::Null(NullKind::NaN)),
                    }
                }
            } else {
                vals.resize(n_rows, Scalar::Null(NullKind::NaN));
            }
            out_cols.insert(name.clone(), Column::new(DType::Float64, vals)?);
        }

        Self::new_with_column_order(self.index.clone(), out_cols, self.column_order.clone())
    }

    /// Shift values per column.
    ///
    /// Matches `pd.DataFrame.shift(periods)`.
    pub fn shift(&self, periods: i64) -> Result<Self, FrameError> {
        self.apply_per_column(|s| s.shift(periods))
    }

    /// Shift index horizontally by desired number of periods.
    ///
    /// Matches `pd.DataFrame.shift(periods, axis=1)`.
    pub fn shift_axis1(&self, periods: i64) -> Result<Self, FrameError> {
        let n_cols = self.column_order.len();
        if n_cols == 0 {
            return Ok(self.clone());
        }

        let mut out_cols = std::collections::BTreeMap::new();
        let missing_val = fp_types::Scalar::Null(fp_types::NullKind::NaN);

        for (i, name) in self.column_order.iter().enumerate() {
            let src_idx = i as i64 - periods;
            let col = if src_idx >= 0 && (src_idx as usize) < n_cols {
                let src_name = &self.column_order[src_idx as usize];
                self.columns[src_name].clone()
            } else {
                Column::from_values(vec![missing_val.clone(); self.len()])?
            };
            out_cols.insert(name.clone(), col);
        }

        Ok(Self {
            index: self.index.clone(),
            column_order: self.column_order.clone(),
            columns: out_cols,
            column_multiindex: self.column_multiindex.clone(),
            row_multiindex: self.row_multiindex.clone(),
            allows_duplicate_labels: self.allows_duplicate_labels,
        })
    }

