    // ── DataFrame-to-DataFrame arithmetic ──

    /// Internal: apply a binary operation between two DataFrames element-wise.
    ///
    /// Aligns on index (outer join), operates on shared numeric columns,
    /// fills missing with NaN.
    fn binary_df_op<F>(&self, other: &Self, op: F, _name: &str) -> Result<Self, FrameError>
    where
        F: Fn(f64, f64) -> f64,
    {
        // Per br-frankenpandas-b0cab: fast path for the common case where self
        // and other already share the same index and column ordering. The
        // align_on_index round-trip would otherwise materialize two intermediate
        // DataFrames byte-identical to self/other, costing 2×N×M Scalar clones
        // that are discarded immediately by the op loop below. Skipping it
        // saves both the alignment-plan build and those wasted clones; the
        // result is identical for the equal-shape case.
        if self.column_order == other.column_order
            && self.index == other.index
            && !self.index.has_duplicates()
            && self
                .column_order
                .iter()
                .all(|n| other.columns.contains_key(n))
        {
            let mut result_cols = BTreeMap::new();
            for col_name in &self.column_order {
                let lc = &self.columns[col_name];
                let rc = &other.columns[col_name];
                let left_numlike =
                    matches!(lc.dtype(), DType::Int64 | DType::Float64 | DType::Null);
                let right_numlike =
                    matches!(rc.dtype(), DType::Int64 | DType::Float64 | DType::Null);

                if left_numlike && right_numlike {
                    let vals: Vec<Scalar> = lc
                        .values()
                        .iter()
                        .zip(rc.values())
                        .map(|(lv, rv)| match (lv.to_f64(), rv.to_f64()) {
                            (Ok(l), Ok(r)) => Scalar::Float64(op(l, r)),
                            _ => Scalar::Null(NullKind::NaN),
                        })
                        .collect();
                    result_cols.insert(col_name.clone(), Column::from_values(vals)?);
                } else {
                    result_cols.insert(col_name.clone(), lc.clone());
                }
            }
            return Ok(Self {
                columns: result_cols,
                column_order: self.column_order.clone(),
                index: self.index.clone(),
                column_multiindex: self.column_multiindex.clone(),
                row_multiindex: self.row_multiindex.clone(),
                allows_duplicate_labels: self.allows_duplicate_labels,
            });
        }

        // align_on_index with Outer gives both sides the union column set,
        // filling missing columns with NaN (DType::Null).
        let (left, right) = self.align_on_index(other, AlignMode::Outer)?;

        let mut result_cols = BTreeMap::new();

        for col_name in &left.column_order {
            let lc = &left.columns[col_name];
            let rc = &right.columns[col_name];
            let left_numlike = matches!(lc.dtype(), DType::Int64 | DType::Float64 | DType::Null);
            let right_numlike = matches!(rc.dtype(), DType::Int64 | DType::Float64 | DType::Null);

            if left_numlike && right_numlike {
                // to_f64() returns Err for Null values, which maps to NaN
                let vals: Vec<Scalar> = lc
                    .values()
                    .iter()
                    .zip(rc.values())
                    .map(|(lv, rv)| match (lv.to_f64(), rv.to_f64()) {
                        (Ok(l), Ok(r)) => Scalar::Float64(op(l, r)),
                        _ => Scalar::Null(NullKind::NaN),
                    })
                    .collect();
                result_cols.insert(col_name.clone(), Column::from_values(vals)?);
            } else {
                result_cols.insert(col_name.clone(), lc.clone());
            }
        }

        Ok(Self {
            columns: result_cols,
            column_order: left.column_order.clone(),
            index: left.index.clone(),
            column_multiindex: left.column_multiindex.clone(),
            row_multiindex: left.row_multiindex.clone(),
            allows_duplicate_labels: left.allows_duplicate_labels,
        })
    }

    /// Add another DataFrame element-wise with index alignment.
    ///
    /// Matches `pd.DataFrame.add(other)`.
    pub fn add_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_df_op(other, |a, b| a + b, "add")
    }

    /// Subtract another DataFrame element-wise with index alignment.
    ///
    /// Matches `pd.DataFrame.sub(other)`.
    pub fn sub_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_df_op(other, |a, b| a - b, "sub")
    }

    /// Multiply another DataFrame element-wise with index alignment.
    ///
    /// Matches `pd.DataFrame.mul(other)`.
    pub fn mul_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_df_op(other, |a, b| a * b, "mul")
    }

    /// Divide by another DataFrame element-wise with index alignment.
    ///
    /// Matches `pd.DataFrame.div(other)`.
    pub fn div_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_df_op(other, |a, b| a / b, "div")
    }

    /// Floor-divide by another DataFrame element-wise with index alignment.
    ///
    /// Matches `pd.DataFrame.floordiv(other)`.
    pub fn floordiv_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_df_op(other, |a, b| (a / b).floor(), "floordiv")
    }

    /// Modulo with another DataFrame element-wise with index alignment.
    ///
    /// Matches `pd.DataFrame.mod(other)`.
    pub fn mod_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_df_op(other, |a, b| a % b, "mod")
    }

    /// Raise another DataFrame element-wise to the power with index alignment.
    ///
    /// Matches `pd.DataFrame.pow(other)` / `df1 ** df2`.
    pub fn pow_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_df_op(other, |a, b| a.powf(b), "pow")
    }

    /// Internal: element-wise binary operation between two DataFrames with fill_value.
    ///
    /// When one operand is NaN/missing and the other is not, the missing operand
    /// is replaced by `fill_value` before applying `op`. When both are missing,
    /// the result is NaN.
    fn binary_df_op_fill<F>(&self, other: &Self, op: F, fill_value: f64) -> Result<Self, FrameError>
    where
        F: Fn(f64, f64) -> f64,
    {
        let (left, right) = self.align_on_index(other, AlignMode::Outer)?;
        let mut result_cols = BTreeMap::new();
        for col_name in &left.column_order {
            let lc = &left.columns[col_name];
            let rc = &right.columns[col_name];
            let left_numlike = matches!(lc.dtype(), DType::Int64 | DType::Float64 | DType::Null);
            let right_numlike = matches!(rc.dtype(), DType::Int64 | DType::Float64 | DType::Null);
            if left_numlike && right_numlike {
                let vals: Vec<Scalar> = lc
                    .values()
                    .iter()
                    .zip(rc.values())
                    .map(|(lv, rv)| {
                        let l_miss = lv.is_missing();
                        let r_miss = rv.is_missing();
                        if l_miss && r_miss {
                            Scalar::Null(NullKind::NaN)
                        } else {
                            let l = if l_miss {
                                fill_value
                            } else {
                                match lv.to_f64() {
                                    Ok(v) => v,
                                    Err(_) => return Scalar::Null(NullKind::NaN),
                                }
                            };
                            let r = if r_miss {
                                fill_value
                            } else {
                                match rv.to_f64() {
                                    Ok(v) => v,
                                    Err(_) => return Scalar::Null(NullKind::NaN),
                                }
                            };
                            Scalar::Float64(op(l, r))
                        }
                    })
                    .collect();
                result_cols.insert(col_name.clone(), Column::from_values(vals)?);
            } else {
                result_cols.insert(col_name.clone(), lc.clone());
            }
        }
        Ok(Self {
            columns: result_cols,
            column_order: left.column_order.clone(),
            index: left.index.clone(),
            column_multiindex: left.column_multiindex.clone(),
            row_multiindex: left.row_multiindex.clone(),
            allows_duplicate_labels: left.allows_duplicate_labels,
        })
    }

    /// Add another DataFrame element-wise with fill_value for NaN handling.
    ///
    /// Matches `pd.DataFrame.add(other, fill_value=X)`.
    pub fn add_df_fill(&self, other: &Self, fill_value: f64) -> Result<Self, FrameError> {
        self.binary_df_op_fill(other, |a, b| a + b, fill_value)
    }

    /// Subtract another DataFrame element-wise with fill_value for NaN handling.
    ///
    /// Matches `pd.DataFrame.sub(other, fill_value=X)`.
    pub fn sub_df_fill(&self, other: &Self, fill_value: f64) -> Result<Self, FrameError> {
        self.binary_df_op_fill(other, |a, b| a - b, fill_value)
    }

    /// Multiply another DataFrame element-wise with fill_value for NaN handling.
    ///
    /// Matches `pd.DataFrame.mul(other, fill_value=X)`.
    pub fn mul_df_fill(&self, other: &Self, fill_value: f64) -> Result<Self, FrameError> {
        self.binary_df_op_fill(other, |a, b| a * b, fill_value)
    }

    /// Divide by another DataFrame element-wise with fill_value for NaN handling.
    ///
    /// Matches `pd.DataFrame.div(other, fill_value=X)`.
    pub fn div_df_fill(&self, other: &Self, fill_value: f64) -> Result<Self, FrameError> {
        self.binary_df_op_fill(
            other,
            |a, b| if b == 0.0 { f64::NAN } else { a / b },
            fill_value,
        )
    }

    /// Floor-divide by another DataFrame element-wise with fill_value for NaN handling.
    ///
    /// Matches `pd.DataFrame.floordiv(other, fill_value=X)`.
    pub fn floordiv_df_fill(&self, other: &Self, fill_value: f64) -> Result<Self, FrameError> {
        self.binary_df_op_fill(
            other,
            |a, b| if b == 0.0 { f64::NAN } else { (a / b).floor() },
            fill_value,
        )
    }

    /// Modulo with another DataFrame element-wise with fill_value for NaN handling.
    ///
    /// Matches `pd.DataFrame.mod(other, fill_value=X)`.
    pub fn mod_df_fill(&self, other: &Self, fill_value: f64) -> Result<Self, FrameError> {
        self.binary_df_op_fill(
            other,
            |a, b| if b == 0.0 { f64::NAN } else { a % b },
            fill_value,
        )
    }

    /// Floor-divide all numeric columns by a scalar.
    ///
    /// Matches `pd.DataFrame.floordiv(scalar)`.
    pub fn floordiv_scalar(&self, value: f64) -> Result<Self, FrameError> {
        self.apply_scalar_op(value, |a, b| (a / b).floor())
    }

    // ── DataFrame-to-DataFrame comparison operators ──

    /// Internal: apply a comparison operation between two DataFrames element-wise.
    ///
    /// Aligns on index (outer join), compares shared columns,
    /// produces a DataFrame of Bool values.
    fn binary_cmp_op(&self, other: &Self, op: ComparisonOp) -> Result<Self, FrameError> {
        let (left, right) = self.align_on_index(other, AlignMode::Outer)?;

        let mut result_cols = BTreeMap::new();
        for col_name in &left.column_order {
            let lc = &left.columns[col_name];
            let rc = &right.columns[col_name];

            let vals: Vec<Scalar> = lc
                .values()
                .iter()
                .zip(rc.values())
                .map(|(lv, rv)| {
                    if lv.is_missing() || rv.is_missing() {
                        return Scalar::Null(NullKind::Null);
                    }
                    match (lv.to_f64(), rv.to_f64()) {
                        (Ok(l), Ok(r)) => Scalar::Bool(match op {
                            ComparisonOp::Eq => l == r,
                            ComparisonOp::Ne => l != r,
                            ComparisonOp::Gt => l > r,
                            ComparisonOp::Ge => l >= r,
                            ComparisonOp::Lt => l < r,
                            ComparisonOp::Le => l <= r,
                        }),
                        _ => {
                            // For non-numeric, compare as strings
                            let ls = format!("{lv}");
                            let rs = format!("{rv}");
                            Scalar::Bool(match op {
                                ComparisonOp::Eq => ls == rs,
                                ComparisonOp::Ne => ls != rs,
                                ComparisonOp::Gt => ls > rs,
                                ComparisonOp::Ge => ls >= rs,
                                ComparisonOp::Lt => ls < rs,
                                ComparisonOp::Le => ls <= rs,
                            })
                        }
                    }
                })
                .collect();
            result_cols.insert(col_name.clone(), Column::from_values(vals)?);
        }

        Ok(Self {
            columns: result_cols,
            column_order: left.column_order.clone(),
            index: left.index.clone(),
            column_multiindex: left.column_multiindex.clone(),
            row_multiindex: left.row_multiindex.clone(),
            allows_duplicate_labels: left.allows_duplicate_labels,
        })
    }

    /// Element-wise equality with another DataFrame.
    ///
    /// Matches `pd.DataFrame.eq(other)`.
    pub fn eq_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_cmp_op(other, ComparisonOp::Eq)
    }

    /// Element-wise not-equal with another DataFrame.
    ///
    /// Matches `pd.DataFrame.ne(other)`.
    pub fn ne_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_cmp_op(other, ComparisonOp::Ne)
    }

    /// Element-wise greater-than with another DataFrame.
    ///
    /// Matches `pd.DataFrame.gt(other)`.
    pub fn gt_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_cmp_op(other, ComparisonOp::Gt)
    }

    /// Element-wise greater-or-equal with another DataFrame.
    ///
    /// Matches `pd.DataFrame.ge(other)`.
    pub fn ge_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_cmp_op(other, ComparisonOp::Ge)
    }

    /// Element-wise less-than with another DataFrame.
    ///
    /// Matches `pd.DataFrame.lt(other)`.
    pub fn lt_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_cmp_op(other, ComparisonOp::Lt)
    }

    /// Element-wise less-or-equal with another DataFrame.
    ///
    /// Matches `pd.DataFrame.le(other)`.
    pub fn le_df(&self, other: &Self) -> Result<Self, FrameError> {
        self.binary_cmp_op(other, ComparisonOp::Le)
    }

    /// Compare each element in all columns against a scalar.
    ///
    /// Matches `pd.DataFrame.eq(scalar)` etc.
    pub fn compare_scalar_df(&self, scalar: &Scalar, op: ComparisonOp) -> Result<Self, FrameError> {
        let mut result_cols = BTreeMap::new();
        for col_name in &self.column_order {
            let col = &self.columns[col_name];
            let vals: Vec<Scalar> = col
                .values()
                .iter()
                .map(|v| {
                    if v.is_missing() || scalar.is_missing() {
                        return Scalar::Null(NullKind::Null);
                    }
                    match (v.to_f64(), scalar.to_f64()) {
                        (Ok(l), Ok(r)) => Scalar::Bool(match op {
                            ComparisonOp::Eq => l == r,
                            ComparisonOp::Ne => l != r,
                            ComparisonOp::Gt => l > r,
                            ComparisonOp::Ge => l >= r,
                            ComparisonOp::Lt => l < r,
                            ComparisonOp::Le => l <= r,
                        }),
                        _ => {
                            let vs = format!("{v}");
                            let ss = format!("{scalar}");
                            Scalar::Bool(match op {
                                ComparisonOp::Eq => vs == ss,
                                ComparisonOp::Ne => vs != ss,
                                ComparisonOp::Gt => vs > ss,
                                ComparisonOp::Ge => vs >= ss,
                                ComparisonOp::Lt => vs < ss,
                                ComparisonOp::Le => vs <= ss,
                            })
                        }
                    }
                })
                .collect();
            result_cols.insert(col_name.clone(), Column::from_values(vals)?);
        }

        Ok(Self {
            columns: result_cols,
            column_order: self.column_order.clone(),
            index: self.index.clone(),
            column_multiindex: self.column_multiindex.clone(),
            row_multiindex: self.row_multiindex.clone(),
            allows_duplicate_labels: self.allows_duplicate_labels,
        })
    }

    /// Element-wise `== scalar` for all columns.
    pub fn eq_scalar_df(&self, scalar: &Scalar) -> Result<Self, FrameError> {
        self.compare_scalar_df(scalar, ComparisonOp::Eq)
    }

    /// Element-wise `!= scalar` for all columns.
    pub fn ne_scalar_df(&self, scalar: &Scalar) -> Result<Self, FrameError> {
        self.compare_scalar_df(scalar, ComparisonOp::Ne)
    }

    /// Element-wise `> scalar` for all columns.
    pub fn gt_scalar_df(&self, scalar: &Scalar) -> Result<Self, FrameError> {
        self.compare_scalar_df(scalar, ComparisonOp::Gt)
    }

    /// Element-wise `>= scalar` for all columns.
    pub fn ge_scalar_df(&self, scalar: &Scalar) -> Result<Self, FrameError> {
        self.compare_scalar_df(scalar, ComparisonOp::Ge)
    }

    /// Element-wise `< scalar` for all columns.
    pub fn lt_scalar_df(&self, scalar: &Scalar) -> Result<Self, FrameError> {
        self.compare_scalar_df(scalar, ComparisonOp::Lt)
    }

    /// Element-wise `<= scalar` for all columns.
    pub fn le_scalar_df(&self, scalar: &Scalar) -> Result<Self, FrameError> {
        self.compare_scalar_df(scalar, ComparisonOp::Le)
    }

    /// Element-wise equality with another DataFrame or scalar.
    ///
    /// Matches `pd.DataFrame.eq(other)`.
    pub fn eq<'a, O>(&self, other: O) -> Result<Self, FrameError>
    where
        O: Into<DataFrameComparisonOperand<'a>>,
    {
        match other.into() {
            DataFrameComparisonOperand::DataFrame(frame) => self.eq_df(frame),
            DataFrameComparisonOperand::Scalar(scalar) => self.eq_scalar_df(&scalar),
        }
    }

