    #[test]
    fn series_clip_bounds_values() {
        let s = Series::from_values(
            "vals",
            vec![
                IndexLabel::from("a"),
                IndexLabel::from("b"),
                IndexLabel::from("c"),
            ],
            vec![
                Scalar::Float64(-5.0),
                Scalar::Float64(3.0),
                Scalar::Float64(10.0),
            ],
        )
        .unwrap();

        let clipped = s.clip(Some(0.0), Some(5.0)).unwrap();
        assert_eq!(clipped.values()[0], Scalar::Float64(0.0));
        assert_eq!(clipped.values()[1], Scalar::Float64(3.0));
        assert_eq!(clipped.values()[2], Scalar::Float64(5.0));
    }

    #[test]
    fn series_clip_nan_bound_preserves_int64_s0rt1() {
        // Per br-frankenpandas-s0rt1: pandas treats NaN bounds as "no
        // clipping" — they must NOT demote Int64 to Float64 and must
        // NOT participate in comparison.
        let s = Series::from_values(
            "v",
            vec![
                IndexLabel::from("a"),
                IndexLabel::from("b"),
                IndexLabel::from("c"),
            ],
            vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)],
        )
        .unwrap();

        // NaN as lower → no clipping; dtype stays Int64
        let clipped = s.clip(Some(f64::NAN), None).unwrap();
        assert_eq!(clipped.values()[0], Scalar::Int64(1));
        assert_eq!(clipped.values()[1], Scalar::Int64(2));
        assert_eq!(clipped.values()[2], Scalar::Int64(3));

        // Real lower bound 2 → 1 clipped to 2; dtype stays Int64
        let clipped = s.clip(Some(2.0), Some(f64::NAN)).unwrap();
        assert_eq!(clipped.values()[0], Scalar::Int64(2));
        assert_eq!(clipped.values()[1], Scalar::Int64(2));
        assert_eq!(clipped.values()[2], Scalar::Int64(3));
    }

    #[test]
    fn series_abs_and_round() {
        let neg_pi = -std::f64::consts::PI;
        let e = std::f64::consts::E;
        let s = Series::from_values(
            "vals",
            vec![IndexLabel::from("a"), IndexLabel::from("b")],
            vec![Scalar::Float64(neg_pi), Scalar::Float64(e)],
        )
        .unwrap();

        let a = s.abs().unwrap();
        assert!(
            matches!(a.values()[0], Scalar::Float64(v) if (v - std::f64::consts::PI).abs() < 1e-12)
        );

        let r = s.round(2).unwrap();
        let expected_neg_pi_2dp = (neg_pi * 100.0).round_ties_even() / 100.0;
        let expected_e_2dp = (e * 100.0).round_ties_even() / 100.0;
        assert!(
            matches!(r.values()[0], Scalar::Float64(v) if (v - expected_neg_pi_2dp).abs() < 1e-12)
        );
        assert!(matches!(r.values()[1], Scalar::Float64(v) if (v - expected_e_2dp).abs() < 1e-12));
    }

    #[test]
