    #[test]
    fn series_sort_values_numeric_ascending_keeps_missing_last() {
        let s = Series::from_values(
            "vals",
            vec![
                IndexLabel::from("r1"),
                IndexLabel::from("r2"),
                IndexLabel::from("r3"),
                IndexLabel::from("r4"),
                IndexLabel::from("r5"),
            ],
            vec![
                Scalar::Int64(3),
                Scalar::Null(NullKind::Null),
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Float64(f64::NAN),
            ],
        )
        .unwrap();

        let out = s.sort_values(true).unwrap();
        assert_eq!(
            out.index().labels(),
            &[
                IndexLabel::from("r3"),
                IndexLabel::from("r4"),
                IndexLabel::from("r1"),
                IndexLabel::from("r2"),
                IndexLabel::from("r5")
            ]
        );
        let expected = [
            Scalar::Float64(1.0),
            Scalar::Float64(2.0),
            Scalar::Float64(3.0),
            Scalar::Null(NullKind::NaN),
            Scalar::Float64(f64::NAN),
        ];
        assert_eq!(out.values().len(), expected.len());
        for (actual, expected) in out.values().iter().zip(expected.iter()) {
            assert!(
                actual.semantic_eq(expected),
                "series_sort_values_numeric_ascending mismatch: actual={actual:?}, expected={expected:?}"
            );
        }
    }

