    #[test]
    fn dataframe_sort_values_na_default_matches_last() {
        let df = DataFrame::from_dict_with_index(
            vec![("v", vec![Scalar::Null(NullKind::Null), Scalar::Int64(1)])],
            vec!["a".into(), "b".into()],
        )
        .unwrap();

        let default_sort = df.sort_values("v", true).unwrap();
        let explicit_last = df.sort_values_na("v", true, "last").unwrap();
        assert_eq!(
            default_sort.index().labels(),
            explicit_last.index().labels()
        );
    }

    #[test]
    fn dataframe_loc_selects_labels_in_request_order_with_duplicates() {
        let df = DataFrame::from_dict_with_index(
            vec![
                (
                    "a",
                    vec![Scalar::Int64(10), Scalar::Int64(20), Scalar::Int64(30)],
                ),
                (
                    "b",
                    vec![Scalar::Int64(100), Scalar::Int64(200), Scalar::Int64(300)],
                ),
            ],
            vec!["x".into(), "y".into(), "z".into()],
        )
        .unwrap();

        let selected = df.loc(&["z".into(), "x".into(), "z".into()]).unwrap();
        assert_eq!(
            selected.index().labels(),
            &[
                IndexLabel::from("z"),
                IndexLabel::from("x"),
                IndexLabel::from("z")
            ]
        );
        assert_eq!(
            selected.column("a").unwrap().values(),
            &[Scalar::Int64(30), Scalar::Int64(10), Scalar::Int64(30)]
        );
        assert_eq!(
            selected.column("b").unwrap().values(),
            &[Scalar::Int64(300), Scalar::Int64(100), Scalar::Int64(300)]
        );
    }

