    // --- Series::pct_change tests ---

    #[test]
    fn series_pct_change_basic() {
        let s = Series::from_values(
            "x",
            vec!["a".into(), "b".into(), "c".into(), "d".into()],
            vec![
                Scalar::Float64(100.0),
                Scalar::Float64(110.0),
                Scalar::Float64(99.0),
                Scalar::Float64(120.0),
            ],
        )
        .unwrap();

        let result = s.pct_change(1).unwrap();
        assert!(result.values()[0].is_missing()); // first is NaN
        let v1 = result.values()[1].to_f64().unwrap();
        assert!((v1 - 0.1).abs() < 1e-10); // (110-100)/100 = 0.1
        let v2 = result.values()[2].to_f64().unwrap();
        assert!((v2 - (-0.1)).abs() < 1e-10); // (99-110)/110 = -0.1
    }

    #[test]
    fn series_pct_change_periods_2() {
        let s = Series::from_values(
            "x",
            vec!["a".into(), "b".into(), "c".into()],
            vec![
                Scalar::Float64(100.0),
                Scalar::Float64(200.0),
                Scalar::Float64(150.0),
            ],
        )
        .unwrap();

        let result = s.pct_change(2).unwrap();
        assert!(result.values()[0].is_missing());
        assert!(result.values()[1].is_missing());
        let v2 = result.values()[2].to_f64().unwrap();
        assert!((v2 - 0.5).abs() < 1e-10); // (150-100)/100 = 0.5
    }

    #[test]
    fn series_pct_change_timedelta64_matches_pandas_naeja() {
        // Per br-frankenpandas-naeja: pct_change on Timedelta64 returns
        // dimensionless f64 ratios; was silently NaN before via the
        // to_f64-else-NaN catch-all.
        let one_hour = 3_600 * 1_000_000_000_i64;
        let two_hours = 2 * one_hour;
        let four_hours = 4 * one_hour;
        let s = Series::from_values(
            "x",
            vec!["a".into(), "b".into(), "c".into()],
            vec![
                Scalar::Timedelta64(one_hour),
                Scalar::Timedelta64(two_hours),
                Scalar::Timedelta64(four_hours),
            ],
        )
        .unwrap();

        let result = s.pct_change(1).unwrap();
        assert!(result.values()[0].is_missing()); // first is NaN
        let v1 = result.values()[1].to_f64().unwrap();
        assert!((v1 - 1.0).abs() < 1e-10); // (2h-1h)/1h = 1.0
        let v2 = result.values()[2].to_f64().unwrap();
        assert!((v2 - 1.0).abs() < 1e-10); // (4h-2h)/2h = 1.0
    }

    #[test]
    fn series_pct_change_timedelta64_nat_propagates_naeja() {
        let one_hour = 3_600 * 1_000_000_000_i64;
        let s = Series::from_values(
            "x",
            vec!["a".into(), "b".into(), "c".into()],
            vec![
                Scalar::Timedelta64(one_hour),
                Scalar::Timedelta64(fp_types::Timedelta::NAT),
                Scalar::Timedelta64(2 * one_hour),
            ],
        )
        .unwrap();

        let result = s.pct_change(1).unwrap();
        assert!(result.values()[0].is_missing());
        assert!(result.values()[1].is_missing()); // NaT current → NaN
        assert!(result.values()[2].is_missing()); // NaT previous → NaN
    }

    #[test]
    fn series_diff_timedelta64_returns_timedelta_q82t4() {
        // Per br-frankenpandas-q82t4: diff on Timedelta64 returns Timedelta64
        // differences (preserves dtype), not Float64. Was silently NaN before
        // via the to_f64-else-NaN catch-all.
        let one_hour = 3_600 * 1_000_000_000_i64;
        let s = Series::from_values(
            "x",
            vec!["a".into(), "b".into(), "c".into()],
            vec![
                Scalar::Timedelta64(one_hour),
                Scalar::Timedelta64(3 * one_hour),
                Scalar::Timedelta64(2 * one_hour),
            ],
        )
        .unwrap();

        let result = s.diff(1).unwrap();
        assert!(result.values()[0].is_missing()); // first row → NaN
        match &result.values()[1] {
            Scalar::Timedelta64(ns) => assert_eq!(*ns, 2 * one_hour),
            other => panic!("expected Timedelta64(2h), got {:?}", other),
        }
        match &result.values()[2] {
            Scalar::Timedelta64(ns) => assert_eq!(*ns, -one_hour),
            other => panic!("expected Timedelta64(-1h), got {:?}", other),
        }
    }

    #[test]
    fn series_diff_timedelta64_nat_propagates_q82t4() {
        let one_hour = 3_600 * 1_000_000_000_i64;
        let s = Series::from_values(
            "x",
            vec!["a".into(), "b".into(), "c".into()],
            vec![
                Scalar::Timedelta64(one_hour),
                Scalar::Timedelta64(fp_types::Timedelta::NAT),
                Scalar::Timedelta64(2 * one_hour),
            ],
        )
        .unwrap();

        let result = s.diff(1).unwrap();
        assert!(result.values()[0].is_missing());
        assert!(result.values()[1].is_missing()); // NaT current → NaT
        assert!(result.values()[2].is_missing()); // NaT previous → NaT
    }

