    #[test]
    fn dataframe_assign_length_mismatch() {
        let df = DataFrame::from_dict(
            &["a"],
            vec![("a", vec![Scalar::Int64(1), Scalar::Int64(2)])],
        )
        .unwrap();

        let bad_col = fp_columnar::Column::from_values(vec![Scalar::Int64(1)]).unwrap();
        assert!(df.assign(vec![("b", bad_col)]).is_err());
    }

    #[test]
    fn dataframe_pipe_basic() {
        let df = DataFrame::from_dict(
            &["a"],
            vec![("a", vec![Scalar::Int64(1), Scalar::Int64(2)])],
        )
        .unwrap();

        let result = df
            .pipe(|d| {
                let col =
                    fp_columnar::Column::from_values(vec![Scalar::Int64(10), Scalar::Int64(20)])?;
                d.assign(vec![("b", col)])
            })
            .unwrap();

        assert_eq!(result.num_columns(), 2);
        assert!(result.column("b").is_some());
    }

    // --- Rolling window tests ---

    #[test]
    fn rolling_mean_basic() {
        let s = Series::from_values(
            "x",
            vec![
                0_i64.into(),
                1_i64.into(),
                2_i64.into(),
                3_i64.into(),
                4_i64.into(),
            ],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
                Scalar::Float64(5.0),
            ],
        )
        .unwrap();

        let result = s.rolling(3, None).mean().unwrap();
        // First 2 should be NaN (window not full)
        assert!(result.values()[0].is_missing());
        assert!(result.values()[1].is_missing());
        // rolling(3).mean() at index 2 = (1+2+3)/3 = 2.0
        assert_eq!(result.values()[2], Scalar::Float64(2.0));
        // at index 3 = (2+3+4)/3 = 3.0
        assert_eq!(result.values()[3], Scalar::Float64(3.0));
        // at index 4 = (3+4+5)/3 = 4.0
        assert_eq!(result.values()[4], Scalar::Float64(4.0));
    }

    #[test]
    fn rolling_sum_basic() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
                Scalar::Float64(30.0),
            ],
        )
        .unwrap();

        let result = s.rolling(2, None).sum().unwrap();
        assert!(result.values()[0].is_missing());
        assert_eq!(result.values()[1], Scalar::Float64(30.0)); // 10+20
        assert_eq!(result.values()[2], Scalar::Float64(50.0)); // 20+30
    }

    #[test]
    fn rolling_min_max() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(3.0),
                Scalar::Float64(1.0),
                Scalar::Float64(4.0),
                Scalar::Float64(2.0),
            ],
        )
        .unwrap();

        let mins = s.rolling(2, None).min().unwrap();
        assert!(mins.values()[0].is_missing());
        assert_eq!(mins.values()[1], Scalar::Float64(1.0)); // min(3,1)
        assert_eq!(mins.values()[2], Scalar::Float64(1.0)); // min(1,4)
        assert_eq!(mins.values()[3], Scalar::Float64(2.0)); // min(4,2)

        let maxs = s.rolling(2, None).max().unwrap();
        assert_eq!(maxs.values()[1], Scalar::Float64(3.0)); // max(3,1)
        assert_eq!(maxs.values()[2], Scalar::Float64(4.0)); // max(1,4)
        assert_eq!(maxs.values()[3], Scalar::Float64(4.0)); // max(4,2)
    }

    #[test]
    fn rolling_min_min_periods_zero_allows_partial_windows() {
        let s = Series::from_values(
            "x",
            vec![
                0_i64.into(),
                1_i64.into(),
                2_i64.into(),
                3_i64.into(),
                4_i64.into(),
            ],
            vec![
                Scalar::Float64(5.0),
                Scalar::Float64(2.0),
                Scalar::Float64(8.0),
                Scalar::Float64(1.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();

        let mins = s.rolling(3, Some(0)).min().unwrap();
        assert_eq!(mins.values()[0], Scalar::Float64(5.0));
        assert_eq!(mins.values()[1], Scalar::Float64(2.0));
        assert_eq!(mins.values()[2], Scalar::Float64(2.0));
        assert_eq!(mins.values()[3], Scalar::Float64(1.0));
        assert_eq!(mins.values()[4], Scalar::Float64(1.0));
    }

    #[test]
    fn rolling_min_min_periods_one_allows_partial_windows_with_nulls() {
        let s = Series::from_values(
            "x",
            vec![
                0_i64.into(),
                1_i64.into(),
                2_i64.into(),
                3_i64.into(),
                4_i64.into(),
            ],
            vec![
                Scalar::Float64(5.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(3.0),
                Scalar::Float64(1.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();

        let mins = s.rolling(3, Some(1)).min().unwrap();
        assert_eq!(mins.values()[0], Scalar::Float64(5.0));
        assert_eq!(mins.values()[1], Scalar::Float64(5.0));
        assert_eq!(mins.values()[2], Scalar::Float64(3.0));
        assert_eq!(mins.values()[3], Scalar::Float64(1.0));
        assert_eq!(mins.values()[4], Scalar::Float64(1.0));
    }

    #[test]
    fn rolling_with_nulls() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();

        // min_periods=2 means we need at least 2 non-null in the window
        let result = s.rolling(3, Some(2)).mean().unwrap();
        assert!(result.values()[0].is_missing()); // window too small
        assert!(result.values()[1].is_missing()); // window too small
        // window [1, NaN, 3] -> non-null: [1,3] -> mean = 2.0
        assert_eq!(result.values()[2], Scalar::Float64(2.0));
    }

    #[test]
    fn rolling_count_counts_non_nulls_after_physical_window_is_ready() {
        let s = Series::from_values(
            "value",
            vec!["dup".into(), "dup".into(), "tail".into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Null(NullKind::Null),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();

        let result = s.rolling(2, None).count().unwrap();
        assert_eq!(result.values()[0], Scalar::Null(NullKind::NaN));
        assert_eq!(result.values()[1], Scalar::Float64(1.0));
        assert_eq!(result.values()[2], Scalar::Float64(1.0));
    }

    #[test]
    fn rolling_count_emits_zero_for_full_all_null_window() {
        let s = Series::from_values(
            "value",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Null(NullKind::Null),
                Scalar::Null(NullKind::NaN),
                Scalar::Null(NullKind::Null),
            ],
        )
        .unwrap();

        let result = s.rolling(2, None).count().unwrap();
        assert_eq!(result.values()[0], Scalar::Null(NullKind::NaN));
        assert_eq!(result.values()[1], Scalar::Float64(0.0));
        assert_eq!(result.values()[2], Scalar::Float64(0.0));
    }

    #[test]
    fn rolling_std() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Float64(4.0),
                Scalar::Float64(6.0),
            ],
        )
        .unwrap();

        let result = s.rolling(3, None).std().unwrap();
        assert!(result.values()[0].is_missing());
        assert!(result.values()[1].is_missing());
        // std of [2,4,6] = 2.0
        let std_val = result.values()[2].to_f64().unwrap();
        assert!((std_val - 2.0).abs() < 1e-10);
    }

    #[test]
    fn rolling_window_zero_is_rejected() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Float64(4.0),
                Scalar::Float64(6.0),
            ],
        )
        .unwrap();

        let mean_err = s.rolling(0, None).mean().unwrap_err();
        assert!(
            matches!(mean_err, FrameError::CompatibilityRejected(msg) if msg == "rolling window must be >= 1")
        );

        let count_err = s.rolling(0, Some(0)).count().unwrap_err();
        assert!(
            matches!(count_err, FrameError::CompatibilityRejected(msg) if msg == "rolling window must be >= 1")
        );
    }

    // --- Expanding window tests ---

    #[test]
    fn expanding_sum_basic() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();

        let result = s.expanding(None).sum().unwrap();
        assert_eq!(result.values()[0], Scalar::Float64(1.0));
        assert_eq!(result.values()[1], Scalar::Float64(3.0)); // 1+2
        assert_eq!(result.values()[2], Scalar::Float64(6.0)); // 1+2+3
        assert_eq!(result.values()[3], Scalar::Float64(10.0)); // 1+2+3+4
    }

    #[test]
    fn expanding_mean_basic() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Float64(4.0),
                Scalar::Float64(6.0),
            ],
        )
        .unwrap();

        let result = s.expanding(None).mean().unwrap();
        assert_eq!(result.values()[0], Scalar::Float64(2.0)); // 2/1
        assert_eq!(result.values()[1], Scalar::Float64(3.0)); // (2+4)/2
        assert_eq!(result.values()[2], Scalar::Float64(4.0)); // (2+4+6)/3
    }

    #[test]
    fn expanding_mean_empty_window_is_nan_not_zero() {
        // All leading values are missing → the agg window is empty; mean
        // should emit NaN (pandas convention) rather than 0/0 producing
        // an Inf or panic.
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Null(NullKind::NaN),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(10.0),
            ],
        )
        .unwrap();
        // min_periods=0 allows the aggregator to be called on an empty
        // slice; earlier positions should therefore still emit NaN.
        let result = s.expanding(Some(0)).mean().unwrap();
        assert!(result.values()[0].is_missing());
        assert!(result.values()[1].is_missing());
        assert_eq!(result.values()[2], Scalar::Float64(10.0));
    }

    #[test]
    fn expanding_sum_empty_window_returns_zero_when_min_periods_zero() {
        // pandas convention: empty-sum identity is 0.0 when
        // min_periods=0; only when min_periods >= 1 do we emit NaN.
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Null(NullKind::NaN),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(5.0),
            ],
        )
        .unwrap();
        let result = s.expanding(Some(0)).sum().unwrap();
        assert_eq!(result.values()[0], Scalar::Float64(0.0));
        assert_eq!(result.values()[1], Scalar::Float64(0.0));
        assert_eq!(result.values()[2], Scalar::Float64(5.0));
    }

    #[test]
    fn expanding_min_max_empty_window_is_nan() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into()],
            vec![Scalar::Null(NullKind::NaN), Scalar::Float64(3.0)],
        )
        .unwrap();
        let min_result = s.expanding(Some(0)).min().unwrap();
        let max_result = s.expanding(Some(0)).max().unwrap();
        // First position: empty window → NaN, not Infinity.
        assert!(min_result.values()[0].is_missing());
        assert!(max_result.values()[0].is_missing());
        assert_eq!(min_result.values()[1], Scalar::Float64(3.0));
        assert_eq!(max_result.values()[1], Scalar::Float64(3.0));
    }

    #[test]
    fn expanding_min_periods() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();

        let result = s.expanding(Some(2)).sum().unwrap();
        assert!(result.values()[0].is_missing()); // only 1 element, need 2
        assert_eq!(result.values()[1], Scalar::Float64(3.0)); // 1+2
        assert_eq!(result.values()[2], Scalar::Float64(6.0)); // 1+2+3
    }

    #[test]
    fn expanding_with_nulls() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();

        let result = s.expanding(None).sum().unwrap();
        assert_eq!(result.values()[0], Scalar::Float64(1.0));
        assert_eq!(result.values()[1], Scalar::Float64(1.0)); // null skipped
        assert_eq!(result.values()[2], Scalar::Float64(4.0)); // 1+3
    }

    // ── rank tests ──

    #[test]
    fn series_rank_average() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(3.0),
                Scalar::Float64(1.0),
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
            ],
        )
        .unwrap();
        let ranked = s.rank("average", true, "keep").unwrap();
        // 1.0 ties at positions 1,2 → average rank (1+2)/2 = 1.5
        assert_eq!(ranked.values()[0], Scalar::Float64(4.0)); // 3.0 → rank 4
        assert_eq!(ranked.values()[1], Scalar::Float64(1.5)); // 1.0 → avg rank
        assert_eq!(ranked.values()[2], Scalar::Float64(1.5)); // 1.0 → avg rank
        assert_eq!(ranked.values()[3], Scalar::Float64(3.0)); // 2.0 → rank 3
    }

    #[test]
    fn series_rank_min_max() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Float64(1.0),
                Scalar::Float64(1.0),
            ],
        )
        .unwrap();
        let min_ranked = s.rank("min", true, "keep").unwrap();
        assert_eq!(min_ranked.values()[0], Scalar::Float64(3.0)); // 2.0 → rank 3
        assert_eq!(min_ranked.values()[1], Scalar::Float64(1.0)); // 1.0 → min rank 1
        assert_eq!(min_ranked.values()[2], Scalar::Float64(1.0)); // 1.0 → min rank 1

        let max_ranked = s.rank("max", true, "keep").unwrap();
        assert_eq!(max_ranked.values()[0], Scalar::Float64(3.0)); // 2.0 → rank 3
        assert_eq!(max_ranked.values()[1], Scalar::Float64(2.0)); // 1.0 → max rank 2
        assert_eq!(max_ranked.values()[2], Scalar::Float64(2.0)); // 1.0 → max rank 2
    }

