    #[test]
    fn series_rank_na_top() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(1.0),
            ],
        )
        .unwrap();
        let ranked = s.rank("average", true, "top").unwrap();
        // NaN gets rank 1 (top), others shift up
        assert_eq!(ranked.values()[0], Scalar::Float64(3.0)); // 2.0 → rank 3
        assert_eq!(ranked.values()[1], Scalar::Float64(1.0)); // NaN → rank 1 (top)
        assert_eq!(ranked.values()[2], Scalar::Float64(2.0)); // 1.0 → rank 2
    }

    #[test]
    fn series_rank_na_bottom() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(1.0),
            ],
        )
        .unwrap();
        let ranked = s.rank("average", true, "bottom").unwrap();
        assert_eq!(ranked.values()[0], Scalar::Float64(2.0)); // 2.0 → rank 2
        assert_eq!(ranked.values()[1], Scalar::Float64(3.0)); // NaN → rank 3 (bottom)
        assert_eq!(ranked.values()[2], Scalar::Float64(1.0)); // 1.0 → rank 1
    }

    #[test]
    fn dataframe_rank_basic() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "a",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(3.0),
                    Scalar::Float64(1.0),
                    Scalar::Float64(2.0),
                ],
            )
            .unwrap(),
            Series::from_values(
                "b",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(30.0),
                    Scalar::Float64(20.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let ranked = df.rank("average", true, "keep").unwrap();
        // Column "a": 3.0→3, 1.0→1, 2.0→2
        assert_eq!(ranked.columns["a"].values()[0], Scalar::Float64(3.0));
        assert_eq!(ranked.columns["a"].values()[1], Scalar::Float64(1.0));
        assert_eq!(ranked.columns["a"].values()[2], Scalar::Float64(2.0));
        // Column "b": 10.0→1, 30.0→3, 20.0→2
        assert_eq!(ranked.columns["b"].values()[0], Scalar::Float64(1.0));
        assert_eq!(ranked.columns["b"].values()[1], Scalar::Float64(3.0));
        assert_eq!(ranked.columns["b"].values()[2], Scalar::Float64(2.0));
    }

    #[test]
    fn dataframe_rank_axis1_basic() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "a",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(3.0),
                    Scalar::Float64(1.0),
                    Scalar::Float64(5.0),
                ],
            )
            .unwrap(),
            Series::from_values(
                "b",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(1.0),
                    Scalar::Float64(2.0),
                ],
            )
            .unwrap(),
            Series::from_values(
                "c",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Null(NullKind::NaN),
                    Scalar::Float64(2.0),
                    Scalar::Float64(4.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let ranked = df.rank_axis1("average", true, "keep").unwrap();

        assert_eq!(ranked.columns["a"].values()[0], Scalar::Float64(2.0));
        assert_eq!(ranked.columns["b"].values()[0], Scalar::Float64(1.0));
        assert!(ranked.columns["c"].values()[0].is_missing());

        assert_eq!(ranked.columns["a"].values()[1], Scalar::Float64(1.5));
        assert_eq!(ranked.columns["b"].values()[1], Scalar::Float64(1.5));
        assert_eq!(ranked.columns["c"].values()[1], Scalar::Float64(3.0));

        assert_eq!(ranked.columns["a"].values()[2], Scalar::Float64(3.0));
        assert_eq!(ranked.columns["b"].values()[2], Scalar::Float64(1.0));
        assert_eq!(ranked.columns["c"].values()[2], Scalar::Float64(2.0));
    }

