    #[test]
    fn dataframe_melt_promotes_mixed_numeric_value_vars() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "id",
                vec![0_i64.into(), 1_i64.into()],
                vec![Scalar::Utf8("row1".into()), Scalar::Utf8("row2".into())],
            )
            .unwrap(),
            Series::from_values(
                "ints",
                vec![0_i64.into(), 1_i64.into()],
                vec![Scalar::Int64(1), Scalar::Int64(2)],
            )
            .unwrap(),
            Series::from_values(
                "floats",
                vec![0_i64.into(), 1_i64.into()],
                vec![Scalar::Float64(2.5), Scalar::Float64(3.5)],
            )
            .unwrap(),
        ])
        .unwrap();

        let melted = df.melt(&["id"], &["ints", "floats"], None, None).unwrap();
        let values = melted.columns["value"].values();

        assert_eq!(melted.columns["value"].dtype(), DType::Float64);
        assert_eq!(values[0], Scalar::Float64(1.0));
        assert_eq!(values[1], Scalar::Float64(2.0));
        assert_eq!(values[2], Scalar::Float64(2.5));
        assert_eq!(values[3], Scalar::Float64(3.5));
    }

    // ── pivot_table tests ──

    #[test]
    fn dataframe_pivot_table_sum() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "row",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Utf8("r1".into()),
                    Scalar::Utf8("r1".into()),
                    Scalar::Utf8("r2".into()),
                    Scalar::Utf8("r2".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "col",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c2".into()),
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c2".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "val",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(2.0),
                    Scalar::Float64(3.0),
                    Scalar::Float64(4.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let pivoted = df.pivot_table("val", "row", "col", "sum").unwrap();
        assert_eq!(pivoted.index.len(), 2); // r1, r2
        assert_eq!(pivoted.column_order.len(), 2); // c1, c2

        // r1, c1 → 1.0; r1, c2 → 2.0; r2, c1 → 3.0; r2, c2 → 4.0
        assert_eq!(pivoted.columns["c1"].values()[0], Scalar::Float64(1.0));
        assert_eq!(pivoted.columns["c2"].values()[0], Scalar::Float64(2.0));
        assert_eq!(pivoted.columns["c1"].values()[1], Scalar::Float64(3.0));
        assert_eq!(pivoted.columns["c2"].values()[1], Scalar::Float64(4.0));
    }

