    #[test]
    fn dataframe_pivot_table_std_uses_sample_std() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "row",
                vec![
                    0_i64.into(),
                    1_i64.into(),
                    2_i64.into(),
                    3_i64.into(),
                    4_i64.into(),
                    5_i64.into(),
                ],
                vec![
                    Scalar::Utf8("r1".into()),
                    Scalar::Utf8("r1".into()),
                    Scalar::Utf8("r2".into()),
                    Scalar::Utf8("r2".into()),
                    Scalar::Utf8("r2".into()),
                    Scalar::Utf8("r2".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "col",
                vec![
                    0_i64.into(),
                    1_i64.into(),
                    2_i64.into(),
                    3_i64.into(),
                    4_i64.into(),
                    5_i64.into(),
                ],
                vec![
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c2".into()),
                    Scalar::Utf8("c2".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "val",
                vec![
                    0_i64.into(),
                    1_i64.into(),
                    2_i64.into(),
                    3_i64.into(),
                    4_i64.into(),
                    5_i64.into(),
                ],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(20.0),
                    Scalar::Float64(4.0),
                    Scalar::Float64(8.0),
                    Scalar::Float64(1.0),
                    Scalar::Float64(3.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let pivoted = df.pivot_table("val", "row", "col", "std").unwrap();
        let r1_c1 = pivoted.columns["c1"].values()[0].to_f64().unwrap();
        let r2_c1 = pivoted.columns["c1"].values()[1].to_f64().unwrap();
        let r2_c2 = pivoted.columns["c2"].values()[1].to_f64().unwrap();
        assert!((r1_c1 - 50.0_f64.sqrt()).abs() < 1e-10);
        assert!((r2_c1 - 8.0_f64.sqrt()).abs() < 1e-10);
        assert!((r2_c2 - 2.0_f64.sqrt()).abs() < 1e-10);
        assert!(pivoted.columns["c2"].values()[0].is_missing());
    }

    #[test]
    fn dataframe_pivot_table_missing_cell() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "row",
                vec![0_i64.into(), 1_i64.into()],
                vec![Scalar::Utf8("r1".into()), Scalar::Utf8("r2".into())],
            )
            .unwrap(),
            Series::from_values(
                "col",
                vec![0_i64.into(), 1_i64.into()],
                vec![Scalar::Utf8("c1".into()), Scalar::Utf8("c2".into())],
            )
            .unwrap(),
            Series::from_values(
                "val",
                vec![0_i64.into(), 1_i64.into()],
                vec![Scalar::Float64(5.0), Scalar::Float64(10.0)],
            )
            .unwrap(),
        ])
        .unwrap();

        let pivoted = df.pivot_table("val", "row", "col", "sum").unwrap();
        // r1 has c1 but not c2; r2 has c2 but not c1
        assert_eq!(pivoted.columns["c1"].values()[0], Scalar::Float64(5.0));
        assert!(pivoted.columns["c2"].values()[0].is_missing()); // missing cell → NaN
        assert!(pivoted.columns["c1"].values()[1].is_missing()); // missing cell → NaN
        assert_eq!(pivoted.columns["c2"].values()[1], Scalar::Float64(10.0));
    }

