    #[test]
    fn dataframe_pivot_table_aggfunc_dict_per_column_agg() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "region",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Utf8("E".into()),
                    Scalar::Utf8("E".into()),
                    Scalar::Utf8("W".into()),
                    Scalar::Utf8("W".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "quarter",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Utf8("Q1".into()),
                    Scalar::Utf8("Q2".into()),
                    Scalar::Utf8("Q1".into()),
                    Scalar::Utf8("Q2".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "amount",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(20.0),
                    Scalar::Float64(30.0),
                    Scalar::Float64(40.0),
                ],
            )
            .unwrap(),
            Series::from_values(
                "qty",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(3.0),
                    Scalar::Float64(2.0),
                    Scalar::Float64(4.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let pivoted = df
            .pivot_table_aggfunc_dict(&[("amount", "sum"), ("qty", "mean")], "region", "quarter")
            .unwrap();

        // Columns: amount_Q1, amount_Q2, qty_Q1, qty_Q2 (in call order).
        assert_eq!(
            pivoted.column_order,
            vec![
                "amount_Q1".to_string(),
                "amount_Q2".to_string(),
                "qty_Q1".to_string(),
                "qty_Q2".to_string(),
            ]
        );
        // amount is summed
        assert_eq!(
            pivoted.columns["amount_Q1"].values()[0],
            Scalar::Float64(10.0)
        );
        assert_eq!(
            pivoted.columns["amount_Q2"].values()[0],
            Scalar::Float64(20.0)
        );
        assert_eq!(
            pivoted.columns["amount_Q1"].values()[1],
            Scalar::Float64(30.0)
        );
        assert_eq!(
            pivoted.columns["amount_Q2"].values()[1],
            Scalar::Float64(40.0)
        );
        // qty is averaged
        assert_eq!(pivoted.columns["qty_Q1"].values()[0], Scalar::Float64(1.0));
        assert_eq!(pivoted.columns["qty_Q2"].values()[0], Scalar::Float64(3.0));
        assert_eq!(pivoted.columns["qty_Q1"].values()[1], Scalar::Float64(2.0));
        assert_eq!(pivoted.columns["qty_Q2"].values()[1], Scalar::Float64(4.0));
    }

