    #[test]
    fn dataframe_pivot_table_with_margins_std_uses_raw_source_values() {
        fn sample_std(values: &[f64]) -> f64 {
            if values.len() < 2 {
                return f64::NAN;
            }
            let mean = values.iter().sum::<f64>() / values.len() as f64;
            let sum_sq = values
                .iter()
                .map(|value| (value - mean).powi(2))
                .sum::<f64>();
            (sum_sq / (values.len() as f64 - 1.0)).sqrt()
        }

        let df = DataFrame::from_series(vec![
            Series::from_values(
                "row",
                vec![
                    0_i64.into(),
                    1_i64.into(),
                    2_i64.into(),
                    3_i64.into(),
                    4_i64.into(),
                    5_i64.into(),
                ],
                vec![
                    Scalar::Utf8("r1".into()),
                    Scalar::Utf8("r1".into()),
                    Scalar::Utf8("r2".into()),
                    Scalar::Utf8("r2".into()),
                    Scalar::Utf8("r2".into()),
                    Scalar::Utf8("r2".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "col",
                vec![
                    0_i64.into(),
                    1_i64.into(),
                    2_i64.into(),
                    3_i64.into(),
                    4_i64.into(),
                    5_i64.into(),
                ],
                vec![
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c2".into()),
                    Scalar::Utf8("c2".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "val",
                vec![
                    0_i64.into(),
                    1_i64.into(),
                    2_i64.into(),
                    3_i64.into(),
                    4_i64.into(),
                    5_i64.into(),
                ],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(20.0),
                    Scalar::Float64(4.0),
                    Scalar::Float64(8.0),
                    Scalar::Float64(1.0),
                    Scalar::Float64(3.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let pt = df
            .pivot_table_with_margins("val", "row", "col", "std", true)
            .unwrap();

        let r1_all = pt.columns["All"].values()[0].to_f64().unwrap();
        let r2_all = pt.columns["All"].values()[1].to_f64().unwrap();
        let all_c1 = pt.columns["c1"].values()[2].to_f64().unwrap();
        let all_c2 = pt.columns["c2"].values()[2].to_f64().unwrap();
        let all_all = pt.columns["All"].values()[2].to_f64().unwrap();

        assert!((r1_all - sample_std(&[10.0, 20.0])).abs() < 1e-10);
        assert!((r2_all - sample_std(&[4.0, 8.0, 1.0, 3.0])).abs() < 1e-10);
        assert!((all_c1 - sample_std(&[10.0, 20.0, 4.0, 8.0])).abs() < 1e-10);
        assert!((all_c2 - sample_std(&[1.0, 3.0])).abs() < 1e-10);
        assert!((all_all - sample_std(&[10.0, 20.0, 4.0, 8.0, 1.0, 3.0])).abs() < 1e-10);
    }

    #[test]
    fn dataframe_pivot_table_with_margins_median_uses_raw_source_values() {
        fn sample_median(values: &[f64]) -> f64 {
            let mut sorted = values.to_vec();
            sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());
            let len = sorted.len();
            if len % 2 == 1 {
                sorted[len / 2]
            } else {
                (sorted[len / 2 - 1] + sorted[len / 2]) / 2.0
            }
        }

        let df = DataFrame::from_series(vec![
            Series::from_values(
                "row",
                vec![
                    0_i64.into(),
                    1_i64.into(),
                    2_i64.into(),
                    3_i64.into(),
                    4_i64.into(),
                    5_i64.into(),
                ],
                vec![
                    Scalar::Utf8("r1".into()),
                    Scalar::Utf8("r1".into()),
                    Scalar::Utf8("r1".into()),
                    Scalar::Utf8("r2".into()),
                    Scalar::Utf8("r2".into()),
                    Scalar::Utf8("r2".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "col",
                vec![
                    0_i64.into(),
                    1_i64.into(),
                    2_i64.into(),
                    3_i64.into(),
                    4_i64.into(),
                    5_i64.into(),
                ],
                vec![
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c2".into()),
                    Scalar::Utf8("c1".into()),
                    Scalar::Utf8("c2".into()),
                    Scalar::Utf8("c2".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "val",
                vec![
                    0_i64.into(),
                    1_i64.into(),
                    2_i64.into(),
                    3_i64.into(),
                    4_i64.into(),
                    5_i64.into(),
                ],
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(100.0),
                    Scalar::Float64(2.0),
                    Scalar::Float64(8.0),
                    Scalar::Float64(9.0),
                    Scalar::Float64(10.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let pt = df
            .pivot_table_with_margins("val", "row", "col", "median", true)
            .unwrap();

        let r1_all = pt.columns["All"].values()[0].to_f64().unwrap();
        let r2_all = pt.columns["All"].values()[1].to_f64().unwrap();
        let all_c1 = pt.columns["c1"].values()[2].to_f64().unwrap();
        let all_c2 = pt.columns["c2"].values()[2].to_f64().unwrap();
        let all_all = pt.columns["All"].values()[2].to_f64().unwrap();

        assert!((r1_all - sample_median(&[1.0, 100.0, 2.0])).abs() < 1e-10);
        assert!((r2_all - sample_median(&[8.0, 9.0, 10.0])).abs() < 1e-10);
        assert!((all_c1 - sample_median(&[1.0, 100.0, 8.0])).abs() < 1e-10);
        assert!((all_c2 - sample_median(&[2.0, 9.0, 10.0])).abs() < 1e-10);
        assert!((all_all - sample_median(&[1.0, 100.0, 2.0, 8.0, 9.0, 10.0])).abs() < 1e-10);
    }

    // ── agg tests ──

    #[test]
    fn dataframe_agg_basic() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "a",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(2.0),
                    Scalar::Float64(3.0),
                ],
            )
            .unwrap(),
            Series::from_values(
                "b",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(20.0),
                    Scalar::Float64(30.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let mut funcs = std::collections::HashMap::new();
        funcs.insert("a".to_string(), vec!["sum".to_string(), "mean".to_string()]);
        funcs.insert("b".to_string(), vec!["sum".to_string(), "mean".to_string()]);

        let result = df.agg(&funcs).unwrap();
        assert_eq!(result.index.len(), 2); // sum, mean
        // a: sum=6, mean=2
        assert_eq!(result.columns["a"].values()[0], Scalar::Float64(6.0));
        assert_eq!(result.columns["a"].values()[1], Scalar::Float64(2.0));
        // b: sum=60, mean=20
        assert_eq!(result.columns["b"].values()[0], Scalar::Float64(60.0));
        assert_eq!(result.columns["b"].values()[1], Scalar::Float64(20.0));
    }

    #[test]
    fn dataframe_aggregate_alias_matches_agg() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "a",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(2.0),
                    Scalar::Float64(4.0),
                    Scalar::Float64(6.0),
                ],
            )
            .unwrap(),
            Series::from_values(
                "b",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(3.0),
                    Scalar::Float64(5.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let mut funcs = std::collections::HashMap::new();
        funcs.insert("a".to_string(), vec!["sum".to_string(), "mean".to_string()]);
        funcs.insert("b".to_string(), vec!["max".to_string()]);

        let agg = df.agg(&funcs).unwrap();
        let aggregate = df.aggregate(&funcs).unwrap();

        assert_eq!(aggregate, agg);

        let labels = aggregate.index.labels();
        let sum_pos = labels
            .iter()
            .position(|label| label == &IndexLabel::Utf8("sum".to_owned()))
            .expect("sum row");
        let mean_pos = labels
            .iter()
            .position(|label| label == &IndexLabel::Utf8("mean".to_owned()))
            .expect("mean row");
        let max_pos = labels
            .iter()
            .position(|label| label == &IndexLabel::Utf8("max".to_owned()))
            .expect("max row");

        assert_eq!(
            aggregate.columns["a"].values()[sum_pos],
            Scalar::Float64(12.0)
        );
        assert_eq!(
            aggregate.columns["a"].values()[mean_pos],
            Scalar::Float64(4.0)
        );
        assert_eq!(
            aggregate.columns["b"].values()[max_pos],
            Scalar::Float64(5.0)
        );
    }

