    #[test]
    fn dataframe_groupby_any_all() {
        let labels = vec![
            IndexLabel::Utf8("r0".into()),
            IndexLabel::Utf8("r1".into()),
            IndexLabel::Utf8("r2".into()),
            IndexLabel::Utf8("r3".into()),
            IndexLabel::Utf8("r4".into()),
            IndexLabel::Utf8("r5".into()),
        ];
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "grp",
                labels.clone(),
                vec![
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("b".into()),
                    Scalar::Utf8("b".into()),
                    Scalar::Utf8("c".into()),
                    Scalar::Utf8("c".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "flag",
                labels.clone(),
                vec![
                    Scalar::Bool(true),
                    Scalar::Bool(false),
                    Scalar::Bool(false),
                    Scalar::Bool(false),
                    Scalar::Null(NullKind::Null),
                    Scalar::Null(NullKind::Null),
                ],
            )
            .unwrap(),
            Series::from_values(
                "count",
                labels.clone(),
                vec![
                    Scalar::Int64(0),
                    Scalar::Int64(2),
                    Scalar::Int64(0),
                    Scalar::Int64(0),
                    Scalar::Null(NullKind::Null),
                    Scalar::Int64(3),
                ],
            )
            .unwrap(),
            Series::from_values(
                "all_na",
                labels,
                vec![
                    Scalar::Null(NullKind::NaN),
                    Scalar::Null(NullKind::NaN),
                    Scalar::Null(NullKind::NaN),
                    Scalar::Null(NullKind::NaN),
                    Scalar::Null(NullKind::NaN),
                    Scalar::Null(NullKind::NaN),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let any_result = df.groupby(&["grp"]).unwrap().any().unwrap();
        assert_eq!(
            any_result.index().labels(),
            &[
                IndexLabel::Utf8("a".into()),
                IndexLabel::Utf8("b".into()),
                IndexLabel::Utf8("c".into())
            ]
        );
        assert_eq!(
            any_result.columns["flag"].values(),
            &[Scalar::Bool(true), Scalar::Bool(false), Scalar::Bool(false)]
        );
        assert_eq!(
            any_result.columns["count"].values(),
            &[Scalar::Bool(true), Scalar::Bool(false), Scalar::Bool(true)]
        );
        assert_eq!(
            any_result.columns["all_na"].values(),
            &[
                Scalar::Bool(false),
                Scalar::Bool(false),
                Scalar::Bool(false)
            ]
        );

        let all_result = df.groupby(&["grp"]).unwrap().all().unwrap();
        assert_eq!(
            all_result.columns["flag"].values(),
            &[Scalar::Bool(false), Scalar::Bool(false), Scalar::Bool(true)]
        );
        assert_eq!(
            all_result.columns["count"].values(),
            &[Scalar::Bool(false), Scalar::Bool(false), Scalar::Bool(true)]
        );
        assert_eq!(
            all_result.columns["all_na"].values(),
            &[Scalar::Bool(true), Scalar::Bool(true), Scalar::Bool(true)]
        );
    }

    #[test]
    fn dataframe_groupby_agg_per_column() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "grp",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("b".into()),
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("b".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "x",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(20.0),
                    Scalar::Float64(30.0),
                    Scalar::Float64(40.0),
                ],
            )
            .unwrap(),
            Series::from_values(
                "y",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(2.0),
                    Scalar::Float64(3.0),
                    Scalar::Float64(4.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let mut func_map = std::collections::HashMap::new();
        func_map.insert("x".to_string(), "sum".to_string());
        func_map.insert("y".to_string(), "mean".to_string());

        let result = df.groupby(&["grp"]).unwrap().agg(&func_map).unwrap();
        assert_eq!(result.len(), 2);
        // Group "a": x sum = 10+30=40; y mean = (1+3)/2=2.0
        assert_eq!(result.columns["x"].values()[0], Scalar::Float64(40.0));
        assert_eq!(result.columns["y"].values()[0], Scalar::Float64(2.0));
        // Group "b": x sum = 20+40=60; y mean = (2+4)/2=3.0
        assert_eq!(result.columns["x"].values()[1], Scalar::Float64(60.0));
        assert_eq!(result.columns["y"].values()[1], Scalar::Float64(3.0));
    }

    #[test]
    fn dataframe_groupby_agg_list() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "grp",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("b".into()),
                    Scalar::Utf8("b".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "val",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(20.0),
                    Scalar::Float64(30.0),
                    Scalar::Float64(40.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let result = df
            .groupby(&["grp"])
            .unwrap()
            .agg_list(&["sum", "mean"])
            .unwrap();
        assert_eq!(result.len(), 2);
        // Column names: val_sum, val_mean
        assert_eq!(result.column_order, vec!["val_sum", "val_mean"]);
        // Group "a": sum=30, mean=15; Group "b": sum=70, mean=35
        assert_eq!(result.columns["val_sum"].values()[0], Scalar::Float64(30.0));
        assert_eq!(
            result.columns["val_mean"].values()[0],
            Scalar::Float64(15.0)
        );
        assert_eq!(result.columns["val_sum"].values()[1], Scalar::Float64(70.0));
        assert_eq!(
            result.columns["val_mean"].values()[1],
            Scalar::Float64(35.0)
        );
    }

    #[test]
    fn dataframe_groupby_agg_dict_list_per_column_funcs() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "grp",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("b".into()),
                    Scalar::Utf8("b".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "x",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(3.0),
                    Scalar::Float64(5.0),
                    Scalar::Float64(7.0),
                ],
            )
            .unwrap(),
            Series::from_values(
                "y",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(30.0),
                    Scalar::Float64(50.0),
                    Scalar::Float64(70.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let mut func_map: std::collections::HashMap<String, Vec<String>> =
            std::collections::HashMap::new();
        func_map.insert("x".to_string(), vec!["sum".to_string(), "mean".to_string()]);
        func_map.insert("y".to_string(), vec!["min".to_string(), "max".to_string()]);

        let result = df
            .groupby(&["grp"])
            .unwrap()
            .agg_dict_list(&func_map)
            .unwrap();

        // Order follows self.df.column_order (grp, x, y). grp is skipped
        // (not in func_map), so we get x_sum, x_mean, y_min, y_max.
        assert_eq!(
            result.column_order,
            vec![
                "x_sum".to_string(),
                "x_mean".to_string(),
                "y_min".to_string(),
                "y_max".to_string(),
            ]
        );
        assert_eq!(result.len(), 2);
        // Group "a" (x=1,3; y=10,30)
        assert_eq!(result.columns["x_sum"].values()[0], Scalar::Float64(4.0));
        assert_eq!(result.columns["x_mean"].values()[0], Scalar::Float64(2.0));
        assert_eq!(result.columns["y_min"].values()[0], Scalar::Float64(10.0));
        assert_eq!(result.columns["y_max"].values()[0], Scalar::Float64(30.0));
        // Group "b" (x=5,7; y=50,70)
        assert_eq!(result.columns["x_sum"].values()[1], Scalar::Float64(12.0));
        assert_eq!(result.columns["x_mean"].values()[1], Scalar::Float64(6.0));
        assert_eq!(result.columns["y_min"].values()[1], Scalar::Float64(50.0));
        assert_eq!(result.columns["y_max"].values()[1], Scalar::Float64(70.0));
    }

