    #[test]
    fn series_corr_spearman() {
        // Perfectly monotonic: [1,2,3,4] vs [10,20,30,40] → Spearman = 1.0
        let a = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
                Scalar::Float64(30.0),
                Scalar::Float64(40.0),
            ],
        )
        .unwrap();

        let r = a.corr_spearman(&b).unwrap();
        assert!((r - 1.0).abs() < 1e-10);
    }

    #[test]
    fn series_corr_spearman_inverse() {
        // Perfectly inversely monotonic: [1,2,3] vs [30,20,10] → Spearman = -1.0
        let a = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(30.0),
                Scalar::Float64(20.0),
                Scalar::Float64(10.0),
            ],
        )
        .unwrap();

        let r = a.corr_spearman(&b).unwrap();
        assert!((r - (-1.0)).abs() < 1e-10);
    }

    #[test]
    fn series_rank_correlations_align_by_index_before_pairing() {
        let a = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec![2_i64.into(), 1_i64.into(), 0_i64.into()],
            vec![
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
                Scalar::Float64(30.0),
            ],
        )
        .unwrap();

        assert!((a.corr_spearman(&b).unwrap() + 1.0).abs() < 1e-10);
        assert!((a.corr_kendall(&b).unwrap() + 1.0).abs() < 1e-10);
    }

    #[test]
    fn series_corr_kendall() {
        // Perfect concordance: [1,2,3] vs [4,5,6] → Kendall tau = 1.0
        let a = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(4.0),
                Scalar::Float64(5.0),
                Scalar::Float64(6.0),
            ],
        )
        .unwrap();

        let tau = a.corr_kendall(&b).unwrap();
        assert!((tau - 1.0).abs() < 1e-10);
    }

    #[test]
    fn dataframe_corr_spearman() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "x",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(2.0),
                    Scalar::Float64(3.0),
                ],
            )
            .unwrap(),
            Series::from_values(
                "y",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(20.0),
                    Scalar::Float64(30.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let result = df.corr_method("spearman").unwrap();
        // Self-correlation = 1.0
        assert_eq!(result.columns["x"].values()[0], Scalar::Float64(1.0));
        assert_eq!(result.columns["y"].values()[1], Scalar::Float64(1.0));
        // Cross-correlation should be 1.0 for perfectly monotonic data
        let xy = expect_float64(&result.columns["y"].values()[0]);
        assert!((xy - 1.0).abs() < 1e-10);
    }

    #[test]
    fn dataframe_groupby_apply() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "grp",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("b".into()),
                    Scalar::Utf8("b".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "val",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(20.0),
                    Scalar::Float64(30.0),
                    Scalar::Float64(40.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        // Apply a function that returns the sum of each group as a single-row DataFrame
        let result = df
            .groupby(&["grp"])
            .unwrap()
            .apply(|group_df| {
                // Sum the 'val' column
                let col = &group_df.columns["val"];
                let total: f64 = col.values().iter().filter_map(|v| v.to_f64().ok()).sum();
                let mut cols = BTreeMap::new();
                cols.insert(
                    "val".to_string(),
                    super::Column::from_values(vec![Scalar::Float64(total)]).unwrap(),
                );
                Ok(DataFrame::new_with_column_order(
                    super::Index::new(vec![0_i64.into()]),
                    cols,
                    vec!["val".to_string()],
                )
                .unwrap())
            })
            .unwrap();

        assert_eq!(result.len(), 2);
        assert_eq!(result.columns["val"].values()[0], Scalar::Float64(30.0)); // 10+20
        assert_eq!(result.columns["val"].values()[1], Scalar::Float64(70.0)); // 30+40
    }

    #[test]
    fn dataframe_groupby_apply_expands_multirow_frames_with_group_index() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "grp",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("a".into()),
                    Scalar::Utf8("b".into()),
                    Scalar::Utf8("b".into()),
                ],
            )
            .unwrap(),
            Series::from_values(
                "val",
                vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
                vec![
                    Scalar::Float64(10.0),
                    Scalar::Float64(20.0),
                    Scalar::Float64(30.0),
                    Scalar::Float64(40.0),
                ],
            )
            .unwrap(),
        ])
        .unwrap();

        let result = df
            .groupby(&["grp"])
            .unwrap()
            .apply(|group_df| group_df.select_columns(&["val"]))
            .unwrap();

        assert_eq!(result.len(), 4);
        assert_eq!(
            result.columns["val"].values(),
            &[
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
                Scalar::Float64(30.0),
                Scalar::Float64(40.0),
            ]
        );
        let row_multiindex = result.row_multiindex.as_ref().unwrap();
        assert_eq!(row_multiindex.nlevels(), 2);
        assert_eq!(
            row_multiindex.names(),
            &[Some("grp".to_owned()), Some("index".to_owned())]
        );
        let first_tuple = row_multiindex.get_tuple(0).unwrap();
        assert_eq!(first_tuple[0], &IndexLabel::Utf8("a".to_owned()));
        assert_eq!(first_tuple[1], &IndexLabel::Int64(0));
        let last_tuple = row_multiindex.get_tuple(3).unwrap();
        assert_eq!(last_tuple[0], &IndexLabel::Utf8("b".to_owned()));
        assert_eq!(last_tuple[1], &IndexLabel::Int64(3));
    }

    #[test]
    fn dataframe_groupby_apply_include_groups_controls_group_frame_columns() {
        let df = DataFrame::from_series(vec![
            Series::from_values(
                "grp",
                vec![0_i64.into(), 1_i64.into()],
                vec![Scalar::Utf8("a".into()), Scalar::Utf8("b".into())],
            )
            .unwrap(),
            Series::from_values(
                "val",
                vec![0_i64.into(), 1_i64.into()],
                vec![Scalar::Float64(10.0), Scalar::Float64(20.0)],
            )
            .unwrap(),
        ])
        .unwrap();

        let without_groups = df
            .groupby(&["grp"])
            .unwrap()
            .apply(|group_df| {
                let mut cols = BTreeMap::new();
                cols.insert(
                    "has_grp".to_owned(),
                    Column::from_values(vec![Scalar::Bool(group_df.columns.contains_key("grp"))])
                        .unwrap(),
                );
                DataFrame::new_with_column_order(
                    Index::new(vec![0_i64.into()]),
                    cols,
                    vec!["has_grp".to_owned()],
                )
            })
            .unwrap();
        assert_eq!(
            without_groups.columns["has_grp"].values(),
            &[Scalar::Bool(false), Scalar::Bool(false)]
        );

        let with_groups = df
            .groupby(&["grp"])
            .unwrap()
            .apply_with_include_groups(true, |group_df| {
                let mut cols = BTreeMap::new();
                cols.insert(
                    "has_grp".to_owned(),
                    Column::from_values(vec![Scalar::Bool(group_df.columns.contains_key("grp"))])
                        .unwrap(),
                );
                DataFrame::new_with_column_order(
                    Index::new(vec![0_i64.into()]),
                    cols,
                    vec!["has_grp".to_owned()],
                )
            })
            .unwrap();
        assert_eq!(
            with_groups.columns["has_grp"].values(),
            &[Scalar::Bool(true), Scalar::Bool(true)]
        );
    }

