    #[test]
    fn dataframe_filter_axis_zero_like_and_regex_use_index_label_strings() {
        let df = DataFrame::from_dict_with_index(
            vec![(
                "v",
                vec![Scalar::Int64(100), Scalar::Int64(210), Scalar::Int64(305)],
            )],
            vec![
                IndexLabel::Int64(10),
                IndexLabel::Int64(21),
                IndexLabel::Int64(305),
            ],
        )
        .unwrap();

        let like = df.filter_axis(None, Some("1"), None, 0).unwrap();
        assert_eq!(
            like.index().labels(),
            &[IndexLabel::Int64(10), IndexLabel::Int64(21)]
        );

        let regex = df.filter_axis(None, None, Some(r"^3"), 0).unwrap();
        assert_eq!(regex.index().labels(), &[IndexLabel::Int64(305)]);
        assert_eq!(regex.column("v").unwrap().values(), &[Scalar::Int64(305)]);
    }

    #[test]
    fn dataframe_filter_labels_rejects_invalid_selector_contract_n33na() {
        let df = DataFrame::from_dict_with_index(
            vec![(
                "v",
                vec![Scalar::Int64(10), Scalar::Int64(20), Scalar::Int64(30)],
            )],
            vec![
                IndexLabel::Utf8("foo".to_owned()),
                IndexLabel::Utf8("bar".to_owned()),
                IndexLabel::Utf8("baz".to_owned()),
            ],
        )
        .unwrap();

        let zero = df
            .filter_labels(None, None, None, 1)
            .expect_err("zero selectors must reject");
        assert!(matches!(zero, FrameError::CompatibilityRejected(msg)
            if msg.contains("exactly one")));

        let multiple = df
            .filter_labels(Some(&["v"]), Some("v"), None, 1)
            .expect_err("multiple selectors must reject");
        assert!(matches!(multiple, FrameError::CompatibilityRejected(msg)
            if msg.contains("exactly one")));

        let bad_column_regex = df
            .filter_labels(None, None, Some("["), 1)
            .expect_err("invalid column regex must reject");
        assert!(
            matches!(bad_column_regex, FrameError::CompatibilityRejected(msg)
            if msg.contains("invalid regex"))
        );

        let bad_row_regex = df
            .filter_labels(None, None, Some("["), 0)
            .expect_err("invalid row regex must reject");
        assert!(
            matches!(bad_row_regex, FrameError::CompatibilityRejected(msg)
            if msg.contains("invalid regex"))
        );

        let bad_axis = df
            .filter_labels(None, Some("ba"), None, 2)
            .expect_err("unsupported axis must reject");
        assert!(matches!(bad_axis, FrameError::CompatibilityRejected(msg)
            if msg.contains("axis must be 0 or 1")));
    }

    // --- Series.str additional methods tests ---

    #[test]
    fn str_get_character() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into()],
            vec![
                Scalar::Utf8("hello".to_owned()),
                Scalar::Utf8("ab".to_owned()),
            ],
        )
        .unwrap();

        let result = s.str().get(0).unwrap();
        assert_eq!(result.values()[0], Scalar::Utf8("h".to_owned()));
        assert_eq!(result.values()[1], Scalar::Utf8("a".to_owned()));

        let result2 = s.str().get(4).unwrap();
        assert_eq!(result2.values()[0], Scalar::Utf8("o".to_owned()));
        assert!(result2.values()[1].is_missing()); // out of bounds
    }

    #[test]
    fn str_wrap() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into()],
            vec![Scalar::Utf8(
                "hello world this is a long sentence".to_owned(),
            )],
        )
        .unwrap();

        let result = s.str().wrap(15).unwrap();
        let wrapped = expect_utf8(&result.values()[0]);
        assert!(wrapped.contains('\n'));
    }

    #[test]
    fn str_isdecimal() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Utf8("123".to_owned()),
                Scalar::Utf8("12.3".to_owned()),
                Scalar::Utf8("٣۳𝟠".to_owned()),
                Scalar::Utf8("²".to_owned()),
            ],
        )
        .unwrap();

        let result = s.str().isdecimal().unwrap();
        assert_eq!(result.values()[0], Scalar::Bool(true));
        assert_eq!(result.values()[1], Scalar::Bool(false));
        assert_eq!(result.values()[2], Scalar::Bool(true));
        assert_eq!(result.values()[3], Scalar::Bool(false));
    }

    #[test]
    fn str_istitle() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("Hello World".to_owned()),
                Scalar::Utf8("hello world".to_owned()),
                Scalar::Utf8("HELLO".to_owned()),
            ],
        )
        .unwrap();

        let result = s.str().istitle().unwrap();
        assert_eq!(result.values()[0], Scalar::Bool(true));
        assert_eq!(result.values()[1], Scalar::Bool(false));
        assert_eq!(result.values()[2], Scalar::Bool(false));
    }

    #[test]
    fn str_title_resets_after_punctuation_and_digits() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("rock'n'roll".to_owned()),
                Scalar::Utf8("a.b".to_owned()),
                Scalar::Utf8("9lives".to_owned()),
            ],
        )
        .unwrap();

        let result = s.str().title().unwrap();
        assert_eq!(result.values()[0], Scalar::Utf8("Rock'N'Roll".to_owned()));
        assert_eq!(result.values()[1], Scalar::Utf8("A.B".to_owned()));
        assert_eq!(result.values()[2], Scalar::Utf8("9Lives".to_owned()));
    }

    #[test]
    fn str_cat_concatenation() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("hello".to_owned()),
                Scalar::Utf8("world".to_owned()),
                Scalar::Utf8("foo".to_owned()),
            ],
        )
        .unwrap();

        let result = s.str().cat(", ").unwrap();
        assert_eq!(result, "hello, world, foo");
    }

    // --- nlargest/nsmallest keep parameter tests ---

    #[test]
    fn series_nlargest_keep_first() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Int64(3),
                Scalar::Int64(1),
                Scalar::Int64(3),
                Scalar::Int64(2),
            ],
        )
        .unwrap();

        let result = s.nlargest_keep(2, "first").unwrap();
        assert_eq!(result.len(), 2);
        assert_eq!(result.values()[0], Scalar::Int64(3));
        assert_eq!(result.values()[1], Scalar::Int64(3));
    }

    #[test]
    fn series_nsmallest_keep_all() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(1),
                Scalar::Int64(3),
            ],
        )
        .unwrap();

        // Asking for 2 smallest, but the 2nd smallest (1) appears twice
        // with keep='all', should return all tied values
        let result = s.nsmallest_keep(2, "all").unwrap();
        assert!(result.len() >= 2);
    }

    #[test]
    fn series_topk_keep_all_zero_returns_empty() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![Scalar::Int64(3), Scalar::Int64(1), Scalar::Int64(2)],
        )
        .unwrap();

        assert_eq!(s.nlargest_keep(0, "all").unwrap().len(), 0);
        assert_eq!(s.nsmallest_keep(0, "all").unwrap().len(), 0);
    }

    #[test]
    fn series_topk_rejects_invalid_keep_even_for_zero_n() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![Scalar::Int64(3), Scalar::Int64(1), Scalar::Int64(2)],
        )
        .unwrap();

        assert!(s.nlargest_keep(0, "bogus").is_err());
        assert!(s.nsmallest_keep(0, "bogus").is_err());
    }

    // --- DataFrame.apply_row tests ---

    #[test]
    fn dataframe_apply_row_sum() {
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                ("a", vec![Scalar::Int64(1), Scalar::Int64(2)]),
                ("b", vec![Scalar::Int64(10), Scalar::Int64(20)]),
            ],
        )
        .unwrap();

        let result = df
            .apply_row("sum", |row| {
                let mut total = 0_i64;
                for val in row {
                    if let Scalar::Int64(v) = val {
                        total += v;
                    }
                }
                Scalar::Int64(total)
            })
            .unwrap();

        assert_eq!(result.name(), "sum");
        assert_eq!(result.values()[0], Scalar::Int64(11));
        assert_eq!(result.values()[1], Scalar::Int64(22));
    }

    #[test]
    fn dataframe_apply_row_fn_failable() {
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                ("a", vec![Scalar::Float64(10.0)]),
                ("b", vec![Scalar::Float64(3.0)]),
            ],
        )
        .unwrap();

        let result = df
            .apply_row_fn("ratio", |row| {
                let a = row[0].to_f64().map_err(fp_columnar::ColumnError::from)?;
                let b = row[1].to_f64().map_err(fp_columnar::ColumnError::from)?;
                Ok(Scalar::Float64(a / b))
            })
            .unwrap();

        let v = expect_float64(&result.values()[0]);
        assert!((v - 10.0 / 3.0).abs() < 1e-10);
    }

    // --- DataFrame clip_lower/clip_upper/round tests ---

    #[test]
    fn dataframe_clip_lower() {
        let df = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(5.0),
                    Scalar::Float64(10.0),
                ],
            )],
        )
        .unwrap();

        let result = df.clip_lower(3.0).unwrap();
        assert_eq!(
            result.column("a").unwrap().values(),
            &[
                Scalar::Float64(3.0),
                Scalar::Float64(5.0),
                Scalar::Float64(10.0)
            ]
        );
    }

    #[test]
    fn dataframe_clip_upper() {
        let df = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(5.0),
                    Scalar::Float64(10.0),
                ],
            )],
        )
        .unwrap();

        let result = df.clip_upper(7.0).unwrap();
        assert_eq!(
            result.column("a").unwrap().values(),
            &[
                Scalar::Float64(1.0),
                Scalar::Float64(5.0),
                Scalar::Float64(7.0)
            ]
        );
    }

    #[test]
    fn dataframe_round() {
        let df = DataFrame::from_dict(
            &["a"],
            vec![("a", vec![Scalar::Float64(1.234), Scalar::Float64(5.678)])],
        )
        .unwrap();

        let result = df.round(1).unwrap();
        assert_eq!(
            result.column("a").unwrap().values()[0],
            Scalar::Float64(1.2)
        );
        assert_eq!(
            result.column("a").unwrap().values()[1],
            Scalar::Float64(5.7)
        );
    }

    // --- DataFrame to_csv/to_json tests ---

    #[test]
    fn dataframe_to_csv_basic() {
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                ("a", vec![Scalar::Int64(1), Scalar::Int64(2)]),
                (
                    "b",
                    vec![Scalar::Utf8("x".to_owned()), Scalar::Utf8("y".to_owned())],
                ),
            ],
        )
        .unwrap();

        let csv = df.to_csv(',', false);
        assert!(csv.starts_with("a,b\n"));
        assert!(csv.contains("1,x\n"));
        assert!(csv.contains("2,y\n"));
    }

    #[test]
    fn dataframe_to_csv_with_index() {
        let df = DataFrame::from_dict(&["a"], vec![("a", vec![Scalar::Int64(10)])]).unwrap();

        let csv = df.to_csv(',', true);
        // When index has no name, header is empty (pandas behavior)
        assert!(csv.starts_with(",a\n"));
        assert!(csv.contains("0,10\n"));
    }

    #[test]
    fn dataframe_to_csv_escapes_headers_and_index() {
        let df = DataFrame::from_dict_with_index(
            vec![("a,b", vec![Scalar::Utf8("x,y".to_owned())])],
            vec!["id,1".into()],
        )
        .unwrap();

        let csv = df.to_csv(',', true);
        // When index has no name, header is empty (pandas behavior)
        assert!(csv.starts_with(",\"a,b\"\n"));
        assert!(csv.contains("\"id,1\",\"x,y\"\n"));
    }

    #[test]
    fn dataframe_to_json_records() {
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                ("a", vec![Scalar::Int64(1)]),
                ("b", vec![Scalar::Utf8("hello".to_owned())]),
            ],
        )
        .unwrap();

        let json = df.to_json("records").unwrap();
        assert!(json.starts_with('['));
        assert!(json.ends_with(']'));
        assert!(json.contains("\"a\":1"));
        assert!(json.contains("\"b\":\"hello\""));
    }

    #[test]
    fn dataframe_to_json_records_emits_int_for_nullable_int_column() {
        // Per br-frankenpandas-vz57j: pandas Int64Dtype keeps integer JSON
        // literals when nulls are present (1, null), rather than promoting
        // every value to Float64 (1.0, null).
        let df = DataFrame::from_dict_with_index(
            vec![("a", vec![Scalar::Int64(1), Scalar::Null(NullKind::Null)])],
            vec!["row".into(), "row".into()],
        )
        .unwrap();

        let json = df.to_json("records").unwrap();
        let parsed: Value = serde_json::from_str(&json).unwrap();
        assert_eq!(parsed, serde_json::json!([{"a": 1}, {"a": null}]));
    }

    #[test]
    fn dataframe_to_json_columns() {
        let df = DataFrame::from_dict_with_index(
            vec![("x", vec![Scalar::Int64(10), Scalar::Int64(20)])],
            vec!["row0".into(), "row1".into()],
        )
        .unwrap();
        let json = df.to_json("columns").unwrap();
        let parsed: Value = serde_json::from_str(&json).unwrap();
        assert_eq!(
            parsed,
            serde_json::json!({
                "x": {
                    "row0": 10,
                    "row1": 20
                }
            })
        );
    }

    #[test]
    fn dataframe_to_json_index() {
        let df = DataFrame::from_dict_with_index(
            vec![
                ("x", vec![Scalar::Int64(10), Scalar::Int64(20)]),
                (
                    "y",
                    vec![Scalar::Utf8("a".to_owned()), Scalar::Utf8("b".to_owned())],
                ),
            ],
            vec!["row0".into(), "row1".into()],
        )
        .unwrap();

        let json = df.to_json("index").unwrap();
        let parsed: Value = serde_json::from_str(&json).unwrap();
        assert_eq!(
            parsed,
            serde_json::json!({
                "row0": {
                    "x": 10,
                    "y": "a"
                },
                "row1": {
                    "x": 20,
                    "y": "b"
                }
            })
        );
    }

    #[test]
    fn dataframe_to_json_duplicate_index_rejected() {
        let df = DataFrame::from_dict_with_index(
            vec![("x", vec![Scalar::Int64(1), Scalar::Int64(2)])],
            vec!["dup".into(), "dup".into()],
        )
        .unwrap();

        let err = df
            .to_json("index")
            .expect_err("duplicate index labels should error");
        assert!(
            matches!(err, FrameError::CompatibilityRejected(msg) if msg.contains("duplicate index"))
        );

        let err = df
            .to_json("columns")
            .expect_err("duplicate index labels should error");
        assert!(
            matches!(err, FrameError::CompatibilityRejected(msg) if msg.contains("duplicate index"))
        );
    }

    #[test]
    fn dataframe_to_json_split() {
        let df = DataFrame::from_dict_with_index(
            vec![
                ("x", vec![Scalar::Int64(10), Scalar::Null(NullKind::Null)]),
                (
                    "y",
                    vec![Scalar::Utf8("a".to_owned()), Scalar::Utf8("b".to_owned())],
                ),
            ],
            vec![10_i64.into(), 20_i64.into()],
        )
        .unwrap();

        let json = df.to_json("split").unwrap();
        let parsed: Value = serde_json::from_str(&json).unwrap();
        assert_eq!(
            parsed,
            serde_json::json!({
                "columns": ["x", "y"],
                "index": [10, 20],
                "data": [
                    [10, "a"],
                    [null, "b"]
                ]
            })
        );
    }

    #[test]
    fn dataframe_to_json_values() {
        let df = DataFrame::from_dict(
            &["x", "y"],
            vec![
                ("x", vec![Scalar::Int64(10), Scalar::Float64(f64::NAN)]),
                ("y", vec![Scalar::Bool(true), Scalar::Bool(false)]),
            ],
        )
        .unwrap();

        let json = df.to_json("values").unwrap();
        let parsed: Value = serde_json::from_str(&json).unwrap();
        assert_eq!(parsed, serde_json::json!([[10.0, true], [null, false]]));
    }

    #[test]
    fn dataframe_to_json_table() {
        let index = Index::from_i64(vec![10, 20]).set_names(Some("row_id"));
        let mut columns = BTreeMap::new();
        columns.insert(
            "x".to_owned(),
            Column::from_values(vec![Scalar::Int64(1), Scalar::Null(NullKind::Null)]).unwrap(),
        );
        columns.insert(
            "y".to_owned(),
            Column::from_values(vec![
                Scalar::Utf8("a".to_owned()),
                Scalar::Utf8("b".to_owned()),
            ])
            .unwrap(),
        );
        let df =
            DataFrame::new_with_column_order(index, columns, vec!["x".to_owned(), "y".to_owned()])
                .unwrap();

        let json = df.to_json("table").unwrap();
        let parsed: Value = serde_json::from_str(&json).unwrap();
        assert_eq!(
            parsed,
            serde_json::json!({
                "schema": {
                    "fields": [
                        {"name": "row_id", "type": "integer"},
                        {"name": "x", "type": "integer"},
                        {"name": "y", "type": "string"}
                    ],
                    "primaryKey": ["row_id"],
                    "pandas_version": "1.4.0"
                },
                "data": [
                    {"row_id": 10, "x": 1, "y": "a"},
                    {"row_id": 20, "x": null, "y": "b"}
                ]
            })
        );
    }

    #[test]
    fn dataframe_to_json_table_unnamed_index_uses_level_0_when_index_column_exists() {
        let df = DataFrame::from_dict(
            &["index", "value"],
            vec![
                ("index", vec![Scalar::Utf8("left".to_owned())]),
                ("value", vec![Scalar::Int64(7)]),
            ],
        )
        .unwrap();

        let json = df.to_json("table").unwrap();
        let parsed: Value = serde_json::from_str(&json).unwrap();
        assert_eq!(
            parsed,
            serde_json::json!({
                "schema": {
                    "fields": [
                        {"name": "level_0", "type": "integer"},
                        {"name": "index", "type": "string"},
                        {"name": "value", "type": "integer"}
                    ],
                    "primaryKey": ["level_0"],
                    "pandas_version": "1.4.0"
                },
                "data": [
                    {"level_0": 0, "index": "left", "value": 7}
                ]
            })
        );
    }

    #[test]
    fn dataframe_to_json_table_uses_stringified_multiindex_column_labels() {
        let index = Index::from_i64(vec![10, 20]).set_names(Some("row_id"));
        let mut columns = BTreeMap::new();
        columns.insert(
            "price_open".to_string(),
            Column::from_values(vec![Scalar::Int64(10), Scalar::Int64(12)]).unwrap(),
        );
        columns.insert(
            "price_close".to_string(),
            Column::from_values(vec![Scalar::Int64(11), Scalar::Int64(13)]).unwrap(),
        );
        let column_multiindex = fp_index::MultiIndex::from_arrays(vec![
            vec![
                IndexLabel::Utf8("price".into()),
                IndexLabel::Utf8("price".into()),
            ],
            vec![
                IndexLabel::Utf8("open".into()),
                IndexLabel::Utf8("close".into()),
            ],
        ])
        .unwrap()
        .set_names(vec![Some("field".into()), Some("stat".into())]);
        let df = DataFrame::new_with_column_order_and_multiindex(
            index,
            columns,
            vec!["price_open".to_string(), "price_close".to_string()],
            Some(column_multiindex),
        )
        .unwrap();

        let err = df.to_json("table").unwrap_err();
        assert!(
            matches!(err, FrameError::CompatibilityRejected(msg) if msg == "orient='table' is not supported for MultiIndex columns")
        );
    }

    // --- Series.explode tests ---

    #[test]
    fn series_explode_basic() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into()],
            vec![
                Scalar::Utf8("a,b,c".to_owned()),
                Scalar::Utf8("d".to_owned()),
            ],
        )
        .unwrap();

        let result = s.explode(",").unwrap();
        assert_eq!(result.len(), 4); // a, b, c, d
        assert_eq!(result.values()[0], Scalar::Utf8("a".to_owned()));
        assert_eq!(result.values()[1], Scalar::Utf8("b".to_owned()));
        assert_eq!(result.values()[2], Scalar::Utf8("c".to_owned()));
        assert_eq!(result.values()[3], Scalar::Utf8("d".to_owned()));
    }

    #[test]
    fn series_explode_preserves_index() {
        let s = Series::from_values(
            "x",
            vec![
                IndexLabel::Utf8("r1".to_owned()),
                IndexLabel::Utf8("r2".to_owned()),
            ],
            vec![Scalar::Utf8("a,b".to_owned()), Scalar::Utf8("c".to_owned())],
        )
        .unwrap();

        let result = s.explode(",").unwrap();
        assert_eq!(result.len(), 3);
        // r1 should be repeated for a and b
        assert_eq!(
            result.index().labels()[0],
            IndexLabel::Utf8("r1".to_owned())
        );
        assert_eq!(
            result.index().labels()[1],
            IndexLabel::Utf8("r1".to_owned())
        );
        assert_eq!(
            result.index().labels()[2],
            IndexLabel::Utf8("r2".to_owned())
        );
    }

    #[test]
    fn series_explode_with_nulls() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into()],
            vec![Scalar::Utf8("a,b".to_owned()), Scalar::Null(NullKind::NaN)],
        )
        .unwrap();

        let result = s.explode(",").unwrap();
        assert_eq!(result.len(), 3); // a, b, NaN
        assert!(result.values()[2].is_missing());
    }

