    // ── EWM tests ──

    #[test]
    fn ewm_mean_basic() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();

        // span=3 → alpha = 2/(3+1) = 0.5
        let result = s.ewm(Some(3.0), None).mean().unwrap();
        // First value: 1.0
        assert_eq!(result.values()[0], Scalar::Float64(1.0));
        // Second: 0.5*2 + 0.5*1 = 1.5
        assert_eq!(result.values()[1], Scalar::Float64(1.5));
        // Third: 0.5*3 + 0.5*1.5 = 2.25
        assert_eq!(result.values()[2], Scalar::Float64(2.25));
        // Fourth: 0.5*4 + 0.5*2.25 = 3.125
        assert_eq!(result.values()[3], Scalar::Float64(3.125));
    }

    #[test]
    fn ewm_mean_with_alpha() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
                Scalar::Float64(30.0),
            ],
        )
        .unwrap();

        let result = s.ewm(None, Some(0.5)).mean().unwrap();
        assert_eq!(result.values()[0], Scalar::Float64(10.0));
        assert_eq!(result.values()[1], Scalar::Float64(15.0));
        assert_eq!(result.values()[2], Scalar::Float64(22.5));
    }

    #[test]
    fn ewm_mean_with_nulls() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();

        let result = s.ewm(Some(3.0), None).mean().unwrap();
        assert_eq!(result.values()[0], Scalar::Float64(1.0));
        // Per br-frankenpandas-mm77i: pandas carries forward last EWM for nulls
        assert_eq!(result.values()[1], Scalar::Float64(1.0));
        // After null, third value: 0.5*3 + 0.5*1 = 2.0
        assert_eq!(result.values()[2], Scalar::Float64(2.0));
    }

    #[test]
    fn ewm_var_basic() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();

        let result = s.ewm(Some(3.0), None).var().unwrap();
        // First value: NaN (can't compute variance from 1 obs)
        assert!(result.values()[0].is_missing());
        // Second value should be a positive number
        let v = expect_float64(&result.values()[1]);
        assert!(v > 0.0);
    }

    #[test]
    fn ewm_std_basic() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();

        let result = s.ewm(Some(3.0), None).std().unwrap();
        // First: NaN
        assert!(result.values()[0].is_missing());
        // Rest: should be sqrt of var, so positive
        let v = expect_float64(&result.values()[1]);
        assert!(v > 0.0);
    }

    #[test]
    fn ewm_sum_basic() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();
        let result = s.ewm(None, Some(0.5)).sum().unwrap();
        // recursive: s0 = 1; s1 = 2 + 0.5*1 = 2.5; s2 = 3 + 0.5*2.5 = 4.25
        assert_eq!(result.values()[0], Scalar::Float64(1.0));
        assert_eq!(result.values()[1], Scalar::Float64(2.5));
        assert_eq!(result.values()[2], Scalar::Float64(4.25));
    }

    #[test]
    fn ewm_sum_skips_nulls() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();
        let result = s.ewm(None, Some(0.5)).sum().unwrap();
        assert_eq!(result.values()[0], Scalar::Float64(1.0));
        assert!(result.values()[1].is_missing());
        // Second real value: 3 + 0.5*1 = 3.5 (count increments only on non-null).
        assert_eq!(result.values()[2], Scalar::Float64(3.5));
    }

    #[test]
    fn ewm_cov_positively_correlated_converges_positive() {
        let a = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Float64(4.0),
                Scalar::Float64(6.0),
                Scalar::Float64(8.0),
            ],
        )
        .unwrap();
        let result = a.ewm(None, Some(0.5)).cov(&b).unwrap();
        assert!(result.values()[0].is_missing());
        // Perfectly positively linear: later cov values should be positive.
        let v = expect_float64(&result.values()[3]);
        assert!(v > 0.0);
    }

