    // ── autocorr tests ──

    #[test]
    fn series_autocorr_lag1() {
        // Perfectly correlated with lag 1: [1,2,3,4,5]
        let s = Series::from_values(
            "x",
            vec![
                0_i64.into(),
                1_i64.into(),
                2_i64.into(),
                3_i64.into(),
                4_i64.into(),
            ],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
                Scalar::Float64(5.0),
            ],
        )
        .unwrap();

        let r = s.autocorr(1).unwrap();
        assert!((r - 1.0).abs() < 0.01);
    }

    #[test]
    fn series_autocorr_lag_too_large() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into()],
            vec![Scalar::Float64(1.0), Scalar::Float64(2.0)],
        )
        .unwrap();

        let r = s.autocorr(5).unwrap();
        assert!(r.is_nan());
    }

    // ── dot product tests ──

    #[test]
    fn series_dot_product() {
        let a = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(4.0),
                Scalar::Float64(5.0),
                Scalar::Float64(6.0),
            ],
        )
        .unwrap();

        // 1*4 + 2*5 + 3*6 = 4 + 10 + 18 = 32
        let result = a.dot(&b).unwrap();
        assert!((result - 32.0).abs() < f64::EPSILON);
    }

    #[test]
    fn series_dot_with_nulls() {
        let a = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(4.0),
                Scalar::Float64(5.0),
                Scalar::Float64(6.0),
            ],
        )
        .unwrap();

        let result = a.dot(&b).unwrap();
        assert!(result.is_nan());
    }

    #[test]
    fn series_dot_aligns_by_index_label() {
        let a = Series::from_values(
            "a",
            vec!["a".into(), "b".into()],
            vec![Scalar::Int64(1), Scalar::Int64(2)],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec!["b".into(), "a".into()],
            vec![Scalar::Int64(10), Scalar::Int64(20)],
        )
        .unwrap();

        let result = a.dot(&b).unwrap();
        assert!((result - 40.0).abs() < f64::EPSILON);
    }

    #[test]
    fn series_dot_rejects_misaligned_label_sets() {
        let a = Series::from_values(
            "a",
            vec!["a".into(), "b".into()],
            vec![Scalar::Int64(1), Scalar::Int64(2)],
        )
        .unwrap();
        let b = Series::from_values(
            "b",
            vec!["a".into(), "c".into()],
            vec![Scalar::Int64(10), Scalar::Int64(20)],
        )
        .unwrap();

        let err = a.dot(&b).unwrap_err();
        assert!(
            matches!(err, FrameError::CompatibilityRejected(message) if message.contains("matrices are not aligned"))
        );
    }

