    #[test]
    fn resample_apply_custom_sum_of_squares() {
        let s = Series::from_values(
            "val",
            vec![
                "2024-01-05".into(),
                "2024-01-20".into(),
                "2024-02-10".into(),
            ],
            vec![
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
                Scalar::Float64(5.0),
            ],
        )
        .unwrap();

        let result = s
            .resample("M")
            .apply(|vals| {
                let sum_sq: f64 = vals
                    .iter()
                    .filter_map(|v| v.to_f64().ok())
                    .map(|x| x * x)
                    .sum();
                Scalar::Float64(sum_sq)
            })
            .unwrap();

        assert_eq!(result.len(), 2);
        // Jan: 3^2 + 4^2 = 9 + 16 = 25
        assert_eq!(result.values()[0], Scalar::Float64(25.0));
        // Feb: 5^2 = 25
        assert_eq!(result.values()[1], Scalar::Float64(25.0));
    }

    #[test]
    fn resample_apply_fn_failable() {
        let s = Series::from_values(
            "val",
            vec!["2024-01-01".into(), "2024-02-01".into()],
            vec![Scalar::Float64(10.0), Scalar::Float64(20.0)],
        )
        .unwrap();

        let result = s
            .resample("M")
            .apply_fn(|vals| {
                let total: f64 = vals.iter().filter_map(|v| v.to_f64().ok()).sum();
                Ok(Scalar::Float64(total * 2.0))
            })
            .unwrap();

        assert_eq!(result.values()[0], Scalar::Float64(20.0));
        assert_eq!(result.values()[1], Scalar::Float64(40.0));
    }

    #[test]
    fn resample_std_var_median_prod() {
        let s = Series::from_values(
            "val",
            vec![
                "2024-01-01".into(),
                "2024-01-15".into(),
                "2024-01-30".into(),
            ],
            vec![
                Scalar::Float64(2.0),
                Scalar::Float64(4.0),
                Scalar::Float64(6.0),
            ],
        )
        .unwrap();

        // Median: 4.0
        let med = s.resample("M").median().unwrap();
        assert_eq!(med.values()[0], Scalar::Float64(4.0));

        // Prod: 2*4*6 = 48
        let prod = s.resample("M").prod().unwrap();
        assert_eq!(prod.values()[0], Scalar::Float64(48.0));

        // Std: sqrt(var) where var = ((2-4)^2 + (4-4)^2 + (6-4)^2) / 2 = 4
        let std_result = s.resample("M").std().unwrap();
        let std_val = std_result.values()[0].to_f64().unwrap();
        assert!((std_val - 2.0).abs() < 1e-10);

        // Var: 4
        let var_result = s.resample("M").var().unwrap();
        let var_val = var_result.values()[0].to_f64().unwrap();
        assert!((var_val - 4.0).abs() < 1e-10);
    }

    #[test]
    fn resample_cxq4t_series_parity_surface() {
        let s = Series::from_values(
            "px",
            vec![
                "2024-01-01".into(),
                "2024-01-15".into(),
                "2024-02-01".into(),
                "2024-02-10".into(),
                "2024-02-20".into(),
            ],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(3.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(5.0),
                Scalar::Float64(5.0),
            ],
        )
        .unwrap();
        let resample = s.resample("M");

        assert_eq!(
            resample.keys(),
            vec![
                IndexLabel::Utf8("2024-01".into()),
                IndexLabel::Utf8("2024-02".into())
            ]
        );
        assert_eq!(resample.ngroups(), 2);
        assert_eq!(resample.ndim(), 1);
        assert_eq!(resample.grouper(), "M");
        assert!(resample.exclusions().is_empty());
        assert_eq!(
            resample.indices().get(&IndexLabel::Utf8("2024-01".into())),
            Some(&vec![0, 1])
        );
        assert_eq!(resample.get_group("2024-02").unwrap().len(), 3);

        let agg = resample.agg(&["sum", "size", "nunique"]).unwrap();
        assert_eq!(
            agg.columns()["sum"].values(),
            &[Scalar::Float64(4.0), Scalar::Float64(10.0)]
        );
        assert_eq!(
            agg.columns()["size"].values(),
            &[Scalar::Int64(2), Scalar::Int64(3)]
        );
        assert_eq!(
            agg.columns()["nunique"].values(),
            &[Scalar::Int64(2), Scalar::Int64(1)]
        );
        let aggregate_alias = resample.aggregate(&["mean"]).unwrap();
        assert_eq!(
            aggregate_alias.columns()["mean"].values(),
            &[Scalar::Float64(2.0), Scalar::Float64(5.0)]
        );

        let quantile = resample.quantile(0.5).unwrap();
        assert_eq!(
            quantile.values(),
            &[Scalar::Float64(2.0), Scalar::Float64(5.0)]
        );
        let sem = resample.sem().unwrap();
        assert!((sem.values()[0].to_f64().unwrap() - 1.0).abs() < 1e-12);
        assert!((sem.values()[1].to_f64().unwrap() - 0.0).abs() < 1e-12);

        let transformed = resample.transform("size").unwrap();
        assert_eq!(
            transformed.values(),
            &[
                Scalar::Int64(2),
                Scalar::Int64(2),
                Scalar::Int64(3),
                Scalar::Int64(3),
                Scalar::Int64(3)
            ]
        );

        let ohlc = resample.ohlc().unwrap();
        assert_eq!(
            ohlc.column_names()
                .into_iter()
                .map(String::as_str)
                .collect::<Vec<_>>(),
            vec!["open", "high", "low", "close"]
        );
        assert_eq!(
            ohlc.columns()["close"].values(),
            &[Scalar::Float64(3.0), Scalar::Float64(5.0)]
        );
        assert_eq!(resample.pipe(|r| Ok(r.ngroups())).unwrap(), 2);
        assert_eq!(
            resample.asfreq().unwrap().values(),
            &[Scalar::Float64(1.0), Scalar::Float64(5.0)]
        );
        assert_eq!(
            resample.bfill(None).unwrap().values(),
            &[Scalar::Float64(3.0), Scalar::Float64(5.0)]
        );
    }

    // ── DataFrame explode tests ──

    #[test]
    fn df_explode_basic() {
        let df = DataFrame::from_dict(
            &["name", "tags"],
            vec![
                (
                    "name",
                    vec![
                        Scalar::Utf8("Alice".to_owned()),
                        Scalar::Utf8("Bob".to_owned()),
                    ],
                ),
                (
                    "tags",
                    vec![
                        Scalar::Utf8("a,b,c".to_owned()),
                        Scalar::Utf8("x,y".to_owned()),
                    ],
                ),
            ],
        )
        .unwrap();

        let result = df.explode("tags", ",").unwrap();
        // Alice: a, b, c (3 rows) + Bob: x, y (2 rows) = 5 rows
        assert_eq!(result.len(), 5);

        let tags = result.column_as_series("tags").unwrap();
        assert_eq!(tags.values()[0], Scalar::Utf8("a".to_owned()));
        assert_eq!(tags.values()[1], Scalar::Utf8("b".to_owned()));
        assert_eq!(tags.values()[2], Scalar::Utf8("c".to_owned()));
        assert_eq!(tags.values()[3], Scalar::Utf8("x".to_owned()));
        assert_eq!(tags.values()[4], Scalar::Utf8("y".to_owned()));
    }

    #[test]
    fn df_explode_preserves_other_columns() {
        let df = DataFrame::from_dict(
            &["id", "items"],
            vec![
                ("id", vec![Scalar::Int64(1), Scalar::Int64(2)]),
                (
                    "items",
                    vec![Scalar::Utf8("a|b".to_owned()), Scalar::Utf8("c".to_owned())],
                ),
            ],
        )
        .unwrap();

        let result = df.explode("items", "|").unwrap();
        assert_eq!(result.len(), 3);
        let id_col = result.column_as_series("id").unwrap();
        assert_eq!(id_col.values()[0], Scalar::Int64(1));
        assert_eq!(id_col.values()[1], Scalar::Int64(1));
        assert_eq!(id_col.values()[2], Scalar::Int64(2));
    }

    #[test]
    fn df_explode_ignore_index_resets_labels() {
        let df = DataFrame::from_dict_with_index(
            vec![
                ("id", vec![Scalar::Int64(1), Scalar::Int64(2)]),
                (
                    "items",
                    vec![Scalar::Utf8("a|b".to_owned()), Scalar::Utf8("c".to_owned())],
                ),
            ],
            vec!["left".into(), "right".into()],
        )
        .unwrap();

        let result = df.explode_with_ignore_index("items", "|", true).unwrap();
        assert_eq!(result.len(), 3);
        assert_eq!(
            result.index().labels(),
            &[0_i64.into(), 1_i64.into(), 2_i64.into()]
        );

        let items = result.column_as_series("items").unwrap();
        assert_eq!(items.values()[0], Scalar::Utf8("a".to_owned()));
        assert_eq!(items.values()[1], Scalar::Utf8("b".to_owned()));
        assert_eq!(items.values()[2], Scalar::Utf8("c".to_owned()));
    }

