    // ── GroupBy pct_change tests ──

    #[test]
    fn groupby_pct_change() {
        let df = DataFrame::from_dict(
            &["g", "v"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".to_owned()),
                        Scalar::Utf8("a".to_owned()),
                        Scalar::Utf8("a".to_owned()),
                    ],
                ),
                (
                    "v",
                    vec![
                        Scalar::Float64(100.0),
                        Scalar::Float64(110.0),
                        Scalar::Float64(121.0),
                    ],
                ),
            ],
        )
        .unwrap();

        let result = df.groupby(&["g"]).unwrap().pct_change(1).unwrap();
        let v = result.column_as_series("v").unwrap();
        assert!(v.values()[0].is_missing()); // first: NaN
        // (110-100)/100 = 0.1
        let f1 = expect_float64(&v.values()[1]);
        assert!((f1 - 0.1).abs() < 1e-10);
        // (121-110)/110 = 0.1
        let f2 = expect_float64(&v.values()[2]);
        assert!((f2 - 0.1).abs() < 1e-10);
    }

    #[test]
    fn groupby_pct_change_timedelta64_matches_pandas_dj6rv() {
        // Per br-frankenpandas-dj6rv: groupby pct_change on Timedelta64
        // now computes f64 ratios; was silently NaN via the to_f64-else
        // catch-all.
        let one_hour = 3_600 * 1_000_000_000_i64;
        let df = DataFrame::from_dict(
            &["g", "v"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".to_owned()),
                        Scalar::Utf8("a".to_owned()),
                        Scalar::Utf8("a".to_owned()),
                    ],
                ),
                (
                    "v",
                    vec![
                        Scalar::Timedelta64(one_hour),
                        Scalar::Timedelta64(2 * one_hour),
                        Scalar::Timedelta64(4 * one_hour),
                    ],
                ),
            ],
        )
        .unwrap();

        let result = df.groupby(&["g"]).unwrap().pct_change(1).unwrap();
        let v = result.column_as_series("v").unwrap();
        assert!(v.values()[0].is_missing());
        let f1 = expect_float64(&v.values()[1]);
        assert!((f1 - 1.0).abs() < 1e-10); // (2h-1h)/1h = 1.0
        let f2 = expect_float64(&v.values()[2]);
        assert!((f2 - 1.0).abs() < 1e-10); // (4h-2h)/2h = 1.0
    }

    #[test]
    fn groupby_diff_timedelta64_returns_timedelta_q82t4() {
        // Per br-frankenpandas-q82t4: groupby diff on Timedelta64 returns
        // Timedelta64 differences (preserves dtype), not Float64.
        let one_hour = 3_600 * 1_000_000_000_i64;
        let df = DataFrame::from_dict(
            &["g", "v"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".to_owned()),
                        Scalar::Utf8("a".to_owned()),
                        Scalar::Utf8("a".to_owned()),
                    ],
                ),
                (
                    "v",
                    vec![
                        Scalar::Timedelta64(one_hour),
                        Scalar::Timedelta64(3 * one_hour),
                        Scalar::Timedelta64(2 * one_hour),
                    ],
                ),
            ],
        )
        .unwrap();

        let result = df.groupby(&["g"]).unwrap().diff(1).unwrap();
        let v = result.column_as_series("v").unwrap();
        assert!(v.values()[0].is_missing());
        match &v.values()[1] {
            Scalar::Timedelta64(ns) => assert_eq!(*ns, 2 * one_hour),
            other => panic!("expected Timedelta64(2h), got {:?}", other),
        }
        match &v.values()[2] {
            Scalar::Timedelta64(ns) => assert_eq!(*ns, -one_hour),
            other => panic!("expected Timedelta64(-1h), got {:?}", other),
        }
    }

    #[test]
    fn series_groupby_min_max_timedelta64_tgm2i() {
        // Per br-frankenpandas-tgm2i: SeriesGroupBy::min/max on Timedelta64
        // preserve dtype per group.
        let one_hour: i64 = 3_600 * 1_000_000_000;
        let keys = Series::from_values(
            "k",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Utf8("a".to_owned()),
                Scalar::Utf8("a".to_owned()),
                Scalar::Utf8("b".to_owned()),
                Scalar::Utf8("b".to_owned()),
            ],
        )
        .unwrap();
        let dur = Series::from_values(
            "dur",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Timedelta64(3 * one_hour),
                Scalar::Timedelta64(one_hour),
                Scalar::Timedelta64(5 * one_hour),
                Scalar::Timedelta64(2 * one_hour),
            ],
        )
        .unwrap();
        let mins = dur.groupby(&keys).unwrap().min().unwrap();
        match mins.values()[0] {
            Scalar::Timedelta64(ns) => assert_eq!(ns, one_hour),
            ref other => panic!("expected Timedelta64(1h), got {:?}", other),
        }
        match mins.values()[1] {
            Scalar::Timedelta64(ns) => assert_eq!(ns, 2 * one_hour),
            ref other => panic!("expected Timedelta64(2h), got {:?}", other),
        }
        let maxes = dur.groupby(&keys).unwrap().max().unwrap();
        match maxes.values()[0] {
            Scalar::Timedelta64(ns) => assert_eq!(ns, 3 * one_hour),
            ref other => panic!("expected Timedelta64(3h), got {:?}", other),
        }
        match maxes.values()[1] {
            Scalar::Timedelta64(ns) => assert_eq!(ns, 5 * one_hour),
            ref other => panic!("expected Timedelta64(5h), got {:?}", other),
        }
    }

    #[test]
    fn series_groupby_sum_mean_timedelta64_c1bxu() {
        // Per br-frankenpandas-c1bxu: SeriesGroupBy::sum and mean on a
        // Timedelta64 source column preserve Timedelta dtype per group.
        let one_hour: i64 = 3_600 * 1_000_000_000;
        let keys = Series::from_values(
            "k",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("a".to_owned()),
                Scalar::Utf8("a".to_owned()),
                Scalar::Utf8("b".to_owned()),
            ],
        )
        .unwrap();
        let dur = Series::from_values(
            "dur",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Timedelta64(one_hour),
                Scalar::Timedelta64(2 * one_hour),
                Scalar::Timedelta64(5 * one_hour),
            ],
        )
        .unwrap();
        let sums = dur.groupby(&keys).unwrap().sum().unwrap();
        match sums.values()[0] {
            Scalar::Timedelta64(ns) => assert_eq!(ns, 3 * one_hour),
            ref other => panic!("expected Timedelta64(3h), got {:?}", other),
        }
        match sums.values()[1] {
            Scalar::Timedelta64(ns) => assert_eq!(ns, 5 * one_hour),
            ref other => panic!("expected Timedelta64(5h), got {:?}", other),
        }
        let means = dur.groupby(&keys).unwrap().mean().unwrap();
        match means.values()[0] {
            Scalar::Timedelta64(ns) => assert_eq!(ns, 3 * one_hour / 2),
            ref other => panic!("expected Timedelta64(1.5h), got {:?}", other),
        }
        match means.values()[1] {
            Scalar::Timedelta64(ns) => assert_eq!(ns, 5 * one_hour),
            ref other => panic!("expected Timedelta64(5h), got {:?}", other),
        }
    }

