    #[test]
    fn series_r6uci_metadata_and_numpy_compat_aliases() {
        let s = Series::from_values(
            "x",
            vec![IndexLabel::Utf8("a".into()), IndexLabel::Utf8("b".into())],
            vec![Scalar::Int64(10), Scalar::Int64(20)],
        )
        .unwrap();

        assert_eq!(s.transpose(), s);
        assert_eq!(s.t(), s);
        assert_eq!(s.T(), s);
        assert_eq!(s.view(), s);
        assert_eq!(s.swapaxes(), s);
        assert_eq!(s.reorder_levels(&[0]).unwrap(), s);
        assert_eq!(s.array(), vec![Scalar::Int64(10), Scalar::Int64(20)]);
        assert_eq!(s.ravel(), s.array());
        assert_eq!(s.tolist(), s.to_list());
        assert_eq!(s.shape(), (2,));
        assert_eq!(s.dtypes(), DType::Int64);
        assert!(s.attrs().is_empty());
        assert!(s.flags().allows_duplicate_labels());
        assert_eq!(s.set_flags(None).unwrap(), s);
        assert_eq!(s.set_flags(Some(false)).unwrap(), s);

        let info = s.info();
        assert!(info.contains("Series: x"));
        assert!(info.contains("Length: 2"));
        assert!(info.contains("Non-Null Count: 2"));
        assert!(info.contains("Dtype: Int64"));

        let strings = Series::from_values(
            "obj",
            vec![0_i64.into(), 1_i64.into()],
            vec![Scalar::Utf8("1".into()), Scalar::Utf8("2".into())],
        )
        .unwrap();
        let inferred = strings.infer_objects().unwrap();
        assert_eq!(inferred.dtypes(), DType::Int64);
        assert_eq!(inferred.values(), &[Scalar::Int64(1), Scalar::Int64(2)]);

        let list = s.list();
        assert_eq!(list.series_name(), "x");
        assert!(!list.is_supported());
        assert!(
            list.unsupported_reason()
                .contains("expected missing values or UTF-8 JSON arrays")
        );

        let struct_accessor = s.r#struct();
        assert_eq!(struct_accessor.series_name(), "x");
        assert!(!struct_accessor.is_supported());
        assert!(
            struct_accessor
                .unsupported_reason()
                .contains("expected missing values or UTF-8 JSON objects")
        );
    }

    #[test]
    fn series_list_accessor_json_values_ego6v() {
        let s = Series::from_values(
            "items",
            vec![
                IndexLabel::Utf8("a".into()),
                IndexLabel::Utf8("b".into()),
                IndexLabel::Utf8("c".into()),
                IndexLabel::Utf8("d".into()),
            ],
            vec![
                Scalar::Utf8(r#"[1,"x",null]"#.into()),
                Scalar::Utf8("[]".into()),
                Scalar::Null(NullKind::Null),
                Scalar::Utf8("[true,2.5]".into()),
            ],
        )
        .unwrap();

        let list = s.list();
        assert!(list.is_supported());
        assert!(
            list.unsupported_reason()
                .contains("supports JSON-array UTF-8 list values")
        );

        let lengths = list.len().unwrap();
        assert_eq!(
            lengths.values(),
            &[
                Scalar::Int64(3),
                Scalar::Int64(0),
                Scalar::Null(NullKind::Null),
                Scalar::Int64(2),
            ]
        );
        assert_eq!(lengths.index().labels(), s.index().labels());

        let second = list.get(1).unwrap();
        assert_eq!(
            second.values(),
            &[
                Scalar::Utf8("x".into()),
                Scalar::Null(NullKind::Null),
                Scalar::Null(NullKind::Null),
                Scalar::Float64(2.5),
            ]
        );

        let last = list.get(-1).unwrap();
        assert_eq!(
            last.values(),
            &[
                Scalar::Null(NullKind::NaN),
                Scalar::Null(NullKind::NaN),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(2.5),
            ]
        );

        let flattened = list.flatten().unwrap();
        assert_eq!(
            flattened.values(),
            &[
                Scalar::Int64(1),
                Scalar::Utf8("x".into()),
                Scalar::Null(NullKind::Null),
                Scalar::Bool(true),
                Scalar::Float64(2.5),
            ]
        );
        assert_eq!(
            flattened.index().labels(),
            &[
                IndexLabel::Int64(0),
                IndexLabel::Int64(1),
                IndexLabel::Int64(2),
                IndexLabel::Int64(3),
                IndexLabel::Int64(4),
            ]
        );
    }

