    #[test]
    fn dataframe_groupby_ba1kr_stats_and_grouped_windows() {
        let df = DataFrame::from_dict(
            &["g", "x", "y"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("b".into()),
                        Scalar::Utf8("b".into()),
                    ],
                ),
                (
                    "x",
                    vec![
                        Scalar::Float64(1.0),
                        Scalar::Float64(2.0),
                        Scalar::Float64(10.0),
                        Scalar::Float64(20.0),
                    ],
                ),
                (
                    "y",
                    vec![
                        Scalar::Float64(2.0),
                        Scalar::Float64(4.0),
                        Scalar::Float64(30.0),
                        Scalar::Float64(50.0),
                    ],
                ),
            ],
        )
        .unwrap();
        let grouped = df.groupby(&["g"]).unwrap();

        let corr = grouped.corr().unwrap();
        assert_eq!(corr.len(), 4);
        assert!(corr.row_multiindex().is_some());
        assert!((corr.columns()["y"].values()[0].to_f64().unwrap() - 1.0).abs() < 1e-12);

        let cov = grouped.cov().unwrap();
        assert!((cov.columns()["y"].values()[0].to_f64().unwrap() - 1.0).abs() < 1e-12);

        let corrwith = grouped.corrwith(&df).unwrap();
        assert_eq!(corrwith.len(), 2);
        assert_eq!(
            corrwith
                .column_names()
                .into_iter()
                .map(String::as_str)
                .collect::<Vec<_>>(),
            vec!["x", "y"]
        );

        let expanding = grouped.expanding(Some(1)).mean().unwrap();
        assert_eq!(
            expanding.columns()["x"].values(),
            &[
                Scalar::Float64(1.0),
                Scalar::Float64(1.5),
                Scalar::Float64(10.0),
                Scalar::Float64(15.0)
            ]
        );

        let ewm = grouped.ewm(None, Some(0.5)).mean().unwrap();
        assert_eq!(
            ewm.columns()["x"].values(),
            &[
                Scalar::Float64(1.0),
                Scalar::Float64(1.5),
                Scalar::Float64(10.0),
                Scalar::Float64(15.0)
            ]
        );
    }

    #[test]
    fn groupby_sem() {
        let df = DataFrame::from_dict(
            &["g", "v"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                    ],
                ),
                (
                    "v",
                    vec![
                        Scalar::Float64(2.0),
                        Scalar::Float64(4.0),
                        Scalar::Float64(6.0),
                        Scalar::Float64(8.0),
                    ],
                ),
            ],
        )
        .unwrap();
        let gb = df.groupby(&["g"]).unwrap();
        let result = gb.sem().unwrap();
        // std of [2,4,6,8] = 2.5819..., sem = 2.5819.../sqrt(4) ≈ 1.2909...
        let val = result.columns()["v"].values()[0].to_f64().unwrap();
        assert!((val - 1.2909944).abs() < 0.001);
    }

    // ── Batch 8: Rolling/Expanding enhancements ──

    #[test]
    fn rolling_var() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();
        let result = s.rolling(3, None).var().unwrap();
        // First two should be NaN, third: var([1,2,3])=1.0, fourth: var([2,3,4])=1.0
        assert!(result.values()[0].is_missing());
        assert!(result.values()[1].is_missing());
        assert_eq!(result.values()[2], Scalar::Float64(1.0));
        assert_eq!(result.values()[3], Scalar::Float64(1.0));
    }

    #[test]
    fn rolling_median() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(3.0),
                Scalar::Float64(2.0),
            ],
        )
        .unwrap();
        let result = s.rolling(3, None).median().unwrap();
        assert!(result.values()[0].is_missing());
        assert!(result.values()[1].is_missing());
        // median([1,3,2]) = 2.0
        assert_eq!(result.values()[2], Scalar::Float64(2.0));
    }

    #[test]
    fn rolling_quantile() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(0.0),
                Scalar::Float64(5.0),
                Scalar::Float64(10.0),
            ],
        )
        .unwrap();
        let result = s.rolling(3, None).quantile(0.5).unwrap();
        // quantile(0.5) of [0,5,10] = 5.0
        assert_eq!(result.values()[2], Scalar::Float64(5.0));
    }

    #[test]
    fn rolling_apply_custom() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(3.0),
            ],
        )
        .unwrap();
        // Custom function: product of window values
        let result = s
            .rolling(2, None)
            .apply(|vals| vals.iter().product())
            .unwrap();
        assert!(result.values()[0].is_missing());
        // 1*2=2, 2*3=6
        assert_eq!(result.values()[1], Scalar::Float64(2.0));
        assert_eq!(result.values()[2], Scalar::Float64(6.0));
    }

    #[test]
    fn rolling_aggregate_sem_rank_and_introspection() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(3.0),
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
            ],
        )
        .unwrap();
        let rolling = s.rolling(2, None);

        let aggregate = rolling.aggregate(&["sum", "sem"]).unwrap();
        assert_eq!(
            aggregate
                .column_names()
                .into_iter()
                .cloned()
                .collect::<Vec<_>>(),
            vec!["sum".to_string(), "sem".to_string()]
        );
        assert_eq!(aggregate.columns()["sum"].values()[1], Scalar::Float64(4.0));
        let sem1 = expect_float64(&aggregate.columns()["sem"].values()[1]);
        let sem2 = expect_float64(&aggregate.columns()["sem"].values()[2]);
        assert!((sem1 - 1.0).abs() < 1e-10);
        assert!((sem2 - 0.5).abs() < 1e-10);

        let rank = rolling.rank("average", true, "keep").unwrap();
        assert!(rank.values()[0].is_missing());
        assert_eq!(rank.values()[1], Scalar::Float64(1.0));
        assert_eq!(rank.values()[2], Scalar::Float64(2.0));
        assert_eq!(rolling.exclusions(), Vec::<String>::new());
        assert_eq!(rolling.ndim(), 1);
    }

