    // ── GroupBy skew/kurtosis/ohlc ──

    #[test]
    fn groupby_skew() {
        let df = DataFrame::from_dict(
            &["g", "v"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                    ],
                ),
                (
                    "v",
                    vec![
                        Scalar::Float64(1.0),
                        Scalar::Float64(2.0),
                        Scalar::Float64(3.0),
                        Scalar::Float64(4.0),
                        Scalar::Float64(5.0),
                    ],
                ),
            ],
        )
        .unwrap();
        let gb = df.groupby(&["g"]).unwrap();
        let result = gb.skew().unwrap();
        // Symmetric data → skew ≈ 0
        let val = result.columns()["v"].values()[0].to_f64().unwrap();
        assert!(val.abs() < 0.01);
    }

    #[test]
    fn groupby_kurtosis() {
        let df = DataFrame::from_dict(
            &["g", "v"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                    ],
                ),
                (
                    "v",
                    vec![
                        Scalar::Float64(1.0),
                        Scalar::Float64(2.0),
                        Scalar::Float64(3.0),
                        Scalar::Float64(4.0),
                        Scalar::Float64(5.0),
                    ],
                ),
            ],
        )
        .unwrap();
        let gb = df.groupby(&["g"]).unwrap();
        let result = gb.kurtosis().unwrap();
        // Uniform-like → excess kurtosis < 0 (platykurtic)
        let val = result.columns()["v"].values()[0].to_f64().unwrap();
        assert!(val < 0.0);
    }

    #[test]
    fn groupby_ohlc() {
        let df = DataFrame::from_dict(
            &["g", "price"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                    ],
                ),
                (
                    "price",
                    vec![
                        Scalar::Float64(10.0),
                        Scalar::Float64(15.0),
                        Scalar::Float64(12.0),
                    ],
                ),
            ],
        )
        .unwrap();
        let gb = df.groupby(&["g"]).unwrap();
        let result = gb.ohlc().unwrap();
        // Only one value column, so no prefix
        assert_eq!(result.columns()["open"].values()[0], Scalar::Float64(10.0));
        assert_eq!(result.columns()["high"].values()[0], Scalar::Float64(15.0));
        assert_eq!(result.columns()["low"].values()[0], Scalar::Float64(10.0));
        assert_eq!(result.columns()["close"].values()[0], Scalar::Float64(12.0));
    }

    #[test]
    fn groupby_ohlc_multiple_value_columns_use_prefixed_names() {
        let df = DataFrame::from_dict(
            &["g", "price", "qty"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("b".into()),
                        Scalar::Utf8("b".into()),
                        Scalar::Utf8("a".into()),
                    ],
                ),
                (
                    "price",
                    vec![
                        Scalar::Float64(10.0),
                        Scalar::Float64(15.0),
                        Scalar::Null(NullKind::NaN),
                        Scalar::Float64(12.0),
                        Scalar::Float64(20.0),
                    ],
                ),
                (
                    "qty",
                    vec![
                        Scalar::Float64(1.0),
                        Scalar::Float64(3.0),
                        Scalar::Float64(5.0),
                        Scalar::Float64(4.0),
                        Scalar::Null(NullKind::NaN),
                    ],
                ),
            ],
        )
        .unwrap();
        let gb = df.groupby(&["g"]).unwrap();
        let result = gb.ohlc().unwrap();

        assert_eq!(
            result.column_names(),
            vec![
                "price_open",
                "price_high",
                "price_low",
                "price_close",
                "qty_open",
                "qty_high",
                "qty_low",
                "qty_close",
            ]
        );
        assert_eq!(
            result.columns()["price_open"].values()[0],
            Scalar::Float64(10.0)
        );
        assert_eq!(
            result.columns()["price_close"].values()[0],
            Scalar::Float64(20.0)
        );
        assert_eq!(
            result.columns()["price_open"].values()[1],
            Scalar::Float64(12.0)
        );
        assert_eq!(
            result.columns()["qty_open"].values()[0],
            Scalar::Float64(1.0)
        );
        assert_eq!(
            result.columns()["qty_close"].values()[0],
            Scalar::Float64(3.0)
        );
        assert_eq!(
            result.columns()["qty_high"].values()[1],
            Scalar::Float64(5.0)
        );
        assert_eq!(
            result.columns()["qty_low"].values()[1],
            Scalar::Float64(4.0)
        );
    }

    #[test]
    fn groupby_ohlc_single_value_column_exposes_column_multiindex() {
        let df = DataFrame::from_dict(
            &["g", "price"],
            vec![
                (
                    "g",
                    vec![
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("b".into()),
                    ],
                ),
                (
                    "price",
                    vec![
                        Scalar::Float64(10.0),
                        Scalar::Float64(15.0),
                        Scalar::Float64(12.0),
                    ],
                ),
            ],
        )
        .unwrap();

        let gb = df.groupby(&["g"]).unwrap();
        let frame = gb.ohlc().unwrap();
        let columns = frame
            .columns_multiindex()
            .expect("ohlc frame should carry column MultiIndex metadata");

        let top = columns.get_level_values(0).unwrap();
        let bottom = columns.get_level_values(1).unwrap();
        assert_eq!(
            top.labels(),
            &[
                IndexLabel::Utf8("price".into()),
                IndexLabel::Utf8("price".into()),
                IndexLabel::Utf8("price".into()),
                IndexLabel::Utf8("price".into()),
            ]
        );
        assert_eq!(
            bottom.labels(),
            &[
                IndexLabel::Utf8("open".into()),
                IndexLabel::Utf8("high".into()),
                IndexLabel::Utf8("low".into()),
                IndexLabel::Utf8("close".into()),
            ]
        );
        assert_eq!(
            frame.keys(),
            fp_index::MultiIndexOrIndex::Multi(columns.clone())
        );
    }

