    // ── Batch 10: DataFrame skew_agg/kurtosis_agg/sem_agg ──

    #[test]
    fn df_skew_agg() {
        let df = DataFrame::from_dict(
            &["x"],
            vec![(
                "x",
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(2.0),
                    Scalar::Float64(3.0),
                    Scalar::Float64(4.0),
                    Scalar::Float64(5.0),
                ],
            )],
        )
        .unwrap();
        let result = df.skew_agg().unwrap();
        // Symmetric data → skew ≈ 0
        let val = result.values()[0].to_f64().unwrap();
        assert!(val.abs() < 0.01);
    }

    #[test]
    fn df_kurtosis_agg() {
        let df = DataFrame::from_dict(
            &["x"],
            vec![(
                "x",
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(2.0),
                    Scalar::Float64(3.0),
                    Scalar::Float64(4.0),
                    Scalar::Float64(5.0),
                ],
            )],
        )
        .unwrap();
        let result = df.kurtosis_agg().unwrap();
        let val = result.values()[0].to_f64().unwrap();
        // Uniform-like → excess kurtosis < 0
        assert!(val < 0.0);
    }

    #[test]
    fn df_sem_agg() {
        let df = DataFrame::from_dict(
            &["x"],
            vec![(
                "x",
                vec![
                    Scalar::Float64(2.0),
                    Scalar::Float64(4.0),
                    Scalar::Float64(6.0),
                    Scalar::Float64(8.0),
                ],
            )],
        )
        .unwrap();
        let result = df.sem_agg().unwrap();
        // sem = std/sqrt(n) = 2.5819.../sqrt(4) ≈ 1.2909...
        let val = result.values()[0].to_f64().unwrap();
        assert!((val - 1.2909944).abs() < 0.001);
    }

