    // ── Batch 12: DataFrame::map_elements + str removeprefix/removesuffix ──

    #[test]
    fn df_map_elements() {
        let df = DataFrame::from_dict(
            &["x"],
            vec![("x", vec![Scalar::Int64(1), Scalar::Int64(2)])],
        )
        .unwrap();
        let result = df
            .map_elements(|v| match v {
                Scalar::Int64(n) => Scalar::Int64(n * 10),
                other => other.clone(),
            })
            .unwrap();
        assert_eq!(result.columns()["x"].values()[0], Scalar::Int64(10));
        assert_eq!(result.columns()["x"].values()[1], Scalar::Int64(20));
    }

    #[test]
    fn str_removeprefix() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("hello_world".into()),
                Scalar::Utf8("hello_foo".into()),
                Scalar::Utf8("bar".into()),
            ],
        )
        .unwrap();
        let result = s.str().removeprefix("hello_").unwrap();
        assert_eq!(result.column().values()[0], Scalar::Utf8("world".into()));
        assert_eq!(result.column().values()[1], Scalar::Utf8("foo".into()));
        assert_eq!(result.column().values()[2], Scalar::Utf8("bar".into()));
    }

    #[test]
    fn str_removeprefix_unicode_exactness() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Utf8("éclair".into()),
                Scalar::Utf8("e\u{301}clair".into()),
                Scalar::Utf8("ééclair".into()),
                Scalar::Utf8("beta".into()),
            ],
        )
        .unwrap();
        let result = s.str().removeprefix("é").unwrap();
        assert_eq!(result.column().values()[0], Scalar::Utf8("clair".into()));
        assert_eq!(
            result.column().values()[1],
            Scalar::Utf8("e\u{301}clair".into())
        );
        assert_eq!(result.column().values()[2], Scalar::Utf8("éclair".into()));
        assert_eq!(result.column().values()[3], Scalar::Utf8("beta".into()));
    }

    #[test]
    fn str_removesuffix() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("file.txt".into()),
                Scalar::Utf8("data.csv".into()),
                Scalar::Utf8("plain".into()),
            ],
        )
        .unwrap();
        let result = s.str().removesuffix(".txt").unwrap();
        assert_eq!(result.column().values()[0], Scalar::Utf8("file".into()));
        assert_eq!(result.column().values()[1], Scalar::Utf8("data.csv".into()));
        assert_eq!(result.column().values()[2], Scalar::Utf8("plain".into()));
    }

    #[test]
    fn str_normalize_unicode_forms() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("e\u{301}".into()),
                Scalar::Utf8("①".into()),
                Scalar::Null(NullKind::NaN),
            ],
        )
        .unwrap();

        let nfc = s.str().normalize("NFC").unwrap();
        assert_eq!(nfc.column().values()[0], Scalar::Utf8("é".into()));
        assert_eq!(nfc.column().values()[1], Scalar::Utf8("①".into()));
        assert!(nfc.column().values()[2].is_missing());

        let nfd = s.str().normalize("NFD").unwrap();
        assert_eq!(nfd.column().values()[0], Scalar::Utf8("e\u{301}".into()));

        let nfkc = s.str().normalize("NFKC").unwrap();
        assert_eq!(nfkc.column().values()[0], Scalar::Utf8("é".into()));
        assert_eq!(nfkc.column().values()[1], Scalar::Utf8("1".into()));

        let nfkd = s.str().normalize("NFKD").unwrap();
        assert_eq!(nfkd.column().values()[0], Scalar::Utf8("e\u{301}".into()));
        assert_eq!(nfkd.column().values()[1], Scalar::Utf8("1".into()));
    }

    #[test]
    fn str_normalize_rejects_invalid_form() {
        let s =
            Series::from_values("x", vec![0_i64.into()], vec![Scalar::Utf8("é".into())]).unwrap();
        let err = s.str().normalize("nfc").unwrap_err();
        assert!(matches!(
            err,
            FrameError::CompatibilityRejected(msg)
                if msg.contains("invalid normalization form: nfc")
        ));
    }

