    // ── DataFrame.where_mask_df / mask_df ──

    #[test]
    fn df_where_mask_df() {
        let df = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)],
            )],
        )
        .unwrap();
        let cond = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![Scalar::Bool(true), Scalar::Bool(false), Scalar::Bool(true)],
            )],
        )
        .unwrap();
        let result = df.where_mask_df(&cond, &Scalar::Int64(0)).unwrap();
        assert_eq!(result.columns["a"].values()[0], Scalar::Int64(1)); // true -> keep
        assert_eq!(result.columns["a"].values()[1], Scalar::Int64(0)); // false -> other
        assert_eq!(result.columns["a"].values()[2], Scalar::Int64(3)); // true -> keep
    }

    #[test]
    fn df_where_mask_df_ignores_extra_rows() {
        let df = DataFrame::from_dict(
            &["a"],
            vec![("a", vec![Scalar::Int64(1), Scalar::Int64(2)])],
        )
        .unwrap();
        let cond = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![Scalar::Bool(true), Scalar::Bool(false), Scalar::Bool(true)],
            )],
        )
        .unwrap();
        let result = df.where_mask_df(&cond, &Scalar::Int64(0)).unwrap();
        assert_eq!(result.len(), 2);
        assert_eq!(result.index().labels(), df.index().labels());
        assert_eq!(result.columns["a"].values()[0], Scalar::Int64(1));
        assert_eq!(result.columns["a"].values()[1], Scalar::Int64(0));
    }

    #[test]
    fn df_mask_df() {
        let df = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)],
            )],
        )
        .unwrap();
        let cond = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![Scalar::Bool(true), Scalar::Bool(false), Scalar::Bool(true)],
            )],
        )
        .unwrap();
        let result = df.mask_df(&cond, &Scalar::Int64(0)).unwrap();
        assert_eq!(result.columns["a"].values()[0], Scalar::Int64(0)); // true -> replace
        assert_eq!(result.columns["a"].values()[1], Scalar::Int64(2)); // false -> keep
        assert_eq!(result.columns["a"].values()[2], Scalar::Int64(0)); // true -> replace
    }

    #[test]
    fn df_where_mask_df_other_with_dataframe_replacement() {
        // br-frankenpandas-df9v7 / fd90.138: where_mask_df_other mirrors
        // mask_df_other so users can plug in a DataFrame as the replacement
        // source for where (was previously scalar-only).
        let df = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)],
            )],
        )
        .unwrap();
        let cond = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![Scalar::Bool(true), Scalar::Bool(false), Scalar::Bool(true)],
            )],
        )
        .unwrap();
        let other = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![Scalar::Int64(100), Scalar::Int64(200), Scalar::Int64(300)],
            )],
        )
        .unwrap();
        let result = df.where_mask_df_other(&cond, &other).unwrap();
        // where cond=true   -> keep self
        // where cond=false  -> take from other (200 at idx 1)
        assert_eq!(result.columns["a"].values()[0], Scalar::Int64(1));
        assert_eq!(result.columns["a"].values()[1], Scalar::Int64(200));
        assert_eq!(result.columns["a"].values()[2], Scalar::Int64(3));
    }

    // ── DataFrame.value_counts() ──

    #[test]
    fn df_value_counts_basic() {
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                (
                    "a",
                    vec![
                        Scalar::Utf8("x".to_string()),
                        Scalar::Utf8("y".to_string()),
                        Scalar::Utf8("x".to_string()),
                    ],
                ),
                (
                    "b",
                    vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(1)],
                ),
            ],
        )
        .unwrap();
        let result = df.value_counts().unwrap();
        // "x, 1" appears 2 times, "y, 2" appears 1 time
        assert_eq!(result.len(), 2);
        assert_eq!(result.column().values()[0], Scalar::Int64(2)); // most frequent first
        assert_eq!(result.column().values()[1], Scalar::Int64(1));
    }

    #[test]
    fn df_value_counts_map_one_series_per_column() {
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                (
                    "a",
                    vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(1)],
                ),
                (
                    "b",
                    vec![
                        Scalar::Utf8("x".into()),
                        Scalar::Utf8("x".into()),
                        Scalar::Utf8("y".into()),
                    ],
                ),
            ],
        )
        .unwrap();
        let result = df.value_counts_map().unwrap();
        assert_eq!(result.len(), 2);
        let a = result.get("a").expect("a column");
        assert_eq!(a.len(), 2); // [1 counted twice, 2 counted once]
        let b = result.get("b").expect("b column");
        assert_eq!(b.len(), 2); // [x counted twice, y counted once]
    }

    #[test]
    fn df_value_counts_map_differs_from_row_value_counts() {
        // Row value_counts treats full-row tuples; per-column decomposes.
        let df = DataFrame::from_dict(
            &["a", "b"],
            vec![
                ("a", vec![Scalar::Int64(1), Scalar::Int64(1)]),
                ("b", vec![Scalar::Int64(2), Scalar::Int64(3)]),
            ],
        )
        .unwrap();
        // Row level: (1,2) and (1,3) are distinct rows → 2 buckets.
        let row_counts = df.value_counts().unwrap();
        assert_eq!(row_counts.len(), 2);
        // Per-column: a has one unique value (1), b has two (2, 3).
        let per_col = df.value_counts_map().unwrap();
        assert_eq!(per_col.get("a").unwrap().len(), 1);
        assert_eq!(per_col.get("b").unwrap().len(), 2);
    }

    #[test]
    fn df_value_counts_merges_negative_zero_and_zero() {
        let df = DataFrame::from_dict(
            &["a"],
            vec![(
                "a",
                vec![
                    Scalar::Float64(-0.0),
                    Scalar::Float64(0.0),
                    Scalar::Float64(1.0),
                ],
            )],
        )
        .unwrap();

        let result = df.value_counts().unwrap();
        assert_eq!(result.len(), 2);
        assert_eq!(result.column().values()[0], Scalar::Int64(2));
        assert_eq!(result.column().values()[1], Scalar::Int64(1));
    }

