    // ── pivot_table_multi_agg ──────────────────────────────────

    #[test]
    fn dataframe_pivot_table_multi_agg() {
        let df = DataFrame::from_dict(
            &["row", "col", "val"],
            vec![
                (
                    "row",
                    vec![
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("a".into()),
                        Scalar::Utf8("b".into()),
                    ],
                ),
                (
                    "col",
                    vec![
                        Scalar::Utf8("x".into()),
                        Scalar::Utf8("x".into()),
                        Scalar::Utf8("x".into()),
                    ],
                ),
                (
                    "val",
                    vec![
                        Scalar::Float64(10.0),
                        Scalar::Float64(20.0),
                        Scalar::Float64(30.0),
                    ],
                ),
            ],
        )
        .unwrap();

        let result = df
            .pivot_table_multi_agg("val", "row", "col", &["sum", "mean"])
            .unwrap();

        // Should have columns: x_sum, x_mean
        assert!(result.columns.contains_key("x_sum"));
        assert!(result.columns.contains_key("x_mean"));
        // Row "a": sum=30, mean=15
        assert_eq!(result.columns["x_sum"].values()[0], Scalar::Float64(30.0));
        assert_eq!(result.columns["x_mean"].values()[0], Scalar::Float64(15.0));
        // Row "b": sum=30, mean=30
        assert_eq!(result.columns["x_sum"].values()[1], Scalar::Float64(30.0));
        assert_eq!(result.columns["x_mean"].values()[1], Scalar::Float64(30.0));
    }

    // ── Series.duplicated_keep ─────────────────────────────────

    #[test]
    fn series_duplicated_keep_first() {
        let s = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(1),
                Scalar::Int64(3),
            ],
        )
        .unwrap();

        let result = s.duplicated_keep(DuplicateKeep::First).unwrap();
        assert_eq!(
            result.values(),
            &[
                Scalar::Bool(false),
                Scalar::Bool(false),
                Scalar::Bool(true),
                Scalar::Bool(false)
            ]
        );
    }

    #[test]
    fn series_duplicated_keep_last() {
        let s = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(1),
                Scalar::Int64(3),
            ],
        )
        .unwrap();

        let result = s.duplicated_keep(DuplicateKeep::Last).unwrap();
        // First 1 (idx 0) is duplicate, second 1 (idx 2) is not
        assert_eq!(
            result.values(),
            &[
                Scalar::Bool(true),
                Scalar::Bool(false),
                Scalar::Bool(false),
                Scalar::Bool(false)
            ]
        );
    }

    #[test]
    fn series_duplicated_keep_none() {
        let s = Series::from_values(
            "a",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(1),
                Scalar::Int64(3),
            ],
        )
        .unwrap();

        let result = s.duplicated_keep(DuplicateKeep::None).unwrap();
        // Both 1s are duplicated
        assert_eq!(
            result.values(),
            &[
                Scalar::Bool(true),
                Scalar::Bool(false),
                Scalar::Bool(true),
                Scalar::Bool(false)
            ]
        );
    }

    // ── DataFrame.combine ──────────────────────────────────────

    #[test]
    fn dataframe_combine_element_wise() {
        let df1 = DataFrame::from_dict(
            &["a"],
            vec![("a", vec![Scalar::Float64(1.0), Scalar::Float64(2.0)])],
        )
        .unwrap();

        let df2 = DataFrame::from_dict(
            &["a"],
            vec![("a", vec![Scalar::Float64(10.0), Scalar::Float64(20.0)])],
        )
        .unwrap();

        let result = df1
            .combine_elementwise(&df2, |left, right| match (left.to_f64(), right.to_f64()) {
                (Ok(l), Ok(r)) => Scalar::Float64(l + r),
                _ => Scalar::Null(NullKind::NaN),
            })
            .unwrap();

        assert_eq!(result.columns["a"].values()[0], Scalar::Float64(11.0));
        assert_eq!(result.columns["a"].values()[1], Scalar::Float64(22.0));
    }

    #[test]
    fn dataframe_combine_aligns_index_and_columns() {
        let mut left_cols = BTreeMap::new();
        left_cols.insert(
            "a".to_string(),
            Column::from_values(vec![Scalar::Int64(1), Scalar::Int64(2)]).unwrap(),
        );
        let df1 = DataFrame::new_with_column_order(
            Index::from_i64(vec![0, 2]),
            left_cols,
            vec!["a".to_string()],
        )
        .unwrap();

        let mut right_cols = BTreeMap::new();
        right_cols.insert(
            "b".to_string(),
            Column::from_values(vec![Scalar::Int64(10), Scalar::Int64(20)]).unwrap(),
        );
        let df2 = DataFrame::new_with_column_order(
            Index::from_i64(vec![1, 2]),
            right_cols,
            vec!["b".to_string()],
        )
        .unwrap();

        let result = df1
            .combine_elementwise(&df2, |left, right| match (left.to_f64(), right.to_f64()) {
                (Ok(l), Ok(r)) => Scalar::Float64(l + r),
                (Ok(l), Err(_)) => Scalar::Float64(l),
                (Err(_), Ok(r)) => Scalar::Float64(r),
                _ => Scalar::Null(NullKind::NaN),
            })
            .unwrap();

        assert_eq!(
            result.index().labels(),
            &vec![0_i64.into(), 2_i64.into(), 1_i64.into()]
        );
        assert_eq!(
            result.columns["a"].values(),
            &[
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Null(NullKind::NaN)
            ]
        );
        assert_eq!(
            result.columns["b"].values(),
            &[
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(20.0),
                Scalar::Float64(10.0)
            ]
        );
    }

    #[test]
    fn dataframe_combine_min() {
        let df1 = DataFrame::from_dict(
            &["x"],
            vec![("x", vec![Scalar::Float64(5.0), Scalar::Float64(1.0)])],
        )
        .unwrap();

        let df2 = DataFrame::from_dict(
            &["x"],
            vec![("x", vec![Scalar::Float64(3.0), Scalar::Float64(7.0)])],
        )
        .unwrap();

        let result = df1
            .combine_elementwise(&df2, |left, right| match (left.to_f64(), right.to_f64()) {
                (Ok(l), Ok(r)) => Scalar::Float64(l.min(r)),
                _ => Scalar::Null(NullKind::NaN),
            })
            .unwrap();

        assert_eq!(result.columns["x"].values()[0], Scalar::Float64(3.0));
        assert_eq!(result.columns["x"].values()[1], Scalar::Float64(1.0));
    }

    // ── Series.std_ddof / var_ddof ─────────────────────────────

    #[test]
    fn series_var_ddof_population() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Float64(4.0),
                Scalar::Float64(6.0),
                Scalar::Float64(8.0),
            ],
        )
        .unwrap();

        // Population variance (ddof=0): mean=5, var = ((2-5)^2+(4-5)^2+(6-5)^2+(8-5)^2)/4 = (9+1+1+9)/4 = 5.0
        let var_pop = s.var_ddof(0).unwrap();
        assert_eq!(var_pop, Scalar::Float64(5.0));

        // Sample variance (ddof=1): same sum / 3 = 20/3 ≈ 6.6667
        let var_sample = s.var_ddof(1).unwrap();
        let v = var_sample.to_f64().unwrap();
        assert!((v - 20.0 / 3.0).abs() < 1e-10);
    }

    #[test]
    fn series_std_ddof() {
        let s = Series::from_values(
            "x",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Float64(4.0),
                Scalar::Float64(6.0),
                Scalar::Float64(8.0),
            ],
        )
        .unwrap();

        let std_pop = s.std_ddof(0).unwrap().to_f64().unwrap();
        assert!((std_pop - 5.0_f64.sqrt()).abs() < 1e-10);
    }

    #[test]
    fn series_var_ddof_insufficient_data() {
        let s = Series::from_values("x", vec![0_i64.into()], vec![Scalar::Float64(42.0)]).unwrap();

        // ddof=1 with 1 value → NaN
        let result = s.var_ddof(1).unwrap().to_f64().unwrap();
        assert!(result.is_nan());
    }

