    #[test]
    fn test_series_groupby_resample_reductions_meqrr() -> Result<(), FrameError> {
        let values = Series::from_values(
            "sales",
            vec![
                IndexLabel::Utf8("2024-01-05".into()),
                IndexLabel::Utf8("2024-01-20".into()),
                IndexLabel::Utf8("2024-01-07".into()),
                IndexLabel::Utf8("2024-02-03".into()),
                IndexLabel::Utf8("2024-02-08".into()),
            ],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
                Scalar::Float64(30.0),
            ],
        )?;
        let groups = Series::from_values(
            "store",
            vec![
                IndexLabel::Utf8("2024-01-05".into()),
                IndexLabel::Utf8("2024-01-20".into()),
                IndexLabel::Utf8("2024-01-07".into()),
                IndexLabel::Utf8("2024-02-03".into()),
                IndexLabel::Utf8("2024-02-08".into()),
            ],
            vec![
                Scalar::Utf8("east".into()),
                Scalar::Utf8("east".into()),
                Scalar::Utf8("west".into()),
                Scalar::Utf8("west".into()),
                Scalar::Utf8("east".into()),
            ],
        )?;
        let grouped = values.groupby(&groups)?;
        let resample = grouped.resample("M");

        let sums = resample.sum()?;
        assert_eq!(
            sums.index().labels(),
            &[
                IndexLabel::Utf8("east, 2024-01".into()),
                IndexLabel::Utf8("east, 2024-02".into()),
                IndexLabel::Utf8("west, 2024-01".into()),
                IndexLabel::Utf8("west, 2024-02".into()),
            ]
        );
        assert_eq!(
            sums.values(),
            &[
                Scalar::Float64(3.0),
                Scalar::Float64(30.0),
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
            ]
        );

        let means = resample.mean()?;
        assert_eq!(
            means.values(),
            &[
                Scalar::Float64(1.5),
                Scalar::Float64(30.0),
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
            ]
        );

        let counts = resample.count()?;
        assert_eq!(
            counts.values(),
            &[
                Scalar::Int64(2),
                Scalar::Int64(1),
                Scalar::Int64(1),
                Scalar::Int64(1),
            ]
        );

        let first = resample.first()?;
        assert_eq!(
            first.values(),
            &[
                Scalar::Float64(1.0),
                Scalar::Float64(30.0),
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
            ]
        );

        let last = resample.last()?;
        assert_eq!(
            last.values(),
            &[
                Scalar::Float64(2.0),
                Scalar::Float64(30.0),
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
            ]
        );

        Ok(())
    }

