    #[test]
    fn test_series_groupby_pairwise_corr_cov_904tg() -> Result<(), FrameError> {
        let values = Series::from_values(
            "x",
            vec![
                IndexLabel::Int64(0),
                IndexLabel::Int64(1),
                IndexLabel::Int64(2),
                IndexLabel::Int64(3),
                IndexLabel::Int64(4),
                IndexLabel::Int64(5),
            ],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(2.0),
                Scalar::Float64(10.0),
                Scalar::Float64(20.0),
                Scalar::Float64(30.0),
                Scalar::Float64(99.0),
            ],
        )?;
        let other = Series::from_values(
            "y",
            vec![
                IndexLabel::Int64(0),
                IndexLabel::Int64(1),
                IndexLabel::Int64(2),
                IndexLabel::Int64(3),
                IndexLabel::Int64(4),
                IndexLabel::Int64(5),
            ],
            vec![
                Scalar::Float64(2.0),
                Scalar::Float64(4.0),
                Scalar::Float64(5.0),
                Scalar::Float64(9.0),
                Scalar::Float64(15.0),
                Scalar::Float64(1.0),
            ],
        )?;
        let groups = Series::from_values(
            "store",
            vec![
                IndexLabel::Int64(0),
                IndexLabel::Int64(1),
                IndexLabel::Int64(2),
                IndexLabel::Int64(3),
                IndexLabel::Int64(4),
                IndexLabel::Int64(5),
            ],
            vec![
                Scalar::Utf8("east".into()),
                Scalar::Utf8("east".into()),
                Scalar::Utf8("west".into()),
                Scalar::Utf8("west".into()),
                Scalar::Utf8("east".into()),
                Scalar::Utf8("solo".into()),
            ],
        )?;
        let grouped = values.groupby(&groups)?;

        let cov = grouped.cov(&other)?;
        assert_eq!(
            cov.index().labels(),
            &[
                IndexLabel::Utf8("east".into()),
                IndexLabel::Utf8("west".into()),
                IndexLabel::Utf8("solo".into()),
            ]
        );
        assert!(matches!(
            cov.values(),
            [Scalar::Float64(east), Scalar::Float64(west), Scalar::Float64(solo)]
                if (*east - 114.5).abs() < 1e-12
                    && (*west - 20.0).abs() < 1e-12
                    && solo.is_nan()
        ));

        let corr = grouped.corr(&other)?;
        let expected_east = 114.5 / (7.0 * 271.0_f64.sqrt());
        assert!(matches!(
            corr.values(),
            [Scalar::Float64(east), Scalar::Float64(west), Scalar::Float64(solo)]
                if (*east - expected_east).abs() < 1e-12
                    && (*west - 1.0).abs() < 1e-12
                    && solo.is_nan()
        ));

        Ok(())
    }

