    #[test]
    fn test_series_replace_map() {
        let s = Series::from_values(
            "data",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)],
        )
        .unwrap();
        let mut mapping = std::collections::HashMap::new();
        mapping.insert(format!("{:?}", Scalar::Int64(1)), Scalar::Int64(100));
        mapping.insert(format!("{:?}", Scalar::Int64(3)), Scalar::Int64(300));
        let result = s.replace_map(&mapping).unwrap();
        assert_eq!(result.column().values()[0], Scalar::Int64(100));
        assert_eq!(result.column().values()[1], Scalar::Int64(2)); // unchanged
        assert_eq!(result.column().values()[2], Scalar::Int64(300));
    }

    #[test]
    fn test_series_apply_fn_na() {
        let s = Series::from_values(
            "data",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Float64(2.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();
        let result = s
            .apply_fn_na(|v| {
                if let Ok(f) = v.to_f64() {
                    Scalar::Float64(f * 10.0)
                } else {
                    v.clone()
                }
            })
            .unwrap();
        assert_eq!(result.column().values()[0], Scalar::Float64(20.0));
        assert!(result.column().values()[1].is_missing()); // NaN preserved
        assert_eq!(result.column().values()[2], Scalar::Float64(40.0));
    }

    #[test]
    fn test_resample_agg_multi() {
        let df = DataFrame::from_dict_with_index(
            vec![(
                "val",
                vec![
                    Scalar::Float64(1.0),
                    Scalar::Float64(2.0),
                    Scalar::Float64(3.0),
                    Scalar::Float64(4.0),
                ],
            )],
            vec![
                IndexLabel::Utf8("2023-01-01".to_string()),
                IndexLabel::Utf8("2023-01-15".to_string()),
                IndexLabel::Utf8("2023-02-01".to_string()),
                IndexLabel::Utf8("2023-02-15".to_string()),
            ],
        )
        .unwrap();
        let result = df
            .resample("M")
            .agg(&["sum", "mean", "std", "var", "median", "prod"])
            .unwrap();
        let col_names: Vec<String> = result.column_names().into_iter().cloned().collect();
        assert!(col_names.contains(&"val_sum".to_string()));
        assert!(col_names.contains(&"val_mean".to_string()));
        assert!(col_names.contains(&"val_std".to_string()));
        assert!(col_names.contains(&"val_var".to_string()));
        assert!(col_names.contains(&"val_median".to_string()));
        assert!(col_names.contains(&"val_prod".to_string()));
        assert_eq!(
            result.columns["val_std"].values(),
            &[
                Scalar::Float64(std::f64::consts::FRAC_1_SQRT_2),
                Scalar::Float64(std::f64::consts::FRAC_1_SQRT_2)
            ]
        );
        assert_eq!(
            result.columns["val_var"].values(),
            &[Scalar::Float64(0.5), Scalar::Float64(0.5)]
        );
        assert_eq!(
            result.columns["val_median"].values(),
            &[Scalar::Float64(1.5), Scalar::Float64(3.5)]
        );
        assert_eq!(
            result.columns["val_prod"].values(),
            &[Scalar::Float64(2.0), Scalar::Float64(12.0)]
        );
    }

    #[test]
    fn test_dt_round() {
        let s = Series::from_values(
            "ts",
            vec![0_i64.into(), 1_i64.into()],
            vec![
                Scalar::Utf8("2023-01-15 14:20:00".to_string()),
                Scalar::Utf8("2023-01-15 14:40:00".to_string()),
            ],
        )
        .unwrap();
        let result = s.dt().round("h").unwrap();
        // 14:20 rounds down to 14:00
        assert_eq!(
            result.column().values()[0],
            Scalar::Utf8("2023-01-15 14:00:00".to_string())
        );
        // 14:40 rounds up to 15:00
        assert_eq!(
            result.column().values()[1],
            Scalar::Utf8("2023-01-15 15:00:00".to_string())
        );
    }

    #[test]
    fn test_series_groupby_var_median() {
        let s = Series::from_values(
            "data",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Float64(1.0),
                Scalar::Float64(3.0),
                Scalar::Float64(2.0),
                Scalar::Float64(4.0),
            ],
        )
        .unwrap();
        let by = Series::from_values(
            "grp",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into(), 3_i64.into()],
            vec![
                Scalar::Utf8("a".into()),
                Scalar::Utf8("a".into()),
                Scalar::Utf8("b".into()),
                Scalar::Utf8("b".into()),
            ],
        )
        .unwrap();
        let gb = s.groupby(&by).unwrap();
        let var = gb.var().unwrap();
        // group "a": var([1,3]) = 2.0
        assert_eq!(var.column().values()[0], Scalar::Float64(2.0));

        let med = gb.median().unwrap();
        // group "a": median([1,3]) = 2.0
        assert_eq!(med.column().values()[0], Scalar::Float64(2.0));
        // group "b": median([2,4]) = 3.0
        assert_eq!(med.column().values()[1], Scalar::Float64(3.0));
    }

