    #[test]
    fn test_dt_to_timestamp() {
        let s = Series::from_values(
            "periods",
            vec![0_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("2023-01".to_string()),
                Scalar::Utf8("2023-06-15".to_string()),
                Scalar::Utf8("2023".to_string()),
            ],
        )
        .unwrap();
        let result = s.dt().to_timestamp().unwrap();
        assert_eq!(
            result.column().values()[0],
            Scalar::Utf8("2023-01-01 00:00:00".to_string())
        );
        assert_eq!(
            result.column().values()[1],
            Scalar::Utf8("2023-06-15 00:00:00".to_string())
        );
        assert_eq!(
            result.column().values()[2],
            Scalar::Utf8("2023-01-01 00:00:00".to_string())
        );
    }

    #[test]
    fn test_dt_to_timestamp_how_end() {
        let s = Series::from_values(
            "periods",
            vec![0_i64.into(), 1_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("2024".to_string()),
                Scalar::Utf8("2024-02".to_string()),
                Scalar::Utf8("2024-02-29".to_string()),
                Scalar::Utf8("2024-02-29T12:30:00".to_string()),
            ],
        )
        .unwrap();
        let result = s.dt().to_timestamp_with_how("end").unwrap();
        assert_eq!(
            result.column().values()[0],
            Scalar::Utf8("2024-12-31 23:59:59.999999999".to_string())
        );
        assert_eq!(
            result.column().values()[1],
            Scalar::Utf8("2024-02-29 23:59:59.999999999".to_string())
        );
        assert_eq!(
            result.column().values()[2],
            Scalar::Utf8("2024-02-29 23:59:59.999999999".to_string())
        );
        assert_eq!(
            result.column().values()[3],
            Scalar::Utf8("2024-02-29T12:30:00".to_string())
        );
    }

    #[test]
    fn test_dt_to_timestamp_rejects_malformed_periods() {
        let s = Series::from_values(
            "periods",
            vec![
                0_i64.into(),
                1_i64.into(),
                1_i64.into(),
                2_i64.into(),
                3_i64.into(),
            ],
            vec![
                Scalar::Utf8("2024-13".to_string()),
                Scalar::Utf8("2024-02-30".to_string()),
                Scalar::Utf8("2024-02-29T25:00:00".to_string()),
                Scalar::Utf8("2024-02-29".to_string()),
                Scalar::Utf8("2024-02-29T12:30:00".to_string()),
            ],
        )
        .unwrap();
        let result = s.dt().to_timestamp().unwrap();
        assert_eq!(result.column().values()[0], Scalar::Null(NullKind::NaN));
        assert_eq!(result.column().values()[1], Scalar::Null(NullKind::NaN));
        assert_eq!(result.column().values()[2], Scalar::Null(NullKind::NaN));
        assert_eq!(
            result.column().values()[3],
            Scalar::Utf8("2024-02-29 00:00:00".to_string())
        );
        assert_eq!(
            result.column().values()[4],
            Scalar::Utf8("2024-02-29T12:30:00".to_string())
        );
    }

    #[test]
    fn test_dt_to_pydatetime_warn_false_truncates_to_microseconds() {
        let s = Series::from_values(
            "datetimes",
            vec![
                0_i64.into(),
                1_i64.into(),
                2_i64.into(),
                3_i64.into(),
                4_i64.into(),
            ],
            vec![
                Scalar::Utf8("2024-01-15 10:30:00.123456789".to_string()),
                Scalar::Utf8("2024-01-15T10:30:00.987654321+05:30".to_string()),
                Scalar::Utf8("2024-01-16".to_string()),
                Scalar::Utf8("2024-01-15 10:30:00.500000000".to_string()),
                Scalar::Utf8("not-a-date".to_string()),
            ],
        )
        .unwrap();
        let result = s.dt().to_pydatetime_with_warn(false).unwrap();
        assert_eq!(
            result.column().values()[0],
            Scalar::Utf8("2024-01-15 10:30:00.123456".to_string())
        );
        assert_eq!(
            result.column().values()[1],
            Scalar::Utf8("2024-01-15 10:30:00.987654+05:30".to_string())
        );
        assert_eq!(
            result.column().values()[2],
            Scalar::Utf8("2024-01-16 00:00:00".to_string())
        );
        assert_eq!(
            result.column().values()[3],
            Scalar::Utf8("2024-01-15 10:30:00.500000".to_string())
        );
        assert_eq!(result.column().values()[4], Scalar::Null(NullKind::NaN));
    }

    #[test]
    fn test_dt_microsecond() {
        let s = Series::from_values(
            "datetimes",
            vec![0_i64.into(), 1_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("2024-06-15 12:34:56.123456".to_string()),
                Scalar::Utf8("2024-06-15T12:34:56.987654321".to_string()),
                Scalar::Utf8("2024-06-15".to_string()),
                Scalar::Utf8("not-a-date".to_string()),
            ],
        )
        .unwrap();
        let result = s.dt().microsecond().unwrap();
        assert_eq!(result.column().values()[0], Scalar::Int64(123_456));
        assert_eq!(result.column().values()[1], Scalar::Int64(987_654));
        assert_eq!(result.column().values()[2], Scalar::Int64(0));
        assert_eq!(result.column().values()[3], Scalar::Null(NullKind::NaN));
    }

    #[test]
    fn test_dt_nanosecond() {
        let s = Series::from_values(
            "datetimes",
            vec![0_i64.into(), 1_i64.into(), 1_i64.into(), 2_i64.into()],
            vec![
                Scalar::Utf8("2024-06-15 12:34:56.123456789".to_string()),
                Scalar::Utf8("2024-06-15T12:34:56.987654321".to_string()),
                Scalar::Utf8("2024-06-15".to_string()),
                Scalar::Utf8("not-a-date".to_string()),
            ],
        )
        .unwrap();
        let result = s.dt().nanosecond().unwrap();
        assert_eq!(result.column().values()[0], Scalar::Int64(789));
        assert_eq!(result.column().values()[1], Scalar::Int64(321));
        assert_eq!(result.column().values()[2], Scalar::Int64(0));
        assert_eq!(result.column().values()[3], Scalar::Null(NullKind::NaN));
    }

