    // ── Categorical tests ──

    #[test]
    fn categorical_from_values() {
        let s = Series::from_categorical(
            "color",
            vec![
                Scalar::Utf8("red".into()),
                Scalar::Utf8("blue".into()),
                Scalar::Utf8("red".into()),
                Scalar::Utf8("green".into()),
            ],
            false,
        )
        .unwrap();

        assert!(s.is_categorical());
        let cat = s.cat().unwrap();
        assert_eq!(cat.categories().len(), 3);
        assert!(!cat.ordered());

        // Codes should map: red=0, blue=1, green=2
        assert_eq!(s.column().values()[0], Scalar::Int64(0));
        assert_eq!(s.column().values()[1], Scalar::Int64(1));
        assert_eq!(s.column().values()[2], Scalar::Int64(0));
        assert_eq!(s.column().values()[3], Scalar::Int64(2));
    }

    #[test]
    fn categorical_from_codes() {
        let categories = vec![
            Scalar::Utf8("low".into()),
            Scalar::Utf8("medium".into()),
            Scalar::Utf8("high".into()),
        ];
        let s =
            Series::from_categorical_codes("rating", vec![0, 2, 1, 0], categories, true).unwrap();

        assert!(s.is_categorical());
        let cat = s.cat().unwrap();
        assert_eq!(cat.categories().len(), 3);
        assert!(cat.ordered());
    }

    #[test]
    fn categorical_from_codes_allows_missing_code() {
        let categories = vec![Scalar::Utf8("low".into()), Scalar::Utf8("high".into())];
        let s =
            Series::from_categorical_codes("rating", vec![0, -1, 1], categories, false).unwrap();

        let values = s.cat().unwrap().to_values().unwrap();
        assert_eq!(values.values()[0], Scalar::Utf8("low".into()));
        assert_eq!(values.values()[1], Scalar::Null(NullKind::Null));
        assert_eq!(values.values()[2], Scalar::Utf8("high".into()));
    }

    #[test]
    fn categorical_from_codes_rejects_out_of_bounds_code() {
        let categories = vec![Scalar::Utf8("low".into()), Scalar::Utf8("high".into())];
        let err =
            Series::from_categorical_codes("rating", vec![0, 2], categories, false).unwrap_err();

        assert!(
            err.to_string().contains("out of bounds"),
            "unexpected error: {err}"
        );
    }

    #[test]
    fn categorical_to_values() {
        let s = Series::from_categorical(
            "x",
            vec![
                Scalar::Utf8("a".into()),
                Scalar::Utf8("b".into()),
                Scalar::Utf8("a".into()),
            ],
            false,
        )
        .unwrap();

        let materialized = s.cat().unwrap().to_values().unwrap();
        assert!(!materialized.is_categorical());
        assert_eq!(materialized.values()[0], Scalar::Utf8("a".into()));
        assert_eq!(materialized.values()[1], Scalar::Utf8("b".into()));
        assert_eq!(materialized.values()[2], Scalar::Utf8("a".into()));
    }

    #[test]
    fn categorical_with_missing() {
        let s = Series::from_categorical(
            "x",
            vec![
                Scalar::Utf8("a".into()),
                Scalar::Null(NullKind::Null),
                Scalar::Utf8("b".into()),
            ],
            false,
        )
        .unwrap();

        // Missing values get code -1
        assert_eq!(s.column().values()[1], Scalar::Int64(-1));

        // Materializing back: -1 becomes Null
        let vals = s.cat().unwrap().to_values().unwrap();
        assert!(vals.values()[1].is_missing());
        assert_eq!(vals.values()[0], Scalar::Utf8("a".into()));
    }

    #[test]
    fn categorical_rename_categories() {
        let s = Series::from_categorical(
            "x",
            vec![Scalar::Utf8("a".into()), Scalar::Utf8("b".into())],
            false,
        )
        .unwrap();

        let renamed = s
            .cat()
            .unwrap()
            .rename_categories(vec![
                Scalar::Utf8("alpha".into()),
                Scalar::Utf8("beta".into()),
            ])
            .unwrap();

        let vals = renamed.cat().unwrap().to_values().unwrap();
        assert_eq!(vals.values()[0], Scalar::Utf8("alpha".into()));
        assert_eq!(vals.values()[1], Scalar::Utf8("beta".into()));
    }

    #[test]
    fn categorical_rename_wrong_length_errors() {
        let s = Series::from_categorical(
            "x",
            vec![Scalar::Utf8("a".into()), Scalar::Utf8("b".into())],
            false,
        )
        .unwrap();

        let err = s
            .cat()
            .unwrap()
            .rename_categories(vec![Scalar::Utf8("only_one".into())]);
        assert!(err.is_err());
    }

    #[test]
    fn categorical_add_categories() {
        let s = Series::from_categorical("x", vec![Scalar::Utf8("a".into())], false).unwrap();

        let extended = s
            .cat()
            .unwrap()
            .add_categories(vec![Scalar::Utf8("b".into()), Scalar::Utf8("c".into())])
            .unwrap();

        assert_eq!(extended.cat().unwrap().categories().len(), 3);
    }

    #[test]
    fn categorical_remove_unused() {
        let s = Series::from_categorical_codes(
            "x",
            vec![0, 0, 2], // only codes 0 and 2 used, 1 unused
            vec![
                Scalar::Utf8("a".into()),
                Scalar::Utf8("b".into()),
                Scalar::Utf8("c".into()),
            ],
            false,
        )
        .unwrap();

        let cleaned = s.cat().unwrap().remove_unused_categories().unwrap();
        let cat = cleaned.cat().unwrap();
        assert_eq!(cat.categories().len(), 2);
        assert_eq!(cat.categories()[0], Scalar::Utf8("a".into()));
        assert_eq!(cat.categories()[1], Scalar::Utf8("c".into()));

        // Codes should be remapped: old 0->new 0, old 2->new 1
        let vals = cleaned.cat().unwrap().to_values().unwrap();
        assert_eq!(vals.values()[0], Scalar::Utf8("a".into()));
        assert_eq!(vals.values()[2], Scalar::Utf8("c".into()));
    }

    #[test]
    fn categorical_set_categories() {
        let s = Series::from_categorical(
            "x",
            vec![
                Scalar::Utf8("a".into()),
                Scalar::Utf8("b".into()),
                Scalar::Utf8("c".into()),
            ],
            false,
        )
        .unwrap();

        // Set to only ["b", "d"] - "a" and "c" become missing, "d" is new
        let result = s
            .cat()
            .unwrap()
            .set_categories(vec![Scalar::Utf8("b".into()), Scalar::Utf8("d".into())])
            .unwrap();

        let vals = result.cat().unwrap().to_values().unwrap();
        assert!(vals.values()[0].is_missing()); // "a" not in new categories
        assert_eq!(vals.values()[1], Scalar::Utf8("b".into()));
        assert!(vals.values()[2].is_missing()); // "c" not in new categories
    }

    #[test]
    fn categorical_ordered_unordered() {
        let s = Series::from_categorical("x", vec![Scalar::Int64(1)], false).unwrap();
        assert!(!s.cat().unwrap().ordered());

        let ordered = s.cat().unwrap().as_ordered();
        assert!(ordered.cat().unwrap().ordered());

        let unordered = ordered.cat().unwrap().as_unordered();
        assert!(!unordered.cat().unwrap().ordered());
    }

    #[test]
    fn categorical_codes_accessor() {
        let s = Series::from_categorical(
            "x",
            vec![
                Scalar::Utf8("a".into()),
                Scalar::Utf8("b".into()),
                Scalar::Utf8("a".into()),
            ],
            false,
        )
        .unwrap();

        let codes = s.cat().unwrap().codes().unwrap();
        assert!(!codes.is_categorical());
        assert_eq!(codes.values()[0], Scalar::Int64(0));
        assert_eq!(codes.values()[1], Scalar::Int64(1));
        assert_eq!(codes.values()[2], Scalar::Int64(0));
    }

    #[test]
    fn non_categorical_series_cat_returns_none() {
        let s = Series::from_values("x", vec![0_i64.into()], vec![Scalar::Int64(42)]).unwrap();
        assert!(!s.is_categorical());
        assert!(s.cat().is_none());
    }

    #[test]
    fn categorical_numeric_values() {
        let s = Series::from_categorical(
            "x",
            vec![Scalar::Int64(10), Scalar::Int64(20), Scalar::Int64(10)],
            true,
        )
        .unwrap();

        let cat = s.cat().unwrap();
        assert_eq!(cat.categories().len(), 2);
        assert!(cat.ordered());

        let vals = cat.to_values().unwrap();
        assert_eq!(vals.values()[0], Scalar::Int64(10));
        assert_eq!(vals.values()[1], Scalar::Int64(20));
        assert_eq!(vals.values()[2], Scalar::Int64(10));
    }

    #[test]
    fn categorical_ordered_comparison_uses_category_order() {
        let categories = vec![
            Scalar::Utf8("low".into()),
            Scalar::Utf8("medium".into()),
            Scalar::Utf8("high".into()),
        ];
        let left =
            Series::from_categorical_codes("rating", vec![0, -1, 2], categories.clone(), true)
                .unwrap();
        let right =
            Series::from_categorical_codes("rating", vec![1, 1, -1], categories, true).unwrap();

        let out = left.lt(&right).unwrap();
        assert_eq!(
            out.values(),
            &[Scalar::Bool(true), Scalar::Bool(false), Scalar::Bool(false)]
        );
    }

    #[test]
    fn categorical_unordered_ordering_comparison_errors() {
        let categories = vec![Scalar::Utf8("low".into()), Scalar::Utf8("high".into())];
        let left =
            Series::from_categorical_codes("rating", vec![0], categories.clone(), false).unwrap();
        let right = Series::from_categorical_codes("rating", vec![1], categories, false).unwrap();

        let err = left.lt(&right).unwrap_err();
        assert!(
            err.to_string()
                .contains("Unordered Categoricals can only compare equality or not"),
            "unexpected error: {err}"
        );
    }

    #[test]
    fn categorical_ordered_scalar_comparison_uses_category_order() {
        let categories = vec![
            Scalar::Utf8("low".into()),
            Scalar::Utf8("medium".into()),
            Scalar::Utf8("high".into()),
        ];
        let s = Series::from_categorical_codes("rating", vec![0, 2, -1], categories, true).unwrap();

        let out = s.lt_scalar(&Scalar::Utf8("medium".into())).unwrap();
        assert_eq!(
            out.values(),
            &[Scalar::Bool(true), Scalar::Bool(false), Scalar::Bool(false)]
        );
    }

    #[test]
    fn categorical_sort_values_respects_category_order_and_preserves_dtype() {
        let categories = vec![
            Scalar::Utf8("low".into()),
            Scalar::Utf8("medium".into()),
            Scalar::Utf8("high".into()),
        ];
        let s =
            Series::from_categorical_codes("rating", vec![2, 0, -1, 1], categories, false).unwrap();

        let sorted = s.sort_values(true).unwrap();
        assert!(sorted.is_categorical());
        assert_eq!(
            sorted.column().values(),
            &[
                Scalar::Int64(0),
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(-1),
            ]
        );
        let materialized = sorted.cat().unwrap().to_values().unwrap();
        assert_eq!(
            materialized.values(),
            &[
                Scalar::Utf8("low".into()),
                Scalar::Utf8("medium".into()),
                Scalar::Utf8("high".into()),
                Scalar::Null(NullKind::Null),
            ]
        );
    }

    #[test]
    fn categorical_ordered_min_max_return_category_values() {
        let categories = vec![
            Scalar::Utf8("low".into()),
            Scalar::Utf8("medium".into()),
            Scalar::Utf8("high".into()),
        ];
        let s =
            Series::from_categorical_codes("rating", vec![2, 0, -1, 1], categories, true).unwrap();

        assert_eq!(s.min().unwrap(), Scalar::Utf8("low".into()));
        assert_eq!(s.max().unwrap(), Scalar::Utf8("high".into()));
    }

    #[test]
    fn categorical_unordered_min_max_error() {
        let categories = vec![Scalar::Utf8("low".into()), Scalar::Utf8("high".into())];
        let s = Series::from_categorical_codes("rating", vec![0, 1], categories, false).unwrap();

        assert!(s.min().unwrap_err().to_string().contains("not ordered"));
        assert!(s.max().unwrap_err().to_string().contains("not ordered"));
    }

    // ── MultiIndex integration tests ──

    #[test]
    fn df_set_index_multi() {
        let df = DataFrame::from_dict(
            &["region", "product", "sales"],
            vec![
                (
                    "region",
                    vec![
                        Scalar::Utf8("east".into()),
                        Scalar::Utf8("west".into()),
                        Scalar::Utf8("east".into()),
                    ],
                ),
                (
                    "product",
                    vec![
                        Scalar::Utf8("A".into()),
                        Scalar::Utf8("B".into()),
                        Scalar::Utf8("A".into()),
                    ],
                ),
                (
                    "sales",
                    vec![Scalar::Int64(100), Scalar::Int64(200), Scalar::Int64(300)],
                ),
            ],
        )
        .unwrap();

        let indexed = df
            .set_index_multi(&["region", "product"], true, "_")
            .unwrap();
        assert_eq!(indexed.index().len(), 3);
        // Composite index labels: "east_A", "west_B", "east_A"
        assert_eq!(
            indexed.index().labels()[0],
            IndexLabel::Utf8("east_A".into())
        );
        assert_eq!(
            indexed.index().labels()[1],
            IndexLabel::Utf8("west_B".into())
        );
        assert_eq!(
            indexed.index().labels()[2],
            IndexLabel::Utf8("east_A".into())
        );
        let row_multiindex = indexed
            .row_multiindex()
            .expect("set_index_multi should attach row MultiIndex metadata");
        assert_eq!(
            row_multiindex.names(),
            &[Some("region".into()), Some("product".into())]
        );
        let level0 = row_multiindex.get_level_values(0).unwrap();
        assert_eq!(level0.labels()[0], IndexLabel::Utf8("east".into()));
        assert_eq!(level0.labels()[1], IndexLabel::Utf8("west".into()));
        assert!(matches!(
            indexed.row_index(),
            fp_index::MultiIndexOrIndex::Multi(ref multiindex) if multiindex == row_multiindex
        ));
        // Only "sales" column remains when drop=true
        assert_eq!(indexed.column_names().len(), 1);
        assert!(indexed.column("sales").is_some());
    }

    #[test]
    fn df_set_index_multi_no_drop() {
        let df = DataFrame::from_dict(
            &["a", "b", "v"],
            vec![
                ("a", vec![Scalar::Int64(1), Scalar::Int64(2)]),
                (
                    "b",
                    vec![Scalar::Utf8("x".into()), Scalar::Utf8("y".into())],
                ),
                ("v", vec![Scalar::Float64(10.0), Scalar::Float64(20.0)]),
            ],
        )
        .unwrap();

        let indexed = df.set_index_multi(&["a", "b"], false, "|").unwrap();
        assert_eq!(indexed.index().labels()[0], IndexLabel::Utf8("1|x".into()));
        assert!(indexed.row_multiindex().is_some());
        // All columns kept when drop=false
        assert_eq!(indexed.column_names().len(), 3);
    }

    #[test]
    fn dataframe_new_with_row_multiindex_round_trips_logical_row_axis() {
        let row_multiindex = fp_index::MultiIndex::from_arrays(vec![
            vec![
                IndexLabel::Utf8("east".into()),
                IndexLabel::Utf8("west".into()),
                IndexLabel::Utf8("east".into()),
            ],
            vec![
                IndexLabel::Int64(2024),
                IndexLabel::Int64(2025),
                IndexLabel::Int64(2026),
            ],
        ])
        .unwrap()
        .set_names(vec![Some("region".into()), Some("year".into())]);
        let flat_index = row_multiindex.to_flat_index("|").set_name("region|year");

        let df = DataFrame::new_with_row_multiindex(
            flat_index.clone(),
            row_multiindex.clone(),
            BTreeMap::from([(
                "value".to_string(),
                Column::from_values(vec![
                    Scalar::Int64(10),
                    Scalar::Int64(20),
                    Scalar::Int64(30),
                ])
                .unwrap(),
            )]),
        )
        .unwrap();

        assert_eq!(df.index(), &flat_index);
        assert_eq!(df.row_multiindex(), Some(&row_multiindex));
        assert!(matches!(
            df.row_index(),
            fp_index::MultiIndexOrIndex::Multi(ref multiindex) if multiindex == &row_multiindex
        ));
    }

