    #[test]
    fn dataframe_reset_index_roundtrips_row_multiindex_levels() {
        let df = DataFrame::from_dict(
            &["region", "product", "year", "sales"],
            vec![
                (
                    "region",
                    vec![
                        Scalar::Utf8("east".into()),
                        Scalar::Utf8("east".into()),
                        Scalar::Utf8("west".into()),
                    ],
                ),
                (
                    "product",
                    vec![
                        Scalar::Utf8("A".into()),
                        Scalar::Utf8("B".into()),
                        Scalar::Utf8("A".into()),
                    ],
                ),
                (
                    "year",
                    vec![
                        Scalar::Int64(2024),
                        Scalar::Int64(2025),
                        Scalar::Int64(2024),
                    ],
                ),
                (
                    "sales",
                    vec![Scalar::Int64(10), Scalar::Int64(20), Scalar::Int64(30)],
                ),
            ],
        )
        .unwrap();

        let indexed = df
            .set_index_multi(&["region", "product", "year"], true, "|")
            .unwrap();
        let reset = indexed.reset_index(false).unwrap();
        assert_eq!(
            reset.index().labels(),
            &[
                IndexLabel::Int64(0),
                IndexLabel::Int64(1),
                IndexLabel::Int64(2)
            ]
        );
        assert!(reset.row_multiindex().is_none());
        assert_eq!(
            reset
                .column_names()
                .into_iter()
                .cloned()
                .collect::<Vec<_>>(),
            vec![
                "region".to_owned(),
                "product".to_owned(),
                "year".to_owned(),
                "sales".to_owned()
            ]
        );
        assert_eq!(
            reset.column("region").unwrap().values(),
            &[
                Scalar::Utf8("east".into()),
                Scalar::Utf8("east".into()),
                Scalar::Utf8("west".into())
            ]
        );

        let roundtrip = reset
            .set_index_multi(&["region", "product", "year"], true, "|")
            .unwrap();
        assert_eq!(roundtrip.index().labels(), indexed.index().labels());
        assert_eq!(roundtrip.row_multiindex(), indexed.row_multiindex());
    }

