        let result = super::to_datetime_with_unit(&s, "s").unwrap();
        assert_eq!(
            result.values(),
            &[
                Scalar::Utf8("1970-01-01 00:00:01".into()),
                Scalar::Utf8("1969-12-31 23:59:59".into()),
            ]
        );
