    #[test]
    fn series_map_uses_hash_fast_path_for_int_keys() {
        // Per br-frankenpandas-5110c: O(n + m) hash fast path. Build a
        // 1000-entry mapping and a 5000-element series; the result must
        // match what the linear-scan version would produce.
        let mapping: Vec<(Scalar, Scalar)> = (0..1000)
            .map(|i| (Scalar::Int64(i), Scalar::Int64(i * 10)))
            .collect();
        let labels: Vec<IndexLabel> = (0..5000_i64).map(IndexLabel::Int64).collect();
        let values: Vec<Scalar> = (0..5000_i64).map(|i| Scalar::Int64(i % 1000)).collect();
        let s = Series::from_values("x", labels, values).unwrap();

        let mapped = s.map(&mapping).unwrap();
        // Each value i % 1000 maps to (i % 1000) * 10.
        for (i, v) in mapped.column().values().iter().enumerate() {
            let expected = ((i as i64) % 1000) * 10;
            assert_eq!(*v, Scalar::Int64(expected), "row {i}");
        }
    }

    #[test]
    fn series_replace_uses_hash_fast_path_for_int_keys() {
        // Same pattern as map: large mapping, large input, hash fast path.
        let replacements: Vec<(Scalar, Scalar)> = vec![
            (Scalar::Int64(1), Scalar::Int64(100)),
            (Scalar::Int64(2), Scalar::Int64(200)),
            (Scalar::Int64(3), Scalar::Int64(300)),
        ];
        let s = Series::from_values(
            "x",
            (0..6_i64).map(IndexLabel::Int64).collect::<Vec<_>>(),
            vec![
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(3),
                Scalar::Int64(4),
                Scalar::Int64(1),
                Scalar::Int64(5),
            ],
        )
        .unwrap();
        let out = s.replace(&replacements).unwrap();
        assert_eq!(
            out.column().values(),
            &[
                Scalar::Int64(100),
                Scalar::Int64(200),
                Scalar::Int64(300),
                Scalar::Int64(4), // unmapped → keep original
                Scalar::Int64(100),
                Scalar::Int64(5), // unmapped → keep original
            ]
        );
    }

    #[test]
    fn series_map_falls_back_to_linear_scan_for_float_keys() {
        // Per br-frankenpandas-5110c: when any mapping key is Float64
        // (non-NaN), the hash fast path is bypassed to preserve
        // semantic_eq's relative-tolerance behavior.
        // semantic_eq treats Float64(1.0 + 1e-16) and Float64(1.0) as
        // equal (relative tolerance 1e-14). With the linear-scan
        // fallback, both should map to the same target.
        let close_to_one = 1.0_f64 + 1e-16;
        let mapping: Vec<(Scalar, Scalar)> = vec![(Scalar::Float64(1.0), Scalar::Int64(999))];
        let s = Series::from_values(
            "x",
            (0..2_i64).map(IndexLabel::Int64).collect::<Vec<_>>(),
            vec![Scalar::Float64(1.0), Scalar::Float64(close_to_one)],
        )
        .unwrap();
        let out = s.map(&mapping).unwrap();
        // Both values should hit the Float64(1.0) entry under semantic_eq's
        // tolerance — both map to Int64(999). The fact that
        // close_to_one != 1.0 bit-exactly is what proves this took the
        // linear-scan path (hash path would only match exact bits).
        assert_eq!(out.column().values()[0], Scalar::Int64(999));
        assert_eq!(out.column().values()[1], Scalar::Int64(999));
    }

    #[test]
    fn series_replace_unmapped_value_keeps_original() {
        // Regression guard: replace's "no match → keep original" path
        // must work on both fast and slow paths.
        let replacements = vec![(Scalar::Int64(99), Scalar::Int64(999))];
        let s = Series::from_values(
            "x",
            (0..3_i64).map(IndexLabel::Int64).collect::<Vec<_>>(),
            vec![Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)],
        )
        .unwrap();
        let out = s.replace(&replacements).unwrap();
        // No values match Int64(99); all originals preserved.
        assert_eq!(
            out.column().values(),
            &[Scalar::Int64(1), Scalar::Int64(2), Scalar::Int64(3)]
        );
    }

    #[test]
    fn series_drop_duplicates_first_matches_unique_metamorphic() {
        // Per br-frankenpandas-d8d9d: metamorphic property —
        // s.drop_duplicates(First) values must equal s.unique() (both
        // return distinct values in first-seen order). The /testing-
        // metamorphic skill applied this property and surfaced both ops
        // had the same O(n²) shape; now both must agree under O(n) impl.
        let s = Series::from_values(
            "x",
            (0..6_i64).map(IndexLabel::Int64).collect::<Vec<_>>(),
            vec![
                Scalar::Int64(3),
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(1),
                Scalar::Int64(3),
                Scalar::Int64(4),
            ],
        )
        .unwrap();

        let dropped = s.drop_duplicates_keep(DuplicateKeep::First).unwrap();
        let dropped_vals: Vec<Scalar> = dropped.column().values().to_vec();
        let unique_vals = s.unique();

        assert_eq!(
            dropped_vals, unique_vals,
            "drop_duplicates(First) values must match unique() values"
        );
    }

    #[test]
    fn series_duplicated_keep_none_marks_all_duplicates() {
        // Per br-frankenpandas-d8d9d: DuplicateKeep::None marks ALL
        // occurrences of any value that appears more than once. The
        // O(n²) filter().count() per element is now a single counts
        // pass + a marking pass; correctness must be preserved.
        // Input: [1, 2, 1, 3, 2, 4]
        // Counts: {1:2, 2:2, 3:1, 4:1}
        // Expected flags: [true, true, true, false, true, false]
        let s = Series::from_values(
            "x",
            (0..6_i64).map(IndexLabel::Int64).collect::<Vec<_>>(),
            vec![
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(1),
                Scalar::Int64(3),
                Scalar::Int64(2),
                Scalar::Int64(4),
            ],
        )
        .unwrap();

        let flags = s.duplicated_keep(DuplicateKeep::None).unwrap();
        let bool_flags: Vec<bool> = flags
            .column()
            .values()
            .iter()
            .map(|v| matches!(v, Scalar::Bool(b) if *b))
            .collect();
        assert_eq!(bool_flags, vec![true, true, true, false, true, false]);
    }

    #[test]
    fn series_drop_duplicates_keep_none_keeps_only_uniques() {
        // Sister case: drop_duplicates(None) keeps ONLY values that
        // appear exactly once.
        // Input: [1, 2, 1, 3, 2, 4] → keep {3, 4} only.
        let s = Series::from_values(
            "x",
            (0..6_i64).map(IndexLabel::Int64).collect::<Vec<_>>(),
            vec![
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(1),
                Scalar::Int64(3),
                Scalar::Int64(2),
                Scalar::Int64(4),
            ],
        )
        .unwrap();

        let kept = s.drop_duplicates_keep(DuplicateKeep::None).unwrap();
        assert_eq!(
            kept.column().values(),
            &[Scalar::Int64(3), Scalar::Int64(4)]
        );
    }

    #[test]
    fn series_duplicated_keep_last_marks_all_but_last_occurrence() {
        // Input: [1, 2, 1, 3, 1] → only the FINAL 1 (idx 4) and 2 (idx 1)
        // and 3 (idx 3) are kept; earlier 1s (idx 0, 2) are flagged.
        let s = Series::from_values(
            "x",
            (0..5_i64).map(IndexLabel::Int64).collect::<Vec<_>>(),
            vec![
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(1),
                Scalar::Int64(3),
                Scalar::Int64(1),
            ],
        )
        .unwrap();

        let flags = s.duplicated_keep(DuplicateKeep::Last).unwrap();
        let bool_flags: Vec<bool> = flags
            .column()
            .values()
            .iter()
            .map(|v| matches!(v, Scalar::Bool(b) if *b))
            .collect();
        assert_eq!(bool_flags, vec![true, false, true, false, false]);
    }

    #[test]
    fn series_unique_handles_many_unique_values_fast() {
        // Per br-frankenpandas-15f51: O(n²) → O(n) regression guard.
        // 5K distinct Int64 values; old impl would do ~12.5M comparisons.
        let n: i64 = 5_000;
        let labels: Vec<IndexLabel> = (0..n).map(IndexLabel::Int64).collect();
        let values: Vec<Scalar> = (0..n).map(Scalar::Int64).collect();
        let s = Series::from_values("x", labels, values).unwrap();

        let unique = s.unique();
        assert_eq!(unique.len() as i64, n);
        // First-occurrence ordering preserved (sequential 0..n).
        for (i, v) in unique.iter().enumerate() {
            assert_eq!(*v, Scalar::Int64(i as i64));
        }
    }

    #[test]
    fn series_unique_preserves_first_seen_order_after_o_n_fix() {
        // Critical contract: unique() returns values in first-seen order.
        // Input: [3, 1, 2, 1, 3, 4]; expected: [3, 1, 2, 4].
        let s = Series::from_values(
            "x",
            (0..6_i64).map(IndexLabel::Int64).collect::<Vec<_>>(),
            vec![
                Scalar::Int64(3),
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(1),
                Scalar::Int64(3),
                Scalar::Int64(4),
            ],
        )
        .unwrap();
        let unique = s.unique();
        assert_eq!(
            unique,
            vec![
                Scalar::Int64(3),
                Scalar::Int64(1),
                Scalar::Int64(2),
                Scalar::Int64(4),
            ]
        );
    }

    #[test]
    fn series_unique_collapses_nan_into_one_bucket() {
        // NaN/Null are emitted as a single bucket via the missing_seen
        // sentinel — same as the prior implementation.
        let s = Series::from_values(
            "x",
            (0..4_i64).map(IndexLabel::Int64).collect::<Vec<_>>(),
            vec![
                Scalar::Float64(1.0),
                Scalar::Null(NullKind::NaN),
                Scalar::Float64(f64::NAN),
                Scalar::Float64(1.0),
            ],
        )
        .unwrap();
        let unique = s.unique();
        // Expected: [1.0, <one missing bucket>] — NaN and Null collapse.
        assert_eq!(unique.len(), 2);
        assert_eq!(unique[0], Scalar::Float64(1.0));
        assert!(unique[1].is_missing());
    }

    #[test]
    fn series_nunique_matches_unique_len() {
        // Consistency: nunique() (with dropna=true) should equal
        // unique().iter().filter(|v| !v.is_missing()).count().
        let s = Series::from_values(
            "x",
            (0..5_i64).map(IndexLabel::Int64).collect::<Vec<_>>(),
            vec![
                Scalar::Int64(7),
                Scalar::Int64(7),
                Scalar::Null(NullKind::NaN),
                Scalar::Int64(3),
                Scalar::Int64(7),
            ],
        )
        .unwrap();
        // Distinct non-null: {7, 3} → 2.
        assert_eq!(s.nunique(), 2);
        // With dropna=false, count includes the null bucket: 3.
        assert_eq!(s.nunique_with_dropna(false), 3);
    }

    #[test]
    fn series_value_counts_handles_many_unique_values_fast() {
        // Per br-frankenpandas-7c7d0: regression guard for the O(n²) →
        // O(n) fix. With 5_000 unique Int64 values, the old linear-scan
        // implementation would do ~12.5M comparisons; the HashMap version
        // does ~5K. Keep this test small enough to stay in the unit
        // suite (no perf assertion — correctness suffices since the
        // big-O improvement is the goal; perf would need a benchmark).
        let n: i64 = 5_000;
        let labels: Vec<IndexLabel> = (0..n).map(IndexLabel::Int64).collect();
        let values: Vec<Scalar> = (0..n).map(Scalar::Int64).collect();
        let s = Series::from_values("x", labels, values).unwrap();

        let counts = s.value_counts().unwrap();
        // All values are distinct → n rows, each count == 1.
        assert_eq!(counts.len() as i64, n);
        for v in counts.column().values() {
            assert_eq!(*v, Scalar::Int64(1));
        }
    }

    #[test]
    fn series_value_counts_preserves_first_seen_order_for_ties_after_o_n_fix() {
        // Per br-frankenpandas-7c7d0: the HashMap-driven counter must
        // still preserve first-seen ordering for tied counts (the sort
        // is stable). Without insertion-order tracking, HashMap iteration
        // would scramble equal-count entries.
        // Input: [b, a, c, a, b] — all three have count {a:2, b:2, c:1}.
        // After stable descending sort, ties preserve first-seen order:
        // expected output index sequence is [b, a, c] (b seen first
        // among count-2 entries; c is unique with count 1).
        let s = Series::from_values(
            "x",
            vec![
                0_i64.into(),
                1_i64.into(),
                2_i64.into(),
                3_i64.into(),
                4_i64.into(),
            ],
            vec![
                Scalar::Utf8("b".into()),
                Scalar::Utf8("a".into()),
                Scalar::Utf8("c".into()),
                Scalar::Utf8("a".into()),
                Scalar::Utf8("b".into()),
            ],
        )
        .unwrap();

        let counts = s.value_counts().unwrap();
        // Three buckets: a, b, c.
        assert_eq!(counts.len(), 3);
        // Counts in order [b:2, a:2, c:1] preserved by stable sort.
        let labels = counts.index().labels();
        assert_eq!(labels[0], IndexLabel::Utf8("b".into()));
        assert_eq!(labels[1], IndexLabel::Utf8("a".into()));
        assert_eq!(labels[2], IndexLabel::Utf8("c".into()));
        let count_vals = counts.column().values();
        assert_eq!(count_vals[0], Scalar::Int64(2));
        assert_eq!(count_vals[1], Scalar::Int64(2));
        assert_eq!(count_vals[2], Scalar::Int64(1));
    }

